window.__QUIZ_SUBJECT__=[{"id": "theory>Government>1995>SECTION A>1", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Explain what is meant by Government as an academic field of study.", "images": [], "marking_scheme": "Government as an academic field of study refers to the study of political institutions, processes and theories taught in schools, colleges and higher institution of learning. It is called Political Science in the Higher Institution, Social Studies in The Primary School, Civic Science and Government in the Secondary School and on some occasions History.    The Scope of this definition is that Government allows students to understand their role in the Country as citizens and to understand the ways in which The  Government operates.", "marks": "15", "difficulty": "1"}, {"id": "theory>Government>1995>SECTION A>2>a", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain the term representative government.", "images": [], "marking_scheme": "Representative government can be defined as a government of elected representative of the people. It is also referred to as indirect democracy. It exists when certain people are duly elected by popular votes to perform the functions of government on behalf of the people.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1995>SECTION A>2>b", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "What conditions are essential for the existence of a representative government?", "images": [], "marking_scheme": "- Franchise must exists. People must possess the right to vote during elections so that they can choose their leaders.  -  Elections must be held periodically. This will afford the people the ample opportunity of rejecting any representative who does not perform well.  - There must be accountability on the part of government to the people. Since the government is exercising a mandated power, they must give account of stewardship to those who bestow the power on them.  - Individual freedom and rights must also be guaranteed. People must have political, social and economic right guaranteed and protected.  - A fearless and independent judicial system will also enhance a representative  government. It will not only act as check on those in government but will help to redress misuse of power and maltreatment of citizens.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>1995>SECTION A>3>a", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is political authority?", "images": [], "marking_scheme": "Political authority grants members of a government the right to rule over citizens using coercion if necessary (i.e., political legitimacy), while imposing an obligation for the citizens to obey government orders (i.e., political obligation).", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1995>SECTION A>3>b", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the various types of political authority.", "images": [], "marking_scheme": "- Traditional Authority  According to Weber, the power of traditional authority is accepted because that has traditionally been the case; its legitimacy exists because it has been accepted for a long time. Britain's Queen Elizabeth, for instance, occupies a position that she inherited based on the traditional rules of succession for the monarchy. People adhere to traditional authority because they are invested in the past and feel obligated to perpetuate it. In this type of authority, a ruler typically has no real force to carry out their will, and their position depends primarily on a group's respect.    - Charismatic Authority  Followers accept the power of charismatic authority because they are drawn to the leader's personal qualities. The appeal of a charismatic leader can be extraordinary, and can inspire followers to make unusual sacrifices or to persevere in the midst of great hardship and persecution. Charismatic leaders usually emerge in times of crisis and offer innovative or radical solutions. They may even offer a vision of a new world order. Despite the catastrophic consequences of events, Hitler's rise to power in the post-World War I economic depression of Germany is an example.    - Rational-Legal Authority  According to Weber, power made legitimate by laws, written rules, and regulations is termed rational-legal authority. In this type of authority, power is vested in a particular rationale, system, or ideology and not necessarily in the person who implements the specifics of that doctrine. With rational-legal authority, the power to influence does not fall on individuals themselves, but instead falls on specific, structured, bureaucratic offices, and individuals holding specific positions have the authority to act in the name of such positions. A nation that follows a constitution applies this type of authority. On a smaller scale, you might encounter rational-legal authority in the workplace via the standards set forth in the employee handbook, which provides the employee with a different type of authority than that of the boss.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>1995>SECTION A>4", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "State the functions and problems of public corporation.", "images": [], "marking_scheme": "FUNCTIONS  - They provide essential services to the people for instance, transport , electricity etc  - They are established to provide employment to the people.  - They promote economic development in the country.  - They help to raise the standard of living of the people through the regular provision of these services.  - They prevent exploitation of the people by few individuals.    PROBLEMS  - Political interference.  - Lack of funding  - Lack of competition  - Poor management.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1995>SECTION A>5", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "What are the functions of pressure groups?", "images": [], "marking_scheme": "- Pressure groups try to make the government more attentive to the needs of the people. This is because as groups with many members sometimes nationally spread, they command more respect than individuals who may be fighting for similar causes.  - Pressure groups provide specialized and expert information to the government on their interests and explain government policies to their members and the general public. Thus, they are an important link between the government and the people.  - They help to educate their members and the whole society on their fundamental human and political rights, and some government policies.  - They promote the economic stability of the country through their useful advice to the government on economic policies.  - They promote and protect the interest of their members.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1995>SECTION B>6", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Explain the factors that necessitated the adoption of the Nigerian Federalism.", "images": [], "marking_scheme": "- Political culture of Nigeria:An important factor that necessitated federalism in Nigeria was the political culture of the country. Evidently, Nigeria's political culture was federalism friendly and that gave rise to easy adoption of federalism.   - Historica experience: The major reason for the adoption of federal system of government in Nigeria is borne out of the historical experience that brought all the ethical groups together under one Nigeria.  - Ethnic, Religious and Geographical Factor: No doubt, the Ethnic, Religious and Geographical nature of Nigeria also contributed to the reason why federalism was adopted. This is so because where federal principles apply, the various ethnic groups that cannot or don't form majority to produce large part may have the opportunity of governing themselves within their federating unit controlled by them.  - Resource control: The availability of resources in a particular region and the need for that area to control the resources has also been seen as a reason for a federal system in Nigeria. This has nexus with the particular sharing formula adopted. In a unitary constitution which opposes federal principles, everything belongs to the central government; the federating unit does not exist, let alone agitating for resource control. However, that is not so in a federal government system.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1995>SECTION B>7", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Highlight the aims and objectives of the National Council for Nigeria and Cameroon (N.C.N.C)", "images": [], "marking_scheme": "- To educate the masses on the benefits of political freedom, social equality, and religious tolerance.  - To fight against British imperialism.  - To educate the Nigerian people politically.  - To educate Nigerians up to higher level so as to be well prepared for leadership positions.  - To unite the people against a common goal.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1995>SECTION B>8", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Outline five major features of Nigeria's foreign policy since independence.", "images": [], "marking_scheme": "- Nigeria foreign policy has as one of the characteristics, the abolition of all forms of colonialism and imperialism in Africa.  - Africa is the center piece of Nigeria foreign policy.  - Other characteristics of Nigeria policy is the Non-alignment with the power blocs.  - Nigeria foreign policy promotes peaceful resolution of inter-state disputes.  - Nigeria foreign policy respects the territorial integrity of other African States based on the principles of non-intervention in the affairs of their member state.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1995>SECTION B>9", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "State the functions of the Secretary-General of the United Nations Organisation.", "images": [], "marking_scheme": "- Chief administrator of the UN and head of the Secretariat.  - Submission of annual reports and recommendations to the General Assembly on the work of the UN.  - Alerting the Security Council about any situation which could pose a threat to world peace and recommending measures needed to forestall any breach of peace in any part of the globe.  - Enforcement of all UN resolutions.  - Appointment or recruitment, supervision and discipline of all UN staff.  - Preparation of annual budget of the UN.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1995>SECTION B>10", "subject": "Government", "year": "1995", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "What were the major changes introduced in Nigeria by the Clifford Constitution of 1922 ?", "images": [], "marking_scheme": "- It introduced the elective principle which was a limited franchise.  - It established a new council with 46 members out of this member, twenty seven  including the Governor were official members. Nineteen members were unofficial.   - It also established the executive council that advised the Governor on policy matters; there was no African in the council.  - The North was not represented in the legislative council but the governor legislated for the North through proclamation.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1996>SECTION A>1>a", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Distinguish between constitution and constitutionalism", "images": [], "marking_scheme": "While constitution is a body of rules that stipulates how a state should be governed, constitutionalism is the application of the constitution. It can also be seen as the act of practicing or putting the constitution into practice to achieve settings goals.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>1>b", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "State the main features of a constitution.", "images": [], "marking_scheme": "- Separation of powers is one of the most important political theory that must be present in a political system so as to avoid dictatorship. It must be entailed.  - In a heterogeneous country, it is usually advisable for the constitution to provide for the representation of the people in government. This means that the people should be able to choose who can represent them at the federal, state and local level of government.  - Another important quality of a good constitution is that it must be comprehensive. It is important that the constitution be comprehensive because many people depends on the information contained in it. If a constitution is not comprehensive enough, it will lead to miscarriage of justice in many court cases and that is not the purpose of a good constitution.  - A good constitution must also protect the fundamental human rights of the citizens it was made for. Fundamental human rights are does rights which are inalienable and immutable and are given to every citizen because he/she is a human being.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>2", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Give reasons for the adoption of bicameral legislature by some countries", "images": [], "marking_scheme": "- It gives room for equal representation of the component units in a federation.  - It gives room for checks and-balances. A house can check the excesses or  misdeeds of another house in a bicameral legislature system.    - The need for thoroughness and precision can also compel a state to adopt a bicameralism. Bills passed by one housewill have to be considered by another house to check against hasty and ill considered actions.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>3>a", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the political concept of legitimacy", "images": [], "marking_scheme": "Legitimacy is commonly defined in political science and sociology as the belief that a rule, institution, or leader has the right to govern. It is a judgment by an individual about the rightfulness of a hierarchy between rule or ruler and its subject and about the subordinate's obligations toward the rule or ruler.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>3>b", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What are the factors that sustain legitimacy in a state?", "images": [], "marking_scheme": "- Good government: If a government is ruling to the acceptance of the people, such government will normally-be recognised and accepted.   - Existence of basis for popular participation and collective bargaining: When the people have the opportunity of taking part in the decision making process, a sense of belonging is imparted into everybody.  - Democratic action is another factor that can sustain legitimacy. A democratically elected government will enjoy the support and acceptance of majority of the people.  - Respects for the rule of law is another factor that can sustain the legitimacy of a government. When government observes the supremacy of the law and the principle of civil liberty, it will enjoy legitimacy.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>4", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Outline the factors which determine the electoral success of a political party.", "images": [], "marking_scheme": "- Party Manifesto: The manifesto is a programme of action of what the political  party will do if it comes to power. If .the manifesto is appealing to the people, it can cause the people to vote for the party and thereby ensure its success.  - The quality of the party flag bearers will go along way to determine the success of the party at the polls. A well known flag bearer who has distinguished himself in one endeavour of life will readily enjoy people's support.  - Wide campaign: is another factor that determine the success of a party at the polls. A party that campaigns widely with winning strategy has a greater chance of victory than party without wide campaign.   - The requirements of the electoral law: wilt also determine the electoral success of a political party. Parties must comply with the provisions of the electoral laws and rules.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1996>SECTION A>5>a", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Identify the characteristics of the civil service.", "images": [], "marking_scheme": "- Permanency  This feature of the Civil Service means that every civil servant enjoys the security of tenure. In other words, a civil servant cannot be dismissed for reasons other than those stated in the law.  - Neutrality  Another important feature of the Civil Service is political neutrality. This simply means that civil servants need to rise above partisan politics. Civil servants must not identify themselves openly with any political party.  - Anonimity  The primary duty of every civil servant is to work to serve the government of the day. Unlike members of the political branch of the Executive, civil servants work behind the scenes and allow the politicians to make themselves known and heard.  - Impartiality  In their dealings with the public, civil servants have to eschew favouritism and nepotism. These are trained professionals who work to promote the national interest. So they must treat each person they deal with equally.  - Expertise  The Civil Service prides itself on the high calibre of its personnel. Civil servants are mostly professionals and experts in their fields of work.  - Bureaucracy  Strict adherence to rules and procedures is one of the most important characteristics of the Civil Service. The procedures that guide the work of civil servants are meant to ensure professionalism and efficiency.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION A>5>b", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Why is it important for the Civil Service to be politically neutral?", "images": [], "marking_scheme": "- Political neutrality is necessary also because they make it possible for the civil servants to continue to enjoy the trust and confidence of successive governments.  - It becomes relatively easy for a new administration to benefit from the services of expert and experienced personnel. This wouldn't have been possible if civil servants were partisan administrators who must leave office following the exit of their party from government.  - Political neutrality makes civil servants objective and reliable partners with the party in government in the national development effort.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION B>6", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Give reasons why the pre-colonial government in Yoruba land can be described as democratic.", "images": [], "marking_scheme": "The pre-colonial government in Yorubaland can be described as democratic due to the following reasons:  - The Oba or Alaafin was appointed by Oyomesi or kingmakers. Therefore no oba can impose himself on the people.  - There was in existence more than one royal lineage. This often allows for competition. Even within a royal lineage, more than one candidate can contest.   - There was in existence of the concept of checks and balances which prevented an Oba from ruling autocratically.  - The Oba did not take decision alone. Decisions were taken with consultation with the chiefs who were representative of the various quarters that constituted the village or town.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION B>7", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Trace the constitutional evolution of federalism in Nigeria up to 1954.", "images": [], "marking_scheme": "Federalism is the division of power between two levels of government that are coordinated. Nigeria was amalgamated in 1914 by Lord Lugard. He created the Nigerian council made up of 36 members! The Clifford constitution of 1922 did not incorporate the representation of Northern  Nigeria in the legislative council into the constitution. It was the Richard' Constitution of 1946 that established three regions but the regions were  heavily dependents on the centre. At the 1953 London constitutional conference, salient decisions relating to setting up of central and regional marketing boards were taken which also enhanced-the adoption of federalism in Nigeria. Far reaching decisions that impacted on federalism were also taken at the resumed Lagos conference of 1954 where it was decided that the judiciary and the police should be regionalized. It should also be noted that the Macpherson constitution of 1957 made the regions to be dependents on the centre. However a true federation was established under the 1954 Lyttleton-constitution. The constitution was a product of the London constitutional conference of 1953 and the Lagos constitutional.. conference of 1954. Under the 1954 constitution, there was the federal civil service and at the same time regional civil service with different civil service commissions.  Decisions of the regional Legislature were no longer to be approved by the  federal cabinet. It can be clearly stated that the 1954 constitution established Nigeria as a truly federal state.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1996>SECTION B>8", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Why has it been difficult for many African countries to implement the principles of Non-Alignment?", "images": [], "marking_scheme": "Many African countries had found it difficult to implements the principles or Non-alignments due to a number of reasons.   - Colonial linkage to former masters.  - Aids and Economic assistance.  - Political struggle among the elites that often led to solicitation for foreign helps.  - Inability to maintain domestic law and order due to outbreak of War is another factor promoting difficulty in implementing non-alignment philosophy.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1996>SECTION B>9", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "9", "group": "", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Highlight the main changes introduced into the Nigerian Government by the 1963 Constitution.", "images": [], "marking_scheme": "- The Governor General was now called the president who was no longer the representative of the queen.   - The federal supreme court now became the-highest court of the land. Appeal to the judicial committee of the Privy council was abolished under the 1963 constitution.  - Under the 1963 constitution the president was elected by the houses of Senate and Representative at a joint sitting. He held office for a period of five years.  - Appointments  to the  Judiciary  and  the  electoral Commission were made by the prime minister. The Judicial Service Commission was abolished under the 1963 constitution.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1996>SECTION B>10", "subject": "Government", "year": "1996", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Explain the problems facing the Economic Community of West African State (ECOWAS).", "images": [], "marking_scheme": "- Widespread Poverty  Many of the member states of ECOWAS are among the poorest of the poor nations in the world. Many of their citizens earn less than a dollar a day. This, in a certain sense, is preventing real economic integration of the sub-region while many continue to live in squalor and deprivation.  - Language barrier  There are three languages that are used for communication within the ECOWAS bloc, that is English, French and Portuguese. For easy communication among members, there is a need for individuals in the region to be able to speak these languages but this is proving too difficult. This has necessitated the use of interpreters to make people understand each other at summit meetings.  - Financial problems  The aims and objectives of the ECOWAS can only be achieved when the financial base of the community is solid. However, some member states are not able to honour their financial obligations to the community. This is one problem that has bedeviled the community over the years, especially when it comes to the running of the affairs of the community.  - Strong External Influence  Many of the member states of ECOWAS were former colonies of some former colonial powers. Countries such as Britain, France, and Portugal ever had a colony or two that now belong to the ECOWAS group. These member states are still controlled, to a certain extent, by their former colonial masters. The influence of these colonial masters, in some cases are so strong that, they are able to determine the direction of their votes at summit meetings on issues that are not in the interest of the former masters.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1997>SECTION A>1", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Why is it necessary to uphold the principle of the Rule of Law in a state?", "images": [], "marking_scheme": "The rule of law prevents the abuse of state power, requires the law to be followed by all, and ensures that legal rights are fulfilled in practice. It also provides the means for various other core aspects of democracy to be safeguarded – for example, making certain that the laws made by parliament are enforced, and that fair conduct of elections can be guaranteed. More broadly, it underpins social functioning by providing fair and legitimate routes for disputes to be settled. And it supports stable economies and economic growth by upholding property rights, facilitating the elimination of corruption, and maintaining a business environment in which contracts are enforced, and international trade and investment can flourish. The rule of law alone is not sufficient to make a state democratic, but a state which does not observe it cannot be a healthy democracy.", "marks": "15", "difficulty": "1"}, {"id": "theory>Government>1997>SECTION A>2>a", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "What is a confederation?", "images": [], "marking_scheme": "A confederation (or confederacy) is a voluntary alliance of sovereign, independent states established to manage matters of common concern to the member states, such as defense.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>1997>SECTION A>2>b", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Highlight the problems that are likely to arise in a confederal state.", "images": [], "marking_scheme": "- A major drawback of the confederate government style is that, the center does not enjoy any power regarding taxation. Levying of or appropriation of taxes in order to regulate the national revenue model is not the function of the central government. Regulation of the monetary system, budgeting, and monitoring the growth of the nation does not follow a uniform policy.  - Confederacies are not observed as a popular form of government across the world. One reason being that, this type of government is not a long-lasting one. Though they are seen to be the most decentralized forms, there arises the question of their sustenance. Confederation is also referred to as a transformation period (as countries are seen transforming from a confederation to a federation).  - If the central government derives its authority from the states, it is bound to become weak. The member states have majority of the legislative powers, thus, leaving the center with no right to make or enforce laws. Also, significant subjects of national interest, like international treaties, issue of currency, or maintenance of an army may not be handled by the center.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1997>SECTION A>3", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "3", "group": "", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Why do some countries adopt written constitutions?", "images": [], "marking_scheme": "One commonly cited benefit to states possessing written constitutions is that such devices perform an educative function, because citizens can easily consult and reference the documents.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1997>SECTION A>4>a", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Define public opinion", "images": [], "marking_scheme": "Public opinion is one of the most frequently evoked terms in American politics. At the most basic level, public opinion represents people's collective preferences on matters related to government and politics.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>1997>SECTION A>4>b", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What are its characteristics?", "images": [], "marking_scheme": "- Public opinion is concerned with a matter of public importance. It is not concerned with the interests of a particular group of people.  - Public opinion is for social welfare. The welfare of society is an essential characteristic of public opinion.  -  Public opinion is arrived at after careful thought. It is the tentative deliberative adjustment of public to a situation. It is a logical view of things. While Lasswell holds that all opinions involve a choice between different views which may be rationally held, Kimball Young, on the other hand, is of the view that an opinion may be rational, or based upon some conviction, or it may proceed from feeling and emotion.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>1997>SECTION A>5", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Give reasons for the creation of local governments in Nigeria.", "images": [], "marking_scheme": "- The local governments are established in order to bring government closer to the people at the grassroots.  - They allow the indigenes of the different local areas to govern themselves according to their culture and traditions.  - They serve as a link between the people and the state and federal government.  - The creation of local government gives room for even development in parts of the country.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1997>SECTION B>6", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Why was the development of Nationalist activities slow in the French West African colonies?", "images": [], "marking_scheme": "- Existence of high level of repression from French officials. Africans were highly maltreated and Chiefs were freely deposed based on the wills of French officials.  - The adoption of assimilation principles that created Frenchmen among Africans, also constituted  a  big  obstacle towards early existence of nationalist activities as educated Africans who had been assimilated enjoyed  French citizenship and see themselves as Frenchmen.  - Trade Union activities were not allowed to operate in a conducive atmosphere hence, nationalism was quite delayed.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1997>SECTION B>7", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Outline the causes and implications of the 1953 Kano riot in Nigeria.", "images": [], "marking_scheme": "The cause of this riot were:  - The  Anthony  Enahoro's  motion   in   the   House   of Representative in March 1953. In this motion Enahoro moved that Nigerian should become self governing by 1956. NPC members rejected this motion as self government in 1956 was not an official policy of the NPC and its legislators refused to support the motion.  - Subjection of Northern representatives to insults by Lagos crowds and bitter criticisms of the Southerners also led to the crisis. The Northerners were  being tagged \"Kolanut men\"  \"Yes   people\"   and   imperialist   stooges   and appendages.  - The belief of Action Group and N.C. N.C. that Northern leaders were not representative of their people on the self government issue and their decision to send delegations to the North on the issue were the immediate cause of the Kano riots of 1953.    The implications of the Crisis were:  - It led to the break down of the Macpherson  constitution of 1951.  - Lives and properties were destroyed.  - It led to the postponement of National Self Government", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1997>SECTION B>8", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What are the positive and negative consequences of the Nigerian civil war (1967 - 1970)?", "images": [], "marking_scheme": "POSITIVE CONSEQUENCES  - Consolidation of Nigeria's territorial integrity  One of the positive sides of the Nigerian Civil War was that it helped the Nigerian government to strengthen the territorial integrity of the nation. By the time the war ended, the entire geographical land mass of the nation of Nigeria was remained intact. This could not have been achieved if the central government had not put its foot on the ground.  - Consolidation of federal authority  Another positive effect of the Nigerian Civil War was the way it strengthened the authority of the federal government as against that of the federating units. No unit of the federation can ever be stronger than the federation itself.  - Technological development  The war, which had devastated the economic system affected imports of finished goods from outside and machinery to produce locally. This had compelled the people to look inward to satisfy their needs for goods and services. After the war therefore, many Nigerians now have the penchant to create things locally.    NEGATIVE CONSEQUENCES OF THE NIGERIAN CIVIL WAR  - It was a waste of resources  One of the negative consequences of the 1967 to 1970 Civil War in Nigeria was the drain it had on the human, material and financial resources of the nation. In order to prosecute the war effort, the government of the day had to expend a lot of money. Even the seceding army had to spend money to procure arms and ammunition that cost millions of naira. Human lives, which constituted a great resource, was lost, estimated to be in the millions. Properties were also destroyed.  - Collapsed educational system  Another negative effect of the war was the way it brought the educational system to its knees. Many of the institutions of learning were destroyed. Those that were not destroyed had to close their doors and their academic calendar was totally distorted.  - Dislocation of economic activity  The war brought to a standstill, the economic activity of the entire nation. The industries of the country which should have been producing goods, either closed down or operated at a very low capacity.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1997>SECTION B>9", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Highlight the achievements of the military governments in Nigeria.", "images": [], "marking_scheme": "- Restoration of peace and order during political crisis  The intervention and restoration of peace and order in 1966 and 1983 when there was serious political crisis in Nigeria is one of the achievements of the military in Nigeria. This is also responsible for the continued existence of the entity known today as Nigeria today. The military was able to achieve this by smoothening the secessionist quest of the default Eastern region.  - Decrease in the problem of tribalism in the formation of political parties in Nigeria  In order to widen the base of political parties and to make them truly rational, the 1979 constitution (Which was introduced immediately after a military rule) provided that each political party should open its door to all Nigerian citizens irrespective of their place of origin, sex, religion and that the political parties should not confine its activities to a party only of the geographical area of Nigeria and that the party must have its headquarters in the capital of the federation.  - Local Government reform of 1976  The Local government reform of 1976 is apparently one of the achievements of military rule in Nigeria too. Before January 1966, the various regions in Nigeria had different system of governments, at the grassroot level.  - Creation of states  Another outstanding achievement of the military in Nigeria was the creation of states to replace the then existing region as it used to be called in the past. Gowon in may 1967, divided Nigeria into twelve (12) states. Seven (7) more states were added by Murtalar during his own time and with the creation of two more states by Babangida, Nigeria had a total of twenty one states. In 1991 Babangida created nine (9) more and afterwards General Abacha created six (6).", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1997>SECTION B>10", "subject": "Government", "year": "1997", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "In what ways does Nigeria maintain friendly relations with other African States?", "images": [], "marking_scheme": "- Establishment of embassies  and appointment of ambassadors  or  High   Commissioners  to African Countries  to  represent  the  interest  of  Nigerian Government.  - Humanitarian assistance in period of disasters just as the Babangida regime sent food aid to Cameroon when there was volcanic eruption.  - Economic assistance like provision of money to the FNLA to enable the party fight for the independence of Angola. Also Nigeria aided SWAPO in the fight for Namibian Independence.  - Military assistance to quel uprising and Civil War is another way Nigeria has been maintaining friendly relations with African States. The use of ECOMOG force to restore peace in Liberia is a case in point.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1998>SECTION A>1", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Outline the basic functions performed by a modern government.", "images": [], "marking_scheme": "- MAKING OF LAWS: This function is carried out through the legislative arm of the government. In a democratic set up, the national assembly or parliament as thecase may be performs this duty.   - MAINTENANCE OF LAWS AND ORDER:  This is a duty that is being complemented by the police who normally quell riots and disturbances. Without the proper discharge of this function, lawlessness will prevail and danger, insecurity will rule the state.  - PROVISION OF SOCIAL AMENITIES: Government provide social amenities   like roads, water and electricity. These services help to, improve the quality of life of the citizens of a state.  - DEFENCE OF THE NATION AGAINST EXTERNAL AGGRESSION: This is done through the Armed forces. The Soldiers defend the land and the Navy protect the territorial waters while the Air force take care of the air space.", "marks": "15", "difficulty": "1"}, {"id": "theory>Government>1998>SECTION A>2", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Give reasons why delegated legislation is often criticized.", "images": [], "marking_scheme": "- Delegated Legislation my lack adequate publicity which may make it unknown among the people. People may therefore unconsciously run foul of the law.  - The exercise of delegated legislation is against the principle of separation of power. Essentially, this principle advocates that governmental functions and  powers should be shared among the three organs of government to prevent despotism and arbitrariness.  - The exercise of delegated legislation is undemocratic. Law are supposed to be made by elected representatives but in a situation where the executive now exercise such powers it is undemocratic.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1998>SECTION A>3>a", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is soverignty in a state?", "images": [], "marking_scheme": "State sovereignty is a term that refers to the legal authority and responsibility of an independent state to govern and regulate its political affairs without foreign interference. Sovereign states have supreme authority over their territory.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>1998>SECTION A>3>b", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline the limitations of sovereignty in a state.", "images": [], "marking_scheme": "- Constitutional Provisions  The supremacy of the constitution makes it possible for all institutions in the state to have their powers limited by the constitution itself. In other words, the law of the land should be above everybody.  - Public Opinion  Public opinion has the capacity to check and control the exercise of the powers of government. Members of the public express their opinions through the mass media, protests and mass demonstrations.  - Membership of International Organizations   Membership of international organizations such as the U.N. African Union, Commonwealth and ECOWAS place limitations on the sovereign power of the state. This is because the states concerned are obliged to abide by the policies and values of these organizations and the rules governing them.  - Interdependence of states (eg. the need for Foreign Aid)   A state cannot depend entirely on its own resources. It may depend on other countries for economic, military and other forms of assistance. It is possible for these donor countries to influence or dictate the economic policies of such countries.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1998>SECTION A>4", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Explain six ways by which a citizen's right can be safeguarded.", "images": [], "marking_scheme": "- A Free and Virile Press: The press play a very powerful role in safeguarding the rights of citizens. This is done through the constant monitoring of activities  of government that violate the rights of citizens and the publication of such  infringement can check the excesses of a government that is sensitive to public opinion.  - The existence of a free and independent judiciary can also help to safeguard the rights of citizens. The court can issue Writ of Habeas Corpus, Writ of Mandamus, Writ of Certiorari and Prohibition.  - Existence of separation of power among the organs of government will also assist in safeguarding the rights of the citizens. The significance of this point lies in the fact that an organ can check the excesses of another organ.  - Establishment  of  Ombudsman,   Public  Complaints Commission or Human Right Corn-mission as we have under the inglorious and wicked Abacha regime -will assist in safeguarding the rights of citizens. But the effectiveness of this type of body is dependent on the independence of such a body and the integrity of members.  - There should also be a constitutional provision dealing with rights of citizens. Such provision must be made rigid so that the government of the day do not manipulate it to suit her whims and caprices.  - The observance of the rule of law will also help to safeguard the rights of citizens in any state.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1998>SECTION A>5", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "What are the merits and demerits of a multi-party system of government?", "images": [], "marking_scheme": "Advantages of a Multi-Party System  - A multi-party system affords citizens the opportunity to have as many choices as possible. As such, those in support of the system say it is democratic.  - Multi-party systems tend to encourage peaceful change of governments. The existence of many parties means that there are other parties waiting for their turn to be voted into power can discourage crude means of gaining political power.  - Since there are many parties that are formed in a multi-party system, this allows for minority groups among the electorate to be represented. This also allows for increased political participation by the masses.  - Another advantage of the operation of a multi-party system is that it allows opposition parties to exist. When there is opposition, it could encourage optimal results.  - The operation of multi-party allows open and constructive criticism of the policies of the ruling government. This prevents the leaders of the ruling party from becoming despotic or tyrannical.    Disadvantages of a Multi-Party System  - In many cases, no one party is able to gain power alone. Therefore, it leads to difficulty in formation of government. Some parties might have to come together before a government can be formed and these coalition governments can be weak and unstable.  - It can be expensive to operate since all the parties vying for political power must convince the people to vote for them. They organize rallies, advertise in the media and so on in order to carry out their campaigns and reach voters.  - Electorates can become bombarded with so many choices to the point where they get confused.  - Another disadvantage of multi-party system is that it can lead to divisions in the nation. This is especially so in Africa where parties could be formed along tribal, religious or ethnic lines.  - When there are many parties vying for the ultimate goal of ruling the country, it can degenerate into an unhealthy rivalry among the various parties. This could eventually stifle development and progress.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1998>SECTION B>6", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Outline the defects of the lyttleton's constitution of 1954", "images": [], "marking_scheme": "- One of the major defects of the 1954 Constitution was the fact that the members of the Federal Executive the Council of Ministers, although they were drawn from the elected \"Members of the House of Representatives by the Governor General their appointments were based on the three major political parties, each controlling one of the Regional Legislatures. The fact that their appointment was party-based coupled with the fact that none of the political leaders was at the Central House but rather they were heads of their Regional Governments made the Federal Ministers look not only for leadership and consultations but also for guidance and instructions from their political leaders. This rendered the Central Executive ineffective because  the loyalty of the ministers resided in their regions as it was under the Macpherson Constitution.  - Another major defect of the Constitution was its failure to provide for the second Chamber at the Centre. The only chamber in existence seemed to be  dictatorial in effect as there was no other chamber to give direction and constructive criticisms to its policies.  - The failure of the Constitution to provide for a Uniform electoral system throughout the country created room for the party in power in the regions to make electoral arrangements to the disadvantages of their opponents.  - Though the Lyttleton Constitution allowed the Africans bigger participation in governmental activities, nevertheless, the immense powers of the Governor to veto legislations, to kill legislations with his reserved power and to influence to a large extent, formulation of various policies were not different from those  powers  he wielded   under  Macpherson Constitution.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1998>SECTION B>7>a", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Define nationalism.", "images": [], "marking_scheme": "Nationalism is an idea and movement that holds that the nation should be congruent with the state.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>1998>SECTION B>7>b", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "What factors aided the growth of nationalism in Nigeria?", "images": [], "marking_scheme": "- The introduction of western education: This was one of the major factors that led to the growth of nationalism in Nigeria. Western education provided a common language with which West Africa used to fight colonialism. It also enlightened people of West Africa to the evils in colonialism and that colonial rule was synonymous with violence which must be removed.  - Return of educated elites: When the colonial masters came to West Africa, almost everyone was not educated and thus, could not understand the real aim of the colonial masters. The return of some educated elites like Nkrumah, Hartford, Azikiwe, Awolowo, Macaulay etc, who studied in foreign independent countries after seeing what a country enjoys by being independent came back to awake the spirit of nationalism in west Africa.  - Emergence of vibrant political parties: No doubt, political parties during the colonial era also gave rise to nationalist activities in Nigeria and in west Africa as a whole.  - Loss of British prestige: Following the defeat of Britain by Japan, a non-European power, Nigerians realized that Britain and other whites were not as powerful as they thought. Thus, they considered putting more effort to see that colonialism ends in the country.  - Effect of the Atlantic Charter: The publication at the end of the second world War of the Atlantic Charter signed in 1941 when America joined the war raised the hope of freedom fighters especially in West Africa.  -  Pan-African Congress: The activities of pan African congress from 1945 contributed immensely in rekindling spirit of nationalism in West Africa. Many African Intellectuals started taking greater part in the activities of the congress right from the October 1945 Manchester conference.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>1998>SECTION B>8", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What were the weaknesses of the military regime in Nigeria between 1966 and 1975?", "images": [], "marking_scheme": "- The unwillingness of the military to quit the political scene. This was clearly evidenced in the attitude of General Gowon who was not willing to hand over the government to a democratically elected government.  - The use of young and politically immatured officers in state administration was partly the weakness of the military rule. This often led to excesses and misuse of powers.  - The military was not completely insulated from corruption. This attitude, indeed, became a military tradition as their taste for luxuries increased.  - The enactment of laws that led to abuse of human rights was another weakness of the military. The disrespect for human rights often led to detention without trial of suspected critics of government.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1998>SECTION B>9", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Why did the educated elites oppose the introduction of Indirect Rule in Southern Nigeria?", "images": [], "marking_scheme": "- The System excluded the educatedelites and this created disunity between the traditional rulers and the educated elites as the traditional rulers were now seen as an instrument of oppression in the hands of the British imperialist.  - The Educated elite also criticised the system of indirect rule because it impeded rapid constitutional development which also retarded independence.  - The System of indirect rule was also criticised because it made the chiefs to become high handed and corrupt. Native treasuries were not properly checked and audited until 1948. This made the chiefs to spend money as they wished.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1998>SECTION B>10", "subject": "Government", "year": "1998", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "How has Nigeria shown that Africa is the centre-piece of her foreign policy?", "images": [], "marking_scheme": "- Decolonization of African States: Nigeria declared Africa as the centre piece of her foreign policy because she realized that her independence will be meaningless if it does not lead to the independence of other African States. This is why decolonization is the main objective of Nigeria's foreign policy.  - By supporting some states in Africa to gain independence.  - By promoting peace in Africa.  - By supporting smaller economies through platforms like ECOWAS.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1999>SECTION A>1>a", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Define democracy.", "images": [], "marking_scheme": "The word democracy comes from the Greek words \"demos\", meaning people, and \"kratos\" meaning power; so democracy can be thought of as \"power of the people\": a way of governing which depends on the will of the people.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>1999>SECTION A>1>b", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "What conditions are necessary for its successful operation?", "images": [], "marking_scheme": "- In a successful democracy the decision makers are elected by the people.  - Everyone is allowed and encouraged to vote. No one is discouraged from voting or made to jump through hoops. Sufficient polling places are maintained so that no one has to stand in line for more than a few minutes to vote.  - All votes are counted equally. One person one vote. No region of the country weighs more than any other region.  - Strict limits are place upon campaign contributions. Corporate contributions are banned. The wealthy are not permitted to \"own\" politicians or have disproportionate influence purchased by their wealth.  - The educational system is maintained so that citizens make intelligent choices when it comes to voting.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>1999>SECTION A>2", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Explain the functions of the legislature in a modern state.", "images": [], "marking_scheme": "Their powers may include passing laws, establishing the government's budget, confirming executive appointments, ratifying treaties, investigating the executive branch, impeaching and removing from office members of the executive and judiciary, and redressing constituents' grievances.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION A>3", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Under what circumstances can the rights of the individual be restricted?", "images": [], "marking_scheme": "- An individual may be denied of his rights during the period of emergency.  - A person's right to express his view is limited or restricted by the law of libel, slander and sedition.  - An individual right to vote or to be voted for in any election may be denied if he is a banned politician, or insane.  - An individual may be denied his right to life if he is condemned to death as a result of murder or armed robbery etc.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION A>4", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Why is delegated legislation necessary in modern governments?", "images": [], "marking_scheme": "- Technicalities of matters: Apparently, the technicalities of some matters is one of the reasons for delegated legislation. The rate at which bills are passed by the legislature might sometimes be so enormous that they may come across or pass bills that may be so technical in nature.  - Unforseen problems:  Another reason why the legislature will delegate its law making powers is to ensure that unforseen problems are handled properly when they arise. Sometimes in the course of operation or execution of a particular enacted legislation, problem may arise which are not foreseeable at the time of making the bill, and this can only be tackled by those in control of the execution.  - Trivial matters:  It is not the duty of the legislatures to legislate on trivial matters relating to operation or execution of all laws enacted by them. Trivial issues relate to such issues that are left to the discretion of other officers in charge of the implementation of the law.  - Emergency situations:  One important areas where delegated legislation is very vital is during emergency situation. In Nigeria, the president is empowered to legislate and control the situation. Emergency period connotes the period when the federation is at war, and there is in force a resolution passed by the National Assembly declaring that a state of public emergency exist or a resolution of each house of parliament supported by not less than two third of all the members of the House declaring that democratic institutions in Nigeria are threatened by subversion.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION A>5", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Highlight the conditions necessary for a free and fair election.", "images": [], "marking_scheme": "- There must be an up-to-date electoral register.   - Counting of votes and declaration of results must be on the spot and in public.  - There should be an independent and impartial electoral commission.  - Equal opportunities must be given to political parties to campaign.  - The electorate must be politically educated.  - There should be no intimidation of voters and candidates.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION B>6", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "How did the traditional rulers in the pre-colonial days control their subjects?", "images": [], "marking_scheme": "- Rules and regulations  Any society without rules and regulations could degenerate into chaos. In pre-colonial traditional societies, there were rules and regulations that the inhabitants were required to abide by. The rules and regulations were therefore established to govern the conduct of individuals within the jurisdiction of the chiefs, so that it does not degenerate into confusion.  - Settlement of disputes  The pre-colonial traditional rulers settled disputes. Disputes are normal in every society and pre-colonial societies in West Africa, were no exception. Any dispute that arose was settled by the chiefs. Culprits were punished, and the innocent were set free. This was one of the ways chiefs controlled their subjects.  - Law enforcement  There were law enforcement institutions in place to ensure law enforcement. Some of the enforcement institutions were the Age grades, masquerades, and militant groups like the Asafo companies among the Akans. These enforcement institutions were used in controlling the subjects.  - Use of ancestral spirits  The traditional belief that when the living misbehaved, the dead who lived in the after world could punish them, was another ingenious way of controlling the people. This belief in the underworld was common in pre-colonial times and nobody wanted to be on the wrong side of the gods, hence they obeyed the laws, thus helping the chiefs maintain control.  - Customs or taboos and conventions  There were things that traditional society frowned upon and society never compromised on them. These were aspects of their customs, taboos, and conventions. Any infraction of the customs, taboos or conventions attracted a certain form of fine or sanctions. This way, the chiefs were able to control their subjects.  - Oath taking  In pre-colonial times, one of the ways of ascertaining the truth was the taking of an oath, to tell the truth. There were serious repercussions for anybody who took the oath and still went ahead to tell a lie. The oath was usually taken before the gods of the land represented by the Chief Priests. Sub-chiefs were also made to swear oaths to remain loyal to the Paramount Chief. All of these helped to keep them in line.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1999>SECTION B>7>a", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Why was the Policy of Association introduced in French West Africa?", "images": [], "marking_scheme": "The main reason that led to the introductionof Association policy was due to the  total failure of Assimilation policy. The following led to the failure of Assimilation  policy:  - There was cultural incompatibility between the French and West Africans.  - The Policy did not accord any respect for the African traditional rulers.   - The policy was direct rule.  - Education was restricted to many Africans because the type of education introduced was religiously motivated.  - The policy did not allow the formation of political parties and publication of independent newspaper.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>1999>SECTION B>7>b", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Describe the characteristics of the Policy.", "images": [], "marking_scheme": "- Abolition of dual citizenship. Africans were no longer divided as citizens and subjects.   - African culture, Identity, tradition, native law and religion were recognized and preserved.   - Education was thrown open to all.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION B>8", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "What were the main features of the Independence Constitutions of the British West African countries?", "images": [], "marking_scheme": "- Governor-General: He was appointed to represent the Monarch and with ceremonial functions.  - Court of appeal: The judicial committee of the privy council was retained as the highest Court of Appeal for the country.  - Executive functions: Executive functions were performed by the Prime Minister and members of his cabinet.  - Citizenship: Provision was made in the constitution for Nigerian citizenship.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION B>9", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Give reasons for the military intervention in the politics of any one West African country.", "images": [], "marking_scheme": "- CORRUPTION  Corruption is a canker worm plaguing deep into the fabric of our society. Many civilian leaders are corrupt to an extent of siphoning and embezzling of public funds, for their selfish aggrandizements.  - ECONOMIC REASONS  One of the reasons or factors why the military seize political power is due to mismanagement of the economy in terms of carrying out or embarking on useless projects which do not help or promote economic development of the country.  - CONTAGION EFFECT  This stands to mean that military coup d'état are contagious. This is so because if colonels in one country overthrow the government and seize political powers, colonels in another country will be aspired to do the same.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION B>10", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Describe how a legislative council was controlled in British West Africa before the second world war.", "images": [], "marking_scheme": "- The legislative council was responsible for law making but such laws had to be approved by the Governor.  - The council had it as a duty to discuss and pass the budget. However, the budget had to be finally approved by the secretary of state for the colonies.  - The Governor presided over all legislative council meetings.  - The Governor had the power to nominate people into the legislative council.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>1999>SECTION B>11", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Why was the Indirect Rule system criticized by the nationalists?", "images": [], "marking_scheme": "- Affected constitutional development  The educated elite believed that Indirect Rule contributed to the slow rate at which constitutional and political changes were taking place. This they attributed to the fact that the chiefs who were being used were illiterates.  - Slow pace of socio-economic development  The chiefs, who were the kingpins of the system, were suspected to have been siphoning monies from the Native Treasuries. Apart from that, the system did not encourage the support the adequate provision of facilities for the educational and medical institutions.  - No leadership training  Another reason was that, the system did not make provisions for the training of people to take up the mantle of leadership when the colonialists eventually left. The chiefs were uneducated, so the educated elite felt that they were not the right material to take up leadership.  - Exclusion of the educated elite  Probably the major reason why the educated elite opposed Indirect Rule was their own exclusion from taking part in the colonial administration of the time. This pitched the educated elite against the chiefs in what is described as divide and rule tactic.  - Effect on the chieftaincy institution  In areas where there were no effective chiefs, the British themselves appointed their own chiefs. This did not follow the laid down traditional procedures of appointing chiefs. The result was that this category of chiefs became stooges of the British colonial administration. This, the educated elite were very bitter about.  - Absence of democratic structures  The educated elite also opposed the fact that Indirect Rule did not make room for democratic structures to be laid. There was nothing like elections or the opportunity for people to directly vote for their leaders. Instead, the leaders were imposed on them.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>1999>SECTION B>12", "subject": "Government", "year": "1999", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Outline four objectives of the foreign policy of any one West African country.", "images": [], "marking_scheme": "- Promotion and protection of national interest.   - Creation of Pan-African Defence Force in order to Africa self-reliant in military matters.   - Establishing diplomatic and friendly relations with all OAU member states and organizations.   - Non-alignment to any power bloc.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2000>Section A>1", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight any three merits and any three demerits of democracy.", "images": [], "marking_scheme": "Democracy may be defined as a system of government whereby political power resides in all the people and is exercised by them .   Merits of Democracy   - Democracy gives the electorate the opportunity to elect leaders of their choice through free and fair election.  - It gives citizen maximum fundamental freedom of speech, religion and association, civil liberties etc.  -  It also gives room for the rule of law to operate, those in government rule according to the law. Therefore, democracy is against dictatorship i.e military rule.  -  It helps to make progress and development among the people and enables changes to take place in a peaceful manner.  -  It guarantees liberty and equality, which are necessary for human development.  -  It broadens the vision of all, neutralizing the inherent selfish tendencies of human mind.  -  It helps to educate the public about political, economic and social affairs.   Demerit of Democracy   -  It is too expensive and time consuming   -  It slows decision making because everybody needs to express their views before decisions is taken.  -  It encourages corruption and malpractices.  -  Self-interest is the most common and majority of the people is unwilling to sub-ordinate it to the general will of the community.  -  Party leaders and political office holders in government controls citizens and members of the party.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2000>Section A>2", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "What are the functions of Head of Government in a presidential system?", "images": [], "marking_scheme": "Functions of the Head of government in Presidential sign   - He is the representative of the country  - He signs treaties on behalf of his country  - He appoints ministers and advisers which he could also dismiss.  - He presents the annual budget to the legislature for its considerations   - He initiates and implements government policies for his country  - He could authorise the withdrawal of money from the consolidated fund.  - He proclaim a state of emergency in the country or any part of it, if there is a breakdown of law and order.  - He is the commander in-chief of the armed forces   - He exercise the power of perogative of mercy i.e his official right  - He gives approval to bills.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2000>Section A>3", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Why is election necessary in a democratic state?", "images": [], "marking_scheme": "Election is the process of nominating or choosing a leader, members of parliament, councillors or other representatives by voting.   REASON   -  It promotes democracy in the society   -  It helps individual and political parties to test their popularity  -  It promotes accountability  -  It helps citizens nominate their choice of leaders and representatives  -  It allows political parties to control its form of government  -  It helps the citizen change unwanted government peacefully", "marks": "20", "difficulty": "1"}, {"id": "theory>Government>2000>Section A>4", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "In what five ways is the civil service different from the public corporation?", "images": [], "marking_scheme": "Civil service  is a body of stable officials responsible for assisting the executive in the formation and implementation or the execution of policies and programmes of the government while    Public Corporation also (Public enterprise or statutory corporation) is defined as a business organisation established, owned, managed and financed with tax payers money by government of a country with the motive of not making profit but to render essential services to members of the public such as water electricity etc   Differences    Civil service  Public corporation The political head is referred to as ministerThe political head is called chairmanCivil servants are employed by civil service commissionStaffs are employed by board of directors. It is a non-profit making organisationIt is profit making because it is not expected to run at loss though it is not a motive for establishment.It is managed by a minister advised by Director General(permanent secretary)This is managed by members of board of directors. It depends directly on annual budgetIt's staff are known as public servant.It depends directly on annual budgetIt is not subjected to legislative annual budget. It performs administrative functionsIt provides social service and amenitiesThey enjoy lesser conditions of service compared to their counterpartThey enjoy better condition of services more than their counterparts It cannot contract for loansIt can contract for loansIt pays its revenue into consolidated fundsIt cannot pay its revenue into the fund.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2000>Section A>5", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Describe any five problems associated with a single party system of government.", "images": [], "marking_scheme": "Single party-i.e one party system of government is a situation whereby there is only one legal political party in the country. Examples of such countries are china, malawi and Tazania.   Problems of one party system   - It opposes the principle of democracy particularly the fundamental freedom of association.  - It promotes inefficiency and corruption when the political office holder stay in office for long.  - It leads to dictatorship, facism and totalitarianism which means they will take total control of all things  - It brings about limit to political education  - It promotes oppression, suppression and every other imaginable things that is evil.  - It neglect public opinion  - It leads to coup  - Absense of watchdogs which results to slack,complacent and corruption of government.  - It attenuates itself from the people.  - The judiciary that maintains the rule of law and serves as hope of people is cowed and intimidated", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2000>Section B>6", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "In what five ways have political parties contributed to the constitutional development of Nigeria?", "images": [], "marking_scheme": "Contributions of Political Parties in Nigeria   - Political parties formed government in various regions under the 1951 constitution. This formed the basis for self government in 1957  and 1959 and eventually independence in 1960.  - Political parties provided the leadership for constitutional development i.e their members spearheaded agitation in Nigeria was criticised for lack of consultation.This was subsequently corrected in the 1951 colonial.  - Parties initiated popular opposition against colonial government e.g the Richard constitution of 1946 was described by party leaders as containing obnoxious laws and these were removed in 1951 constitution.  - The political parties provided leaders who attended  constitutional conferences for the attainment of political independence e.g the Ibadan conference of 1951 and the london conference of 1953 and 1957.  - They provided political education through rallius and newspapers owned by their leader.  Generally,  - Parties manifestors helps the government of a country in formulating its policies.  - It helps in passing information or government policies to members of the public.  - It helps to appoint leaders and personal to the legislative council.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2000>Section B>7", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Why was Indirect Rule not successful in Nigeria?", "images": [], "marking_scheme": "Indirect rule was a system in which the British colonial government ruled her colonies through their traditional rulers e.g Obas,Emirs and Obi's   Reason For Failure In Southern Nigeria   - Inappropiate traditional political system  - Lack of understanding of traditional political system.  - Imposition of direct taxation which was alien to the people.  - Exclusion of educated elite in the direct rule system.  - The imposition of warrants chiefs in Eastern Nigeria despite the fact that it was alien to their culture.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2000>Section B>8", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "What were the functions of the colonial Governor in British West Africa?", "images": [], "marking_scheme": "Function of colonial Governor in British West Africa   - He presided over the executive council   - He appointed,promoted,dismissed and deployed officers of the government.  - He presided over all legislative council meeting's.  - He had the power to nominate people unto all legislature and executive council  - He legislated by certification approval.  - He was responsible for the day or day administration of colony.  - He appointed, promoted,dismissed and deployed officers of the government.  - He exercised the power of prerogative of mercy.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2000>Section B>9", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Trace the evolution of federalism in Nigeria from 1914 to 1954.", "images": [], "marking_scheme": "Evolution of federalism in Nigeria from 1914-1954    By 1914 Lord Lugard amalgamated the colony and protectorate of southern Nigeria and that of Nigeria which was done mainly for economic reasons. By 1922 a constitution was promulgated named Clifford constitution. The constitution provided for legislative council for the colony and southern protectorate of Nigeria. The Northern region excluded from the council by 1946 another constitution named after Arch Richards was promulgated. The constitution introduced regionalism under which the country was divided into three regions. North,West and East. There was however, no constitution.Division of powers existed.  Regional assemblies had no legislative powers. In 1951, Macpherson constitution introduced quasi-federal system which gave legislative powers on specific issues to the regional governments but subject to the ratification of the central government. The 1954 lyttleton constitution formally established an improved quasi. Federal system which divided legislative powers into exclusion,concurrent and residue  lists. Premiers were appointed to head the three regions.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2000>Section B>10", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Distinguish between the 1963  Constitution  and 1979 Constitution of Nigeria", "images": [], "marking_scheme": "19631979It provided cabinet system of governmentIt provides a presidential system of governmentIt allows the merging or combining of power between legislative and executiveIt enables the separation of powers among the Executive and Legislative.It declares official oppositionIt does not allow official opposition It support the supremacy of the parliamentIt hold on the view that constitution was supreme.Appointment of prime ministers among the elected parliamentarianIt provides a separate election of the president by the electorate.It did not allow prime minister to appoint members outside the parliament", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2000>Section B>11", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "What are the guiding principles of the Organisation of Africa Unity (OAU)?", "images": [], "marking_scheme": "- The sovereign equality of all member states.  - Peaceful settlement of disputes by negotiation,mediation,conciliation or arbitration.  - Affirmation of a policy of non-alignment with regard to all blocs.  - Absolute dedication to the total emanciation of the African territories which are still dependent.  - Respect for the sovereignty of member states.  - The organisation condemned outrightly attempt by any member state to destabilise another state.  - Non-interference in the internal affairs of member states.  - Non-revision of international boundaries as fixed during the Berlin conference of 1884.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2000>Section B>12", "subject": "Government", "year": "2000", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Describe any four benefits member states of the Common Wealth derive from the Organization", "images": [], "marking_scheme": "Benefit Members Of Common Wealth Derive From Organisation.   - Existence of trade co-operation from members of nation.  - It provides military assistance from member-nations.  - Common language in the organisation serves as unifying factor among member-nations i.e easy communication and understanding.  - It brings about the spirit of oneness and encourages healthy competition due to organised games and sports.  - Co-operation in the field of education e.g awarding scholarship etc.Which is facilitated by common language.  - Uniform legal system i.e assistance from one another  - It provides monetary and inform of loan for development purpose.  - Scientific co-operation i.e the enjoyment of scientific inventions of other countries.  - Encouragement of writers in elevating the educational standard of member nations.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section A>1", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What are the characteristics of feudalism?", "images": [], "marking_scheme": "Characteristics of Feudalism   - It is based on land ownership  - Land is legally vested on the king or monarch or superior   - Money or kind is paiding annually by the serfs(tenants) in tribute to the superior.  - The overlords(Superior) are duty bound to protect the serfs.  - Feudal tenants give military services to the overload.  - Only a vessel of the lord can receive land.  - It is characterised by close personal bond between the lords and serfs  - Vessels keep land as long as he performs his feudal duties e.g payment of tribute, military service etc  - The land goes back to the lord when the vessel dies without an heir.  - The monarch is the law-marker, judge and commander over his vessels.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section A>2", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Describe the basic features of a democratic state?", "images": [], "marking_scheme": "- Periodic election to elect representatives.  - Equal opportunity to participate in the decisions of government.  - Fundamental human right are guaranteed  - Rights of the minority are guaranteed   - Free and fair elections (an independent electoral commission updating the electoral register,secret ballot etc)  - Existence of political parties in the state.  - An independent judiciary  - Existence of opposition party", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section A>3", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Why do some countries adopt unitary system of government?", "images": [], "marking_scheme": "- Small size in terms of territory and population  - Relative homogeneity and absense of marked ethnic inequalities   - Limited human (skilled personnel) and economic resources.  - Identical political culture and history i.e common historical and political experience in administration.  - Desire for the preservation of national unity or identities and values.  - Simple and cheap to operate   - Desire for the preservation of national unity or identities and values.  - Simple and cheap to operate.  - Facilitates quick decisions-making.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section A>4", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "How can the revenue of Local Authorities in your country be improved?", "images": [], "marking_scheme": "- Grants from the central government should be increased.  - Grants to local authorities should be paid regularly and promptly to encourage investments in variable projects.  - Local rates should be reviewed and where it is low, it should be increased to cater for inflation.  - The revenue collecting sector should be revised and only qualified officers with proven integrity should be responsible for collecting revenues.  - The local authorities should be allowed by the central government to raise loans more easily from financial institution.  - More revenue yielding.Projects should be embarked upon e.g commercial agriculture housing project etc  - The local people should be well educated to pay their rates regularly.  - Regularly auditing of the accounts of the accounts of the local authorities.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section A>5", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "5", "group": "", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Enumerate the methods used by pressure groups to achieve their objectives.", "images": [], "marking_scheme": "-  Demonstration/Protest : It protest against a government policy through rioting, hijacking and holding people as hostages.  -  Work-to-rule : No extra work is done apart from the normal working period.  -  Strike : Pressure group may refuse to work to back their demand.  -  Boycott :Sometimes pressure group refuse to operate with the authorities untill their demands are met.  -  Special publication :This is done either in the press or a booklet to published on their action  -  Debates and Symposia/Workshop :These are organised to educate people on their work and also their stand on some issues.  -  Campaigns and Propaganda :They mount effective campaigns and propaganda by writing letters to the radio,television,newspaper etc to educate the public and to show their stands on some issues inorder to win and influence the public opinion and achieve their aims.  -  Lobbying :They use the members of the legislature as a passage in other to pass law that are favourable to their members.  -  Presentation of Gift :They influence the policy makers with gifts  -  Alliance with Political Parties :They associate join, or unite with political parties in order to influence election election results by making monetary contributions.  -  Sending a Delegation :They select some of their members to discuss their problems with the government or decision makers  -  Pressure on Civil Servant :Pressure mount on civil servant in order to execute some government policies in their favour  -  Ultimatum :These are final statements of conditions pressure groups issue to be accepted by the government without which actions they may deem necessary will be taken.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section B>6", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "How did the people of any one British West African territory govern themselves before and advent of colonial rule?", "images": [], "marking_scheme": "- The people were governed by customs,rules and norms.  - The paramount chief was at the apex of the administration.  - The chiefs and council of elders made laws.  - The age grades executed laws   - The traditional rulers and elders exercised legislative,exercised legistrative, executive and judiciary functions i.e there was no separation of powers  - The chiefs priest and secret societies performed religious functions and checked arbitary use of power by chiefs.  - Queen mothers and palace women performed important roles e.g settling disputes among women,advising the chiefs etc   - Revenue was raised through tributes and taxes.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2001>Section B>7", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION~~NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "State how the British colonial policies contributed to the rise of nationalism in West Africa.", "images": [], "marking_scheme": "- The crown colony policy was not acceptable to the nationalist i.e both the legislative and executive councils were dominated by British official. Only illiterates African chiefs were nominated as members of the legislative council.  - Opportunities provided for the Africans to participate in governement through constitutional development.  - Inequality in wages between whites and natives especially in commercial enterprises.  - Provision of educational facilities through missionaries made the Africans politically concious.  - The land was unfavourable to the chiefs and people.  - Colour bar and social segregation e.gHousing estates,Recreational facilities,hospitals and schools.  - Little or no opportunities for the advancement of the Africans in the public service.  - Economic inequalities between the white and the indigenes especially in commercial enterprises e.g granting of loans by banks, the activities of companies like UAC, UTC,PZ.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section B>8", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Describe the main features of the 1946 Richards Constitution of Nigeria.", "images": [], "marking_scheme": "- It was brought the north and south together under one legislature.  - It granted the north a bicameral legislature i.e the regional assembly and the regional assembly and the regional assembly and regional house of chiefs.  - Certain services were reserved to the central government and were financed by the central government e.g railways, army post and telegraphs.  - The regional council were used as electoral colleges for representation in the legislative council.  - The revenues of Nigeria were given to each region in the form of bulk grants.  - Members of the central legislative council were at the same time.  - The native authorities were linked with regional assembly and through the later to the central legislative council.  - Members of the regional council, the central legislative had regional, instead of national outlook.  - It led to the creation of regional assemblies with limited powers to legistrate on minor matters subject to the governor's  - Nigerians were in minority in the central executive council were at the same time.  - Limited franchise was maintained 3 representatives were elected for lagos and i for calabar.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section B>9", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Outline the objectives of the National Council of NIgeria and the Cameroons (N.C.N.C).", "images": [], "marking_scheme": "- To promote higher education as well as compulsory and free education for the children.  - To arouse mass interest and obtain overwhelming national support for political reforms.  - To advance the interest of the people of Nigeria and the cameroon under the British mandate.  - To achieve political independence by giving political education to the people of Nigeria.  - To organise and collaborate effectively with all its branches through out the country.  - To provide the members with the medium of expression in order to secure political freedom, economic security,social equality and religious tolerance.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2001>Section B>10", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What were the causes of the 1975 military coup de'tat in Nigeria?", "images": [], "marking_scheme": "- Corruption:The government was corrupt practices of contractors,government officials etc  - Government was not able to arrive at a definite figure for 1973 census. Government announced only provisional figures which were not generally acceptable.  - The government disregarded public opinion or some major national issues e.g creation of more states.  - Mismanagement of armed forces.  - Indecision on the part of the then government on major policies of government e-g redeployment of governors and permanent secretaries.  - Port-congestion leading to scarcity of essential commodities.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2001>Section B>11>a", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is  foreign policy ?", "images": [], "marking_scheme": "Foreign policy -refers to the strategy and tactics employed by a state in conducting her relationship with other states while pursuing her interest.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2001>Section B>11>b", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Outline the basic factors that inflence Nigeria's foreign policy.", "images": [], "marking_scheme": "- Historical background e.g Nigeria's membership of the common wealth   - Ideological disposition of the rulers:Countries tend to relate more with those countries with similar ideologies.  - The military strength of Nigeria(i.e size of the army and the quality influence her foreign policy)  - Types of government e.g military to democratic governments.  - The economic resources available to Nigeria e.g mineral resources and agricultural products  - Population:Large size and quality of human resources of Nigeria affect her foreign policy.  - The industrial strength of Nigeria influence her choice of trading partners e.gElectricity supply to Niger,Republic of Benin and Togo Gas to Ghana.  - Public opinion on issues can bring changes in government foreign policy e.g Anglo-Nigeria pact of 1962.  - Location:Africa is described as centre piece of Nigeria's foreign policy.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2001>Section B>12", "subject": "Government", "year": "2001", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Highlight the functions of the Assembly of Heads of State and Government of the Organization of Afican Unity (O.A.U)", "images": [], "marking_scheme": "- It acts as the highest decision making organ of O.A.U   - It approves the regulations governing the function and conditions of service of administrative secretary general, his assistants and the other staff.  - It decides on the admission of new members  - It discuss matters of common imterest of member states.  - It considers reports from the secretariat.  - It has power to establish specialised commissions.  - It co-ordinates and harmonises the general policies of the organisation.  - It examines and reviews the structure,composition and functions of all other organs and specialised agencies of the organisation.  - It appoints the important officers of the organisation such as Secretary General.  - It appoints adhoc committees to settle disputes involving member states.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2002>Section A>1>a", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Describe the term \\! State \\.", "images": [], "marking_scheme": "State:is defined as a society organised by law within a definite territory under a single sovereign.", "marks": "8", "difficulty": "1"}, {"id": "theory>Government>2002>Section A>1>b", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "What are the features of a state?", "images": [], "marking_scheme": "Before a society could be described as a state the following features must be present in such society.  - Territory:This refers to the location of the society, it must be definite and permanent. A group of wanderers moving from one location to the other cannot be described as a state.  - Population:This refers to the presence of people. It should be noted that an area where nobody inhabits such as Atlante sahara desert etc.  cannot be said to be state   - Government:This is the body that controls the affairs of the state. There could be noted that the government of a state should be recognised locally and intentionally.  - Soveignty:This refers to the supreme authority that makes and enforces law within the state without external influence.", "marks": "12", "difficulty": "1"}, {"id": "theory>Government>2002>Section A>2>a", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain the concept of the rule of law", "images": [], "marking_scheme": "Rule of law means the absolute supremacy or predominance of law over every citizens(everybody) both the ruler and the ruled and all decisions taken in a country.The concept of the rule of law was popularized by Professor A-V Dicey.", "marks": "8", "difficulty": "2"}, {"id": "theory>Government>2002>Section A>2>b>i", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Give two advantages of the rule of law", "images": [], "marking_scheme": "- It brings about equality before the law.  - It promotes justice,fear play and good governance.  - It prevents the emergence of dictatorship  - Fundamental human rights are enjoyed by the citizens.  - There is no partiality in dealing with offenders.", "marks": "6", "difficulty": "1"}, {"id": "theory>Government>2002>Section A>2>b>ii", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Give two limitations of the rule of law.", "images": [], "marking_scheme": "- Existence of special administrative tribunals  - Special immunity granted to certain people such as the president,judges,diplomats e.t.c  - Lack of moral integrity of judges.  - The poor suffers the brunt when justice is purchased in the court of law as commodity.  - Poverty,illiteracy and ignorance deprive citizens of their right.  - People's age determine the legal offence they committed not withstanding e.gchildren under eighteen years cannot prosecuted  - People's age determine the legal offence they committed not withstanding e.g children under eighteen years cannot be prosecuted.", "marks": "6", "difficulty": "1"}, {"id": "theory>Government>2002>Section A>3", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Highlight three merits and any three demerits of a simple majority system of voting", "images": [], "marking_scheme": "The advantages of Simple majority system of voting are:  - The system is very simple to operate.  - It makes it easy for the election results to be ascertained.  -The system discourages the formation of coalition government.  - It makes elected candidates to be responsible and accountable to the electorate.  - It is economical to operate.  - It ensures the emergence of a stable government.  The disadvantages of Simple majority system of voting are:  - It is sometimes undemocratic because it neglects the wishes of the majority of the voters as majority votes are wasted.  - Majority ethnic groups can use their majority strength to secure simple majority at the expense of the minority groups.  - It encourages election rigging in order to secure highest number of votes.  - It encourages gerrymandering.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2002>Section A>4>a", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the concept of the  sovereignty of a State", "images": [], "marking_scheme": "Sovereignty means the supreme authority that has power to make laws and enforces such laws without external influence or control. Sovereignty is usually grouped into different types e.g legal sovereignty, popular or political sovereignty, popular or political sovereignty, Defacto, De-fure and external sovereignty.", "marks": "8", "difficulty": "2"}, {"id": "theory>Government>2002>Section A>4>b", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "State any five factors that limit the sovereignty of a State", "images": [], "marking_scheme": "Limitations   - Member nations must respect international law and charters of the various bodies such as U.N.O.A.U(African union) Opec etc which are membership of international organisation.   - International law and agreements on fundamental human right, labour etc.  - Influence of public opinion: The decision of the public supercedes that of government. A good government must respect and listen to public opinion.  - Pressure groups:These are powerful and influential groups that cannot be ignored by the government.  - Economic factors e.g debts to other nations, external aids and assitance.  - The donor country may dictate how the recipient country must use the assistance being rendered.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2002>Section A>5", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "What major reforms were made in the local government system in Nigeria in 1976?", "images": [], "marking_scheme": "In the National guidelines for local Government reform published in August 1976 by the General Olusegun Obasanjo administration aimed at unifying the hitherto multiple's system of local government in Nigeria as a true and third tier of government.   THE REFORMS   The major forms centered on the following areas:  -  The introduction of a uniform local government system in NIgeria in terms of structure,functions,financing,operational modalities etc  - The reform stated the condition for creating new local government such as must have a population ranging between 100,000 and 800,000  - For the first time, all local governments were made the third tier government after the federal and state government.  - The guidelines made all local governments in Nigeria a single-tier instead of all the multiple system.  - Unlike before, chairman and supervisory councillors became full time and workers of local government   - The federal government cancelled all the debits of the local government to enable them off effectively.  - For efficiency and coordination of government activities, special grants were given to local governments to enable them build their secretariats.  - The guidelines directed all state government to set up local government service board to ensure quality personnel in the local government level.  - To remove local government from partisan politics, local government councillors were to be elected on individual merits instead of party tickets.  - The reform harmonized the conditions of service of local government markers with personnel of both the federal and state government.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2002>Section B>6", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Describe the functions of the age-grades in the pre-colonial administration in Nigeria", "images": [], "marking_scheme": "The age grades was one of the main political institutions of pre-colonial societies.They performed a lot of functions which are listed below.  -  Defence :The age grade served as members of armed forces.Among their duties was to defend their commodities against attack both form within and outside their societies.They were militant in carrying out their duties.  - Public work:Members of the age grades participated actively in carrying out community work such as construction of path roads,maintenance of good environment hall,clearing of places meant for public use.  - Security functions:The various pre-colonial communities ensured proper maintenance of law and order.The age grades served as the communities police.They carried out investigations on criminal activities,made arrest and punish offenders.  - Socialization Function:Apart from the functions above age-grades also carried socialisation functions above age-grades.They educated their members about their community. They organised awareness programmes for themselves and the community in general.  - Prevent Abuse Of Power:As an important political institution in the society, age grades acted as checks against abuse of power or office by traditional chiefs and council of elders. This was done to prevent tyranny in the community.  - Implementation of Policies:As an important organ of pre-colonial societies, age-grades also carried out ceremonial organised by the community.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2002>Section B>7", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Highlight the external factors that aided the Nationalists in their struggle for political independence", "images": [], "marking_scheme": "Nationalist activities in West Africa took a more militant posture after second world war. It changed from its mild nature of radical and the demands of the nationalists changed from reform to independence as a result of these external and internal affairs.   External Factors  - The Atlantic Charter:The publication at the end of the sound world war of the Atlantic charter in 1914 when American joined the war raised the hope of the nationalist leaders. The charter declared the right of all peoples to choose the form of government under which they will be governed. The charter was signed in new found land in U.S.A between the American president Roosevelt and the British prime minister winston churchill.  - The support of the British labour party:The british labour party played an important role in the growth of nationalism in West Africa.The party condemned and critised British colonial policies in Africa and called on Britain to extend to other people of the world that freedom which they enjoyed.  - Pan-African Congress:The activities of Pan African Congress from 1945 contributed immensely in rekindling spirit of nationalism in W est Africa. Many African intellectuals started taking greater part in the activities of the congress right from October 1945.  - USSR and U.S.A:The second world war established USSR and USA as the most powerful nations in the world. These two super powers that emerged after 1945 condermned European colonialism and imperialism in all its forms.  - Loss of British Prestige: The defeat of Britain suffered in the hands of Japan on non European power had psychological effects on colonial territories.It made the west African people realise that Britain and other whites were not as powerful as they hitherto thought  - Independence of India:The independence of India in 1947 reshaped that inspiration of nationalism that was a British colony for many years could ward off the shackles of colonialism.  - Anti-colonial posture of U.N.O-The anti-colonial posture of the united Nations organisation(U.N.O) that replaced the league of Nations Organisation (U.N.O) that replaced the league of Nations after 1945 was another factor that awakened the spirit of nationalism in West Africa. The organisation carried out its aim of eradicating colonialism and imperialism vigorously by putting such pressure on colonial powers.  - The socialist and communist influence   - Activities of organisations formed by Africans in Britain e.g the west Africa students union(WASU)  - Intellectual write-ups", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2002>Section B>8", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Give six reasons for political instability in any one West African country after independence", "images": [], "marking_scheme": "- When the right and freedom of the people are trampled upon.  - Corruption and mismanagement of the wealth of a country by the leaders.  - Rigging of votes and intimidations during elections which leads to political crisis   - Mass unemployment and poverty.  - When the government is not open and transparent   - Intolerance for the views and opinion of others can lead to political instability", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2002>Section B>9", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Explain the importance of the Lyttleton Constitution of 1954 in the polical development of Nigeria.", "images": [], "marking_scheme": "The outcome of the London conference of 1953 and that of Lagos was named after the then secetary of state for the colonies Mr.Oliver Lyttleton later Lord Chander.The 1954 constitution was important because of the following reasons:  - The central legislative now known as federal house of representatives was composed of 184 directly elected representatives in terms of 92 members for north, 42 for west and 42 members for eastern region.  - The central council of ministers become the policy making body of government with three members from one region, three official members and one member from southern cameroon.  - The Regions-The constitution formally created three main regions i.e Northern,western and Eastern region. The house of Assembly of each region was given legislative powers.  - The constitution formally established federal system of governments.  - The regional House of Assemblies ceased to serve as electoral colleges for the central legislature.  - The titles of the chief executives were changed. The chief executives of the country was identified as Governor General while the Regional chief executive were called Governors in place of Governor and It-Governors respectively as they were known by the 1951 constitution.  - Speakers were appointed to preside over the legislatures instead of the Governor and It.Governor as the case was before 1954.  - For the first time the Judiciary and civil service were decentralised and each region received powers to set up its own marketing Board for the sale of the major commodities produced in the region.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2002>Section B>10", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "What were the functions of the Secretary of State for the colonies in the colonial period?", "images": [], "marking_scheme": "Functions of Secretary In Colonial Period   - Responsible and accountable to British parliament.  - Supervised the colonial administration by giving directives to the Governors based on the British policies.  - Advised the governors on the affairs of the colonies e.g during crisis.  - He approved major projects to be undertaken in the colonies.  - He could overide the Governors veto and power of certification.  - Approved the draffing of a new constitution for the colonies.  - Controlled the finances of the colonies through approval of the budget and auditing of accounts", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2002>Section B>11", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Highlight the basic principles on which the United Nations Organization (UNO) was founded.", "images": [], "marking_scheme": "The United Nations Organisation(U.N.O) which was formed in 1945 to replace the league of nations has the following principles.  - The organisation was based on the principle of Sovereignty of equality of all members.  - All members of the U.N.O are to carry out their obligations which they have signed under the charter of the organisation.  - Settlement of International disputes in peaceful way means in such a manner as not to endanger world peace and security.  - That members should refrain from the use of threat or force in the conduct of their relation in any way inconsistent with the purposes of the United Nations.  - That all members will support the United Nations in any action taken in accordance with the charter of the organisation.  - That all member states must fulfil the above aims and objectives in good faith.  - To ensure that non-member states must fulfill the above aims and objectives in good faith.  - That the United Nation shall not intervene in matters which are essentially within the domestic Jurisdiction of members states except when it is acting to enforce international peace and security.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2002>Section B>12", "subject": "Government", "year": "2002", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "In what four ways has Nigeria demonstrated that Africa is the centre-piece of her foreign policy?", "images": [], "marking_scheme": "- Support for OAU: Successive Nigerian governments have given political, financial and diplomatic support to the Organisation of Africa Unity because Nigeria believes that OAU is the foremost continental machinery for the articulation of African interests.  - Nigeria's African policy is shown in her anti-colonial pre-occupations as Nigeria has committed herself to ridding Africa of all forms of colonialism and neo-colonialism by sending aid and material assistance to freedom fighters.  - Nigeria identified herself with the anti-apartheid front by giving moral, political, financial, material and diplomatic support to the liberation movement in South Africa.  - Nigeria has often undertaken the promotion of intra-African economic co-operation, e.g. creation of ECOWAS in 1975 and the African Economic community in 1991.  - Nigeria is committed to peaceful settlement of inter-state disputes as she has played active role in the settlement of political crises in Liberia and Sierra Leone through the formation of ECOMOG.  - Nigeria has.been seriously involved in the promotion of intra-African sporting competitions through hosting of important sporting events, e.g. the All African Games and the African Nations cup co-hosted by Nigeria and Ghana.  - Nigeria has championed the provision of technical aid and expertise to sister African States, e.g. TACS.  - Nigeria has shown high commitment to the promotion of cultural ties amongst African nations, e.g. FESTAC.  - Nigeria has influ-enced other African countries to speak with one voice at international organisations such as the UNO, OAU and the commonwealth of nations.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>1", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "What is government as an academic field of study?", "images": [], "marking_scheme": "Government as an academic field of study involves the study of political institutions in the state, ideas, values and doctrines about politics, the view of political thinkers on what constitutes the welfare of the people. It is a social science subject that is taught in schools & colleges as well as in higher institutions where it is popularly known as political science.  The study of government embraces international relations, local government administration, public administration, comparative politics e.t.c. Government as a science studies politics through the use of computers, research, statistics and analysis o data.", "marks": "20", "difficulty": "1"}, {"id": "theory>Government>2003>2>a", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Outline any three fundamental human rights of a citizen.", "images": [], "marking_scheme": "- Right to dignity of human person.  - Right to life.  - Right to freedom of thought, conscience and religion.  - Right to peace assembly association.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2003>2>b", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "What are the limitations of these rights?", "images": [], "marking_scheme": "- Right to life can be limited by criminals.  - Right to dignity of human person can be limited by the process of war, diseases, riot, disaster etc.  - Right to personal liberty can be limited by war, disease, riot etc.  - Right to fair hearing can also be limited by riot, war, disease.  - Right to private life and family life can be limited by disease war, riot e.t.c.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2003>3>a", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Explain this term in electoral systems    Simple plurality system.", "images": [], "marking_scheme": "This is an electoral system in which the candidate with the highest number of votes even though he may not secure the majority of the votes is declared winner of the election. It is also known as first-past-the post system.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2003>3>b", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Explain this term in electoral systems  The repeated ballot.", "images": [], "marking_scheme": "This is an electoral system in which voters vote continuously with intervals for discussions and negotiations until a winner emerges. A typical example is when a new pope is to be elected by a body of cardinals.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2003>3>c", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Explain this term in electoral systems  The second ballot.", "images": [], "marking_scheme": "This is an electoral system in which the two candidates who secured the highest number of votes are made to face the electorate at a later date. Voters who supported the less successful candidates are able to switch their support to either to the two leading candidates until a candidates secures the majority votes & wins. It is also known as run-off election.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2003>3>d", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Explain this term in electoral systems  The alternative vote.", "images": [], "marking_scheme": "This is an electoral system designed to secure majority representation of the electorate under the system, voters are issued ballot of papers in which they must indicate their preference in order of importance by marking 1, 2, 3 e.t.c. The candidates with the least preferences are repeatedly knocked down/out until a winner emerges.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2003>4", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "How is the Executive controlled in the exercise of its powers and functions?", "images": [], "marking_scheme": "- The constitution places limitations on the exercise of the powers and functions of the executive.  - Actions of the executive could be challenged in the courts and such acts could be declared illegal, null and void.  - Judicial application of certain writs e.g habeas corpus, mandamus, injunction e.t.c could be used to control the executive to do certain things.  - Some appointments and decisions of the executive hire to be approved by the legislature in presidential system of government.  - Impeachment of the president in the presidential system while in parliamentary system of government a vote of no confidence on the executive can be passed.  - A change of government by peaceful or violent means could be used if the government becomes unpopular or unreasonable.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>5", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "What factors led to the increasing popularity of the presidential system of government in West Africa?", "images": [], "marking_scheme": "- The friction that characteristics the parliamentary system as a result of the division of ceremonial and executive functions is removed.  - Given the mode of his election and his powers, the president is capable of instituting a strong executive that can promote faster rate of nation building.  - It eliminates the parliamentary collective responsibility requirement of all cabinet resigning because of one man's mistake.  - It ensures quick decision making process as there is no official opposition.  - It make it easy to identify who has responsibility or certain functions or who is to blame for inaction.  - The desire by West Africa to experiment a new system led to the adoption of presidential system of government.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2003>6", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "In what ways did colonial rule contribute to the decline of the powers of the traditional rulers in West Africa.", "images": [], "marking_scheme": "- Introduction of wage earning for working subjects by colonial government gave the subject economic independence from the traditional rulers.  - The impact of Western education led to the break down of traditional norms and values of society.  - The influence of foreign religion scaled down the powers of traditional rulers as the spiritual authority of their people.  - Establishment of law courts by colonialists reduced the law-making function of traditional rulers.  - Colonialism introduced native/local authorities which took over the traditional rulers absolute control over taxation and it disbursement.  - Stoppage of inter-tribal wars put an end to the means by which traditional rulers accumulated wealth.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>7>a", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Describe the organizational structure of the Nigerian Youth Movement (NYM).", "images": [], "marking_scheme": "- The Nigerian Youth Movement (NYM) congress/convention   - The NYM had a national executive headed by a president.  - It had branches established in some urban areas throughout Nigeria.  - It utilized ad hoc committees.  - Its national headquarters was in Lagos.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2003>7>b", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "What led to its collapse?", "images": [], "marking_scheme": "- Internal wrangling within the movement.  - Internal weaknesses of the NYM structure.  - Tribal conflicts which pitched the leaders.  - The resignation of Dr. Nnamdi Azikiwe and Samuel Akinsanya.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2003>8", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Highlight the factors that contributed to the failure of the policy of Assimilation in French West African colonies.", "images": [], "marking_scheme": "- Cultural differences between french people and the people of West Africa.  - The policy was rigid and discriminatory.  - The reduction in power of the traditional chiefs accounted for its failure.  - The system was a financial burden on the people of france who therefore criticised it.  - The french intellectuals and merchants were opposed to the policy which would create a situation of equality between frenchmen and Africans.  - The success of indirect rule system in Nigeria motivated the need for change of the french policy.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>9", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Describe how a Legislative Council was controlled in British West Africa before the Second World War.", "images": [], "marking_scheme": "- Veto Power: The governor had the power to veto laws passed by the legislature council.  - Money bills: The governor had the exclusive rights to introduce money bills.  - Casting vote: As president of the legislative council, the governor had a casting vote.  - Power of certification: Empowered the governor to enforce a bill that had been rejected by the legislative council.  - Official control: The legislative council was mainly controlled by official majority initially.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>10", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Why did the nationalists criticize the post - 1954 constitutions in British West African colonies?", "images": [], "marking_scheme": "- They were opposed to the continuing inclusion of nominated members into the legislature.  - Inclusion of traditional rulers in the legislature was seen as not allowing for greater participation of educated elites  - The limited or qualified franchise.  - The executive council was not responsible to the legislature.  - Few elected members in the executive council.  - The continuing retention of the veto and reserved powers of the colonial governor.  - Inadequate consultation with people by the colonial administrators before the adoption of some of the consultations.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>11", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Outline the conditions that gave rise to the adoption of federalism in Nigeria.", "images": [], "marking_scheme": "- Fear of domination  - Tribal differences  - Protection of the interest of minority Groups  - The size of the country population  - For rigid and even development  - To bring government close to the people  - To expand local markets  - For easy and effective government  - To create more employment opportunities  - For diverse law to be made  - For security reasons  - Geographical proximity.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2003>12", "subject": "Government", "year": "2003", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "In what ways do member states of the Organisation of African Unity (OAU) co-operate with one another", "images": [], "marking_scheme": "- Peaceful settlement of disputes by negotiation, mediation e.t.c.  - Unreserved condemnation in all form of political assassination   - Economic co-operation  - Educational, sports and cultural co-operation  - Health, Sanitation and Nutritional Co-operation  - Scientific and technical co-operation  - Respect for the sovereignty of each state.  - Eradication of all forms of colonialism from Africa.  - Taking collective decisions in international bodies.  - Provision of military aid and support for countries in need.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2004>1>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is Capitalism?", "images": [], "marking_scheme": "Capitalism is a political and economic system in which the means of production, distribution and exchange are owned and controlled by private individuals and in which the economic activity of the government is at a minimum.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2004>1>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline any five features of capitalism.", "images": [], "marking_scheme": "- Private ownership and control of the means of production and distribution.  - Profit motive is the guiding principle.  - The economy is subject to the market forces of demand and supply.  - There is freedom of choice to consumers, workers and owners of capital.  - It has highly developed occupational specialization.  - There are many producers as well as buyers.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2004>2>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain decentration.", "images": [], "marking_scheme": "Decentralization refers to a system of government administration in which powers are not concentrated in a single central authority only but shared with component regions, states, provinces and local units. Such Powers are clearly specified in the constitution or enabling act/law. It involves devolution, delegation and deconcentration of powers.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2004>2>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "State four advantages of decentralization.", "images": [], "marking_scheme": "- It enhances political unity.  - Faster pace of development.  - Encouragement of healthy competition.  - It brings government nearer to the people.  - It increases efficiency of government.  - It reduces the work-load of central government.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2004>3", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "What are the characteristics of the judiciary in a state?", "images": [], "marking_scheme": "- IMPARTIALITY: The judiciary is impartial.  - POLITICAL NEUTRALITY: The Judiciary is politically neutral. Judges do not engage in partisan politics.  - PERMANENCE: The Judiciary is a Permanent Institution inherited by Successive governments.  - INDEPENDENCE: The Judiciary is made Independent of the executive and the legislature.  - PROFESSIONALISM: The Judiciary is made up of Judges who are legal experts.  - STABLE TENURE OF OFFICE OF JUDGES: In some countries, judges hold office until they retire if they are not fount guilty of any corrupt practices, ill health.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2004>4>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Define the rights of a citizen.", "images": [], "marking_scheme": "Rights of citizen are legal claims or entitlement, which every citizen enjoys in a country and which the state has a duty to protect and guarantee.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2004>4>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Highlight five ways of safeguarding the rights of a citizen in a state.", "images": [], "marking_scheme": "- The entrenchment of fundamental human rights of citizens in the constitution is a way of safeguarding their rights.  - Existence of principle of the rule of law: The government under the Principle of the rule of law has an obligation to ensure the existence of civic liberties and equality of all citizens.  - Independence of the Judiciary for citizens to enjoy their rights the judiciary should be free from the Interference and control of both the executive and the legislature.  - Freedom of the Press: The press should be free to serve as the watchdog for the rights of the citizens.  - Activities of the opposition: The opposition, whether in government or outside, is a Powerful Instrument for Protecting the rights of the citizen.  - Consciousness and Vigilance of citizens over their rights.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2004>5", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Differentiate between government and state.", "images": [], "marking_scheme": "STATEGOVERNMENT- A state is a territorial association of people with defined boundaries.Government is an administrative institution within a state.- A state is more inclusive and therefore greater than government, i.e it embraces all the people and associations within a given areaGovernment is not as inclusive as a state it is only a part of a state.- A state is a continuing entity. It is therefore permanent.Government is a temporary institution. It only lasts over a period of time.- A state depends on government for carrying out it activities.Government is the machinery by which the functions of a state are performed. It is the means by which a state maintains its existence.- A state has its elements as population, territory, government and sovereigntyGovernment has its main organs as the legislature, executive and judiciary.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2004>6", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "State any two merits and four demerits of the Clifford Constitution of the 1922 in Nigeria.", "images": [], "marking_scheme": "- The constitution introduced elective principles which for the first time allowed Nigerians to elect their representatives to the legislative council.  - It paved way for the formation of political parties in Nigeria.  - More Africans were allowed into the legislature council.  - It was the first written constitution for Nigeria.  - It established a constitutional government in Nigeria as opposed to government by statutory instrument or orders.  - It increased political awareness through political education during political party campaigns.      - The British still dominated the legislative council  - Majority of the members of the legislative council were nominated  - The executive council was made up of officials to the exclusion of Nigerians.  - The application of the elective principle was limited to Lagos and calabar.  - The constitution limited its Jurisdiction only to the Southern Provinces.  - The governor was vested with Veto and reserved powers.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2004>7", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "Outline six functions of the Emir in the Hausa/Fulani traditional political system.", "images": [], "marking_scheme": "- The emir appointed officials e.g Madawaki/Waziri/Galadima/Hakimi  - He provided social security for the people  - He organised his people for communal work  - He organised his people for defence of the emirate  - He enforced the sharia (islamic law)  - He was the Spiritual head of the emirate.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2004>8>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Identify four political parties in Nigeria during the Second Republic.", "images": [], "marking_scheme": "- People's Redemption Party (PRP)  - National Party of Nigeria (NPN)  - Unity Party of Nigeria (UPN)  - Nigerian People's Party (NPP)  - Great Nigerian People's Party (GNPP)  - National Advance Party (NAP)", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2004>8>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Describe any four functions performed by political parties.", "images": [], "marking_scheme": "- They help to recruit leaders to political offices in the government as well as within the parties.  - They educate the electorate on how to vote and why the should vote. They hereby help to create political awareness.  - They provide programmes which they hope to implement when voted into power.  - They organize rallies, campaigns, lectures, debates and symposia on government programmes and activities.  - They provide employment opportunities.  - They perform welfare, social and humanitarian functions.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2004>9>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the term Native Authority.", "images": [], "marking_scheme": "Native Authority was an institution of local administration of indirect rule system in British West African colonies.", "marks": "8", "difficulty": "1"}, {"id": "theory>Government>2004>9>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "State four defects of the Indirect Rule system.", "images": [], "marking_scheme": "- It increased the Power of the traditional rulers to the detriment of their subjects.  - The imposition of warrant chiefs and taxations where there were none, made the system unpopular e.g Isehin and Aba riots (Hut War in Sierra Leone).  - It created tension and misunderstanding between the chiefs and educated Africans.  - It was autocratic since colonial authorities had power to override the decisions of the native administration.  - The system made the chiefs corrupt e.g mismanagement of funds, embezzlement of taxes, forced labour e.t.c.  - The activities of the native courts were unsatisfactory, they were slow, corrupt, inefficient e.t.c.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2004>10", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Highlight and six features of the Independence Constitution of your country.", "images": [], "marking_scheme": "- It provided for the appointment of a General for Nigeria  - The judicial committee of the privy council in Britain was retained as the Highest Court of Appeal.  - Prime Minister: Executive functions council in Britain were as the Highest Court of Appeal.  - Prime Minister: Executive functions were ascribed to the prime minister.  - Parliamentary system: It embraced the British Parliamentary system of government.  - Fundamental Human Rights: It was entrenched in all the independence constitution.  - Citizenship: Provisions were made for definition of citizenship.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2004>11>a", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What is Military Rule?", "images": [], "marking_scheme": "Military Rule is a form of unconstitutional administration of a state by member of the armed forces based on martial laws (Decree & Edicts) after successfully overthrowing the government of the state or country.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2004>11>b", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Give five reasons why people reject Military rule in West Africa.", "images": [], "marking_scheme": "- By training of the armed forces they are not meant to rule.  - Military rule is characterized by corruption, tribalism, sectionalism, nepotism.  - Military govt is undemocratic and unconstitutional.  - Undermilitary rule there is no accountability to the people.  - In the process of state and loca government creation, military rule often brings confusion in the country.  - Military rule frustrates all efforts at establishing democratic government.  - Military rule is autocratic i.e ruling by decrees and edicts .", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2004>12", "subject": "Government", "year": "2004", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Discuss the functions of the General Assembly of the United Nations of Organization (UNO).", "images": [], "marking_scheme": "- It delibrates on issues pertaining to worl peace and security.  - It discusses, approves and controls the annual budgets of the UNO.  - It approves the appointment of the secretary-general of the UNO.  - It receives and considers reports from all other organs and specialized agencies of UNO.  - It admits new members into the organisation.  - It adopt resolutions on fundamental human rights issues.  - It suspends or expels any erring member state.  - In conjunction with the security council, it elects judges to the International court of Justice.  - It amends the charter of the organisation.  - It initiates, studies and makes recommendations concerning development and codification of International laws.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2005>1>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the term authority.", "images": [], "marking_scheme": "Authority can be defined as legal right to make and enforce laws or policies which the citizens obey. Authority connote the acceptance of the right to rule as conferred by the people.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2005>1>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What are the main sources of political authority?", "images": [], "marking_scheme": "- Traditional authority: This is derivable from custom and traditions of the people.  - Legal authority: The source of this authority is mostly the constitution of a given country.  - Charismatic authority: This is the authority derived from special and unique qualities of an individual which makes him to be accepted as a leader.  - Consent of the people: People may decide to invest a certain person with authority. This could be as a result of his philantropic work in the community.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>2>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Explain the concept proletariat.", "images": [], "marking_scheme": "Proletariat: This is a socialist concept of exploited class/workers in a capitalist system. They do not own the means of production but earn their living through labour wage.", "marks": "8", "difficulty": "3"}, {"id": "theory>Government>2005>2>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight four features of socialism.", "images": [], "marking_scheme": "- Means of production: There is the state ownership and control of the means of production & distribution.  - Employment: There is gainful employment for all citizens in the country.  - Free education and free medical services: Free education and free medical services are provided for all citizens.  - One sole party: There is existence of only one political party.  - Private enterprises: Individuals are not allowed to engage in the production and distribution of good and services.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2005>3>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "What is a representative government?", "images": [], "marking_scheme": "Representative government: This is also known as indirect democracy is defined as a government of elected representatives of the people. Those elected, through organised elections, rule on behalf of the people.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2005>3>b>i", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "- State two features of a representative government.", "images": [], "marking_scheme": "- Free and fair elections  - Periodic elections  - Independent electoral commission  - Free press  - Existence of law courts  - Freedom of choice  - Universal adult sulfrage.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>2005>3>b>ii", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Outline three conditions necessary for a representative government.", "images": [], "marking_scheme": "- Rule of law: There is the need for everybody, including the political leaders, to abide by the provisions of the constitution.  - Written constitution: helps to specify the rules of the game as everything will be properly documented.  - Universal adult suffrage: Every qualified adult should be allowed to vote and be voted for in any political elections.  - Independent and impartial judiciary: This institution should be free from undue interference and control from other arms of government.  - Fundamental human rights: These rights are necessary for a representative government and should be entrenched in the constitution.", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2005>4>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Describe separation of powers.", "images": [], "marking_scheme": "Separation of powers: It is defined as division of political powers and functions among the three arms of government it was propounded by baron de militesquieu in his book titled The of laws.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>4>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "How does separation of powers operate under the presidential system of government?", "images": [], "marking_scheme": "- President/Head of state do not make laws.  - Dissolution of parliament.  - Appointment of Judges.  - Judicial review.  - Individual responsibility.  - Elected by popular support.  - Checks and balances.  - Impeachment.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2005>5>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Explain the term bureaucracy.", "images": [], "marking_scheme": "Bureaucracy: This is the same as Red-Tapism. The civil service lay two much emphasis on protocol, especially, on the issues that demand urgent attention. This slows down decision making and implementation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>5>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "State five functions of a modern civil service.", "images": [], "marking_scheme": "- Formulation of policies: They formulate policies and these are part of the objectives of government.  - Implementation of policies: The civil service ensures that the policies made are executed.  - Preparation of budget: It prepared the government's yearly statement of expected income and expenditure.  - They make bye-laws: The power to make bye-laws is made possible through delegated legislation.  - They advice government: They advice government on issues facing the country for a better result.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>6", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "What were the roles of the traditional rulers in Nigeria in the pre-colonial era?", "images": [], "marking_scheme": "- Law and order: They were involved in maintenance of law and order in their domain.  - Law making: They made laws, rules and regulations.  - Appointments: They appointed subordinate chiefs to help in the administration.  - Symbol of unity: They served as political symbol of unity and power.  - Protection of his domain: This is done to safeguard the domain against external aggression.  - Administration of Justice: Some of these traditional rulers acted as the final court of appeal.  - Planning and development: traditional rulers planned for the progress and development of various communities.  - Native laws and customs: The traditional rulers preserved the native laws and customs.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2005>7>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Describe Colonialism.", "images": [], "marking_scheme": "Colonialism: it is defined as an imposition of a more developed culture over a less developed one, backed up by expansionist and economic adventurism. European capitalist countries established political, economic, military and cultural hegemony over other parts of the world.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2005>7>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Highlight five powers of the British Governor in any one West African colony.", "images": [], "marking_scheme": "- He exercised the power of prerogative of mercy.  - He presided over both the legislative and executive council.  - He exercised executive functions.  - He performed legislative functions e.g Proclamation  - He gave assent to bills before they became laws.  - He exercised vote and reserved powers over all issues.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2005>8>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Outline three activities of the National Congress of British West Africa (NCBWA).", "images": [], "marking_scheme": "- The congress under the leadership of J. E. Caseley Hayford, a Gold Coast Lawyer, Mobilized educated elities in the four British colonies.  - The congress introduced radical approach to the nationalist activities in British West Africa e.g holding International meetings, Petitions to the colonial government and demand for elective principle.  - The congress tried to unite the four British West African colonies.  - The congress enlightened the people of West Africa through its meetings and publications.  - The congress identified shortcomings, objection able practices and policies of colonial administration in British West African colonies.  - At a meeting held in Accra in 1920, the congress sent a delegation to london to present certain demands.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>8>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "State three effects of the activities highlighted in 8(a) above.", "images": [], "marking_scheme": "- it brings about the elective principles on West Africa e.g 1922 Clifford constitution in Nigeria introduced elective principle.  - In 1923 and 1924 West African members were elected into legislative houses, most especially in Nigeria.  - The introduction of political parties in 1923 e.g Nigerian National Democratic Party (NNDP).", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>9", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "In what ways did the Nigeria National Democratic Party (NNDP) contribute to the political development of Nigeria?", "images": [], "marking_scheme": "- It was responsible for the upgrading of lagos town council.  - Contributed to competitive political activities   - It was first political party contested elections in 1923, under the leadership of Herbert Macaulay.  - It motivated the establishment of other political parties e.g Lagos Youth Movement (LYM), NCNC etc  - It wa responsible for returning the three elected candidates allocated to Lagos during the election into the legislative council 1923, 1928 and 1933.  - It socialised and educated the electorate on political, economic and other vital issues affecting the country.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2005>10>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What is a coup d'etat?", "images": [], "marking_scheme": "Coup d'etat is a forceful takeover of government in a country by the armed forces.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2005>10>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Give five reasons for military intervention in politics in West Africa.", "images": [], "marking_scheme": "- Lack of a legitimate base.  - Low level of economic development.  - Regional differences.  - Allegations of different proportion.  - Tribal loyalties.  - Corruption.  - Nationalism.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>11>a", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "With two examples, explain the meaning of federal character in Nigeria.", "images": [], "marking_scheme": "Federal character refers to distribution of amenities and resources/appointment based on quota system to be applied in the three tiers of government in the country.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2005>11>b", "subject": "Government", "year": "2005", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "State three factors responsible for the introduction of the concept of federal character in Nigeria.", "images": [], "marking_scheme": "- Appointment to promote unity, ensure stability and sense of belong.  - There is discrimination on the basis of education, religion, ethnic affinity etc.  - Uneven development: there disparity in educational, political and economic development in Nigeria.  - To harmonize the monetary policies of member states through integrating the economic and industrial policies.  - To remove obstacles to free movement of people, services and capital among member states.  - To harmonize the economic and industrial policies of member states and eliminate disparity in the level of development of member states.  - To eliminate artificial barriers in respect of the importation and exportation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>1>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Define government as an academic field of study", "images": [], "marking_scheme": "Govenment as an academic feld of study inolves the study of political institution in a state, ideal,values and doctrines about politics, the view of political thinkers on what constitutes the welfare off the people. The study of government embraces international relations, public administration, local government administration, comparative politics etc.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2006>1>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE~~ORGANS OF GOVERNMENT : JUDICIARY~~ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Describe any three branches of government.", "images": [], "marking_scheme": "- Political economy: It deals with fiscal and monetary policies of a country.\t  - Comparative politics: It deals with comparative analysis of government of other countries.  - Political thought/theories: It has to do with early political thinkers like Jean Lucke, Hobbes, Machiavelli", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>2>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Identify three types of delegated legislature", "images": [], "marking_scheme": "Types of Delegated legislation  - Bye-laws  - Orders in council  - Provisional orders  - Warrants", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2006>2>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Give three reasons for the control of delegated legislature in West Africa", "images": [], "marking_scheme": "- To protect the freedom of people  - To discourage the abuse of power  - To prevent excesses of people in power  - To foster good governance", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2006>3>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Outline any three features of written constitution", "images": [], "marking_scheme": "- The constitution is rigid and difficult to amend  - It is easily available on one single document and can easily be obtained and read  - It ensures political stability since method of acquiring power is clearly defined", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>3>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Highlight any three reasons for the adoption of Unitary constitution", "images": [], "marking_scheme": "- Quick decision-making\t  - It is cheap\t  - It is flexible", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>4>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Describe any three functions of a political party", "images": [], "marking_scheme": "- Unity: political parties unite the people on  major issues affecting the state  - Accountability: They enable the government to become accountable to the electorate through criticism of the government in power  - Machinery for recruitment: political parties provide a machinery for recruiting political leaders", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>4>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "State any three problems of political party", "images": [], "marking_scheme": "- Corruption and favoritism\t  - Anti-party activities\t  - Inadequate funding", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>5>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Give three reasons for holding elections in a state", "images": [], "marking_scheme": "- Elections allows the people to have the free choice of electing leaders into political office  - Elections provides a means of checking the excesses of peoples representatives in government\t  - It serves as a useful check to test the popularity of leadership succession through voting", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>5>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Identify three factors that can disqualify a person from voting in a democracy", "images": [], "marking_scheme": "- Age of the person: the age for voting is put at 18 years. Anyone below this age is disenfranchised.  - Presence of criminal record: Anyone who has ever being convicted of any criminals offence is disallowed from voting.  - Sanity of the person: Before anyone is allowed to vote, the person must have been confirmed to be of sound mind. However, anyone suffering from mental issues are not eligible to vote.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>6", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "Highlight three methods used by the pre-colonial chiefs in your country to control their chiefs", "images": [], "marking_scheme": "- Law, rules and regulations.  - Settlement of disputes.  - Creation of law enforcement  - The use of Ancestral spirits.  - Minor chief Appointments.  - Use of taboos.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2006>7>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Outline four reasons for the adoption of Indirect Rule System", "images": [], "marking_scheme": "- There was shortage of funds.  - They was lack of qualified personnel.  - Knowledge of local culture and tradition.  - Knowledge of geographical terrain.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>7>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Enumerate two achievements of the Indirect Rule System", "images": [], "marking_scheme": "- It was very economical: The use of traditional rulers in the administration made it less costly  - Respect for other people's tradition and culture.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>8>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Highlight two methods used by the nationalist leaders in  their opposition to British Rule in West Africa", "images": [], "marking_scheme": "- Formation of political partices and associations: NNDP, NCNC,NPC,AG etc were some of the political parties formed.  - The print media (Newspaper): They used the news papers to agitate for social, political and other reforms", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>8>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Outline four external factors that led to increased nationalist demands after the second World War in West Africa", "images": [], "marking_scheme": "- Deeper awareness of the ills of colonization.  - Nationalization and Independence struggles in other parts of the world  - Educational awareness of nationalist.  - Increase media influence.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2006>9>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "State two objectives of the National Council Of Nigeria and the Cameroons (NCNC)", "images": [], "marking_scheme": "- The extension of democratic principles and advancement of the interest of the people of Nigeria and Cameroons under British mandate.  - The impartings of political education to the people of Nigeria in order to prepare them for self-government.  - The provision of medium of expression for members of NCNC through which they would endeavor to secure for Nigeria and the Cameroons, political freedom, social equality, religious toleration and economic activity.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>9>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Describe four achievments of the NCNC", "images": [], "marking_scheme": "- Nationalist opposition- The party was the brain behind nationalist opposition to the 1946 Richards constitution.  - Constitutional conferences - It tooks part in most of the constitutional conferences e.g 1953 London constitutional conference.  - Formation of a coalition government: It formed a coalition government with the Northern people's congress between 1960 and 1966.  - Government of Eastern Nigeria: The NCNC controlled the government of Eastern Nigeria in the 1st Republic (1963-1966)", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>10>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Highlight four features of the Nigerian Federalism", "images": [], "marking_scheme": "- Constitutional division of power  - Written and rigid  - Bi-cameral legislature  - Powers derived from the constitution", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>10>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "State two problems confronting the Nigerian Federalism.", "images": [], "marking_scheme": "- Problem of minorities  - Regional political parties", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>11>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is foreign policy?", "images": [], "marking_scheme": "Foreign policy can be defined as the decisions and actions taken by a state to pursue her interests within the global system. The ability of a nation to influence the decisions and actions of the nations within the comity of nations is of great importance.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2006>11>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Outline three reasons for adoption of Africa as the centrepiece of Nigeria's foreign policy", "images": [], "marking_scheme": "- Size and population: With her size and population on the continent added to its enormous wealth, Nigeria has a task to accomplish for African states  - To depend: The independence and territorial integrity of African states.  - Peace and order: To join hands with other African states to maintain peace and order in the continent.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2006>12>a", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "List four organs of the Economic Community of West African States (ECOWAS)", "images": [], "marking_scheme": "- The fund for cooperation, compensation and development.  - The Executive Secretariat.  - The Community Tribunals.  - The Council of Ministers.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2006>12>b", "subject": "Government", "year": "2006", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Outline four obstacles that hinder the implementation of the aims and objectives of the ECOWAS", "images": [], "marking_scheme": "- ECOWAS fund: Inability of member states to contribute to  ECOWAS fund.  - Fear of domination: The fear of domination by larger states over smaller once a barrier to unity.  - Global recession complicates effort of the community and its members.  - Political instability: Frequent changes of leadership in member countries.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>1>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Explain the term government as an art of governing.", "images": [], "marking_scheme": "Government is referred to as an art of governing because it is a body vested with the supreme power of the affairs of a state. A government is vested with the power of maintaining peace and security by putting in place machinery for that purpose.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2007>1>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Why is government important as an art of governing?", "images": [], "marking_scheme": "i) Government makes laws and enforces them on the people of that country  ii) Government assists the citizens of the country to be politically aware of things happenings around.  iii) It stimulates the citizens interest to participate more in politics  iv) It also helps in acknowledging and appreciating government in what they do", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>2", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "2", "group": "", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Identify six external limitations to the exercise of sovereignty of the state", "images": [], "marking_scheme": ") Dominance of powerful state can limit the sovereignty of a state.  ii) Military agreement or pact.  iii) International laws and correction.  iv) Diplomatic relations with other states.  v) International financial institutions.  vi) External aids", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2007>3>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Define Fundamental Human Rights", "images": [], "marking_scheme": "It can be defined as those in-alignable (natural) rights, and priviledge's enjoyed by the citizens of a given state, which are usually stated in the constitution of the country.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2007>3>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Highlight five means of safeguarding Fundamental Human Rights in a state.", "images": [], "marking_scheme": "i) Independence of the judiciary  ii) Democracy  iii) Power distribution   iv) Fundamental human rights  iv) Vigilance", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>4", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "4", "group": "", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "Identify six features of a parliamentary system of government.", "images": [], "marking_scheme": "a) The prime minister can only choose his ministers from his party man in the legislature  b) Presence of collective responsibility  c) The executive can be removed from office by the legislature  d) Existence of opposition party  e) Obedience to party directives  f) Fusion of power", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2007>5>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "What is Local government?", "images": [], "marking_scheme": "Local government may be defined as a government established through an act at the local level and to deal with specific matters as it affects them. Under the 1963 republican constitution, local government authorities were created mainly to deal with matters of local concern e.g markets,feeder roads,motor parks.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2007>5>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Highlight five sources of local government revenue.", "images": [], "marking_scheme": "i) Allocation from the federation account  ii) Grants  iii) Imposition of levy  iv) Collection of ventures", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2007>6", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "6", "group": "", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Discuss six features of the traditional Yoruba political system.", "images": [], "marking_scheme": "i) Centralization: The yoruba pre-colonial political system had a centralized system of public administration and governance.  ii) Single head: Political authority was vested in one single head, the kings(Oba).  iii) Hereditary: Becoming a King (oba) or ascension to kingship in pre-colonial Yoruba political system was based on hereditary rights.  iv) Occultive clabash: These was the system of occultic calabash (igba-iwa) Which was used as an instrument of checking and controlling the possible excesses, despotic or dictatorial rule of the king (oba).  v) Impeachment: The Oyomesi and Ogboni exercised the power of impeachment of the oba and it was by death  vi) Tenure of Office: The king (oba) stayed in office for life.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2007>7", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Describe six factors that led to the growth of nationalism in Nigeria before 1945", "images": [], "marking_scheme": "i) The attitude of racism in employment leading to limited opportunities for Nigerians in the civil service.  ii) The influence of christianity and establishment of schools: This made the nationalists to realize that afterall, men are created equal by God.  iii) Activities of educated electees like Nnamdi Azekwe, H.O.Davies, Herbert, Macaulary etc the masses for support during the stuggle for independence  iv) Student Union: The formation of the West African students Union (WASU) in 1925.  v) Youth movement: The formation of youth movement helped in the growth and spread of nationalism in Nigeria e.g Lagos Youth movement (LYM).   vi) Establishment of newspapers: Newspapers e.g  the West African pilot, Lagos Daily News played vital roles in the de-colonialization process.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2007>8", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Highlight six merits of Richards Constitution of 1946 in Nigeria.", "images": [], "marking_scheme": "i) Introduction of regionalism: The formal three province gave way to 3 regions- North, West and East.  ii) Unofficial majority: Richard constitution gave the unofficial members  a majority in the legislative council.  iii) Nigerians were now represented in the legislative council even though in an unofficial capacity.  iv) Bi-cameral legislature: The North had Houses of Assembly and Chiefs thereby introducing bi-cameralism into the system, even though, East and West had only unicameral legislature.  v) Franchise qualification: It was reduced from one hundred pounds to fifty pounds annual income and 24 month to 12 month residence.  vi) Federalism: The full blown federal structure of 1954 was laid down by this constitution.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2007>9>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "State the aim and objective of the Unity Party in Nigeria (UPN)", "images": [], "marking_scheme": "i) Promote and sustain the unity of Nigeria.  ii) Achieving equal opportunities for all Nigerians.  iii) Provision of job opportunities and development of manpower.  iv) Provision of free medical care to all.  v) Provides free and equality education to all Nigerians.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>9>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Outline four achievements of the party", "images": [], "marking_scheme": "i) It helps to recruit leaders.  ii) Free education.  iii) Governorship election.  iv) Political education.  v) It formed the opposition at the centre and acted  as watch dog on the activities of the rules NPN and NPP government.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>10", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Outline four achievements that led to the  formation of Federalism in Nigeria.", "images": [], "marking_scheme": "i) Cultural diversity: It is argued that cultural diversity among ethnic group in Nigeria makes the operation of a federal system possible.  ii) Size of the country: Nigeria is a large country both in population and territory and so federalism is a better opinion.  iii) Geographical factor: Different component units are geographically near to one another, making it easier for the adoption of a federal system.  iv) Religion and culture: They also contribute to its formation.  v) For effective administration: Federalism makes for duplication of functions of creating atmosphere for an enduring and effective administration.  vi) Bringing government to the grass roots: Federalism makes the people to be involved in governance and also be involved in the policy making of their country.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2007>11>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is Foreign Policy?", "images": [], "marking_scheme": "Foreign policy refers to the decision and actions taken by a state to pursue her interests within the global system. The ability of a nation to  influence the decisions and actions of other nations within the county of nations is of great importance.", "marks": "0", "difficulty": "1"}, {"id": "theory>Government>2007>11>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Identify five  factors that can influence Nigeria's Foreign policy", "images": [], "marking_scheme": "i) The military strength of Nigeria.  ii) Public opinion.  iii) Historical background.  iv) National or domestic interest.  v) Geographical location.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>12>a", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Describe the origin of the Commonwealth.", "images": [], "marking_scheme": "i) Origin: The origin of the Commonwealth could be traced to 1907 when representatives of governments of the countries Austria, Canada, Ireland, New Zealand and South Africa met for the first time.  ii) The Association was formerly known as British Commonwealth Nations.  iii) The modern Commonwealth began in 1931 when British parliament created stature of West Minister.  iv) Commonwealth is composed of 54 countries now.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2007>12>b", "subject": "Government", "year": "2007", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Identify four benefits derived by being a member of the Commonwealth.", "images": [], "marking_scheme": "i) Scholarship: There is Commonwealth scholarship for deserving students.  ii) Granting of loans: The rich states help the poor ones through granting of loans or financial aid.  iii) Sporting Activities: Members states engage in sporting activities every four years, thereby strengthening the existing relationship among them.  iv) Official Language: English language is the official language. It makes for easy communication and understanding among members.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>1>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Define Communism", "images": [], "marking_scheme": "Communism is a political and economic system in which the community through the common ownership, collectively controls all the means of production of goods and services, exchange and distribution.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2008>1>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline four features of Communism", "images": [], "marking_scheme": "i) Common ownership.  ii) Use of force.  iii) One-party system.  IV) Dictatorship.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>2>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Describe the principle of the rule of law.", "images": [], "marking_scheme": "i) Principle of equality: It state that laws should apply equally to all citizen of a country, irrespective of their economic or social status.  ii) Principle of impartiality: This principle is of the view that the law should be impartial in dealing with the offenders.  iii) Principle of individual rights: Every human being is entitled to an exercise of fundamental rights and freedom and that when these rights are violated,citizens should have the right to seek redress from the courts.  iv) Supremacy of law: The supremacy of law over every individual is established.  v) Fair hearing: Anybody arrested for any offense is still a suspect and should be given a fair hearing.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>2>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "How can it be ensured in a state?", "images": [], "marking_scheme": "i) Publication of law should be made and not kept confidential.  ii) It is only possible to bring the offenders within 24hrs/1day of his arrest to follow the bail procedures.  iii) Inclusion of seperation of powers between the various aims of government.  iv) Punishment of offenders should only be meted out as specified in the law.  v) Logical limitations on government's actions should be enforced.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2008>3", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Highlight any six ways that the rights of youths can be protected", "images": [], "marking_scheme": "i) Checks and balances.  ii) Retrospective laws.  iii) Power separation.  iv) Period of detention.  v) Independent judiciary.  vi) Quick dispensation of justice.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2008>4>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Define Public Opinion", "images": [], "marking_scheme": "Public opinion is defined as the belief,values and attitude, which are commonly held and expressed by the majority of the people on a given public issue.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2008>4>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Explain three factors that can promote public opinion in  a state.", "images": [], "marking_scheme": "i) Press freedom: The use of mass media should be maintained.  ii) Bureau of information: This should established to receive, compile, and discriminate information.  iii) Freedom of speech and association: By encouraging and allowing the activities of pressure groups and other voluntary organisation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>5", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "5", "group": "", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "State six importance of local government in a state.", "images": [], "marking_scheme": "i) Political Education.  ii) Preserving the traditional institutions.  iii) Government at the grassroots.  iv) They mobilize both human and material resources for community development.  v) Local government facilitate quick decision-making in matters within jurisdiction.  vi) They help to create job opportunities in local areas.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2008>6", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "6", "group": "", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Outline six roles played by traditional rulers during the British Colonial rule in Nigeria.", "images": [], "marking_scheme": "i) They took part in the colonial government policy of indirect rules.  ii) They assisted in the maintenance of law and order.  iii) The traditional rulers helped to serve the culture and customs of their communities that were approved by the British.  iv) They acted as a link between the colonial masters and their people.  v) They organized communal work on behalf of the British.  vi) The traditional rulers took part in law-making as some of them were members of the legislative councils and later Houses of chiefs.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2008>7>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Describe the Crown Colony system.", "images": [], "marking_scheme": "The crown colonial system was a form of direct rules of British annexed authorities in which the British established political institutions surely as the executive council, legislative council and governor which were used in ruling people who were regarded as British subjects. The crown colony system was headed by the governor.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>7>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Give four reasons why the Crown Colony system was unpopular among the educated.", "images": [], "marking_scheme": "i) Domination: The legislative council were dominated by the British in the 1920s.  ii) Dictatorship: The governors were virtually colonial dictators as they had veto powers.  iii) Advisory bodies: Executive councils were mere advisory bodies to the governments.  iv) Unofficial members: The use of traditional rulers as unofficial members in the legislative council.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>8>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "What is Nationalist Movement?", "images": [], "marking_scheme": "Nationalist movement is an association formed by a group of people who share common interest, to resist political domination and cultural intimidation and to struggle for political independence. The nationalist movement played significant role in influencing Nigerians and propelling them towards the struggle for self rule.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2008>8>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Highlight five effects of of nationalist activities in British West Africa.", "images": [], "marking_scheme": "i) It increased African participation in politics as it led to the inclusion of Africans into the executive and legislative councils.  ii) Their agitation led to the introduction and extension of franchise in West Africa.  iii) Their struggle led to the Africanisation of the civil services.  iv) They made Africans aware of the shortcomings of colonial rule and their political rights.  v) There was the emergence of nationalist newspapers.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>9>a", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Outline three merits of the Lyttleton constitution", "images": [], "marking_scheme": "i) This constitution gave Nigeria a federal system of government  ii) Lagos was removed from the western region and made a federal capital territory.  iii) The two tiers of government central and regional were given specific functions to perform.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>9>b", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Highlight three demerits of Lyttleton constitution", "images": [], "marking_scheme": "i) There was no senate as the second chamber at the central legislature.  ii) The mode of selecting the Ministers was undemocratic as they were appointed instead of elected.  iii) It failed to provide for the second chamber at the Federal and Eastern region.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2008>10", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Give six reasons for the reluctance of military regimes to hand over power to civilian administrations.", "images": [], "marking_scheme": "i) The desire of the military rule to ensure that they totally eliminate the political party or group they unlawfully overthrew from power.  ii) Recognition given to military government by other countries of the world.  iii) The military being in possession of instrument of coercion and force.  iv) The inordinate ambition to remain in power for life by some military heads of state.  v) The support from civilians who benefit from military administration.  vi) Disunity among civilian and politicians who could not offer effective opposition and create hatred and disaffection to military rule.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2008>11", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Highlight three merits and three demerits of Africa as the centre piece of Nigeria Foreign Policy.", "images": [], "marking_scheme": "Merits   i) Unity and solidarity: Nigeria has showed that Africa is the centre piece of her foreign policy through the promotion of African unity and solidarity, especially at the international community.   ii) Friendly relations: Nigeria has done this by establishing friendly relations with all African states   iii) Promotion of peace: Serious efforts have been made by different governments to promote peace in Africa                                                     Demerits   i) Financial burden: It imposes heavy financial burden on Nigeria.   ii) Brain drain: It leads to brain drain from Nigeria to other African states.   iii) Influence of citizens of other countries to Nigeria for greener pasture.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2008>12", "subject": "Government", "year": "2008", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Outline four political factors that contribute to the weakness of the Organization of African Unity.", "images": [], "marking_scheme": "i) Decision of the organisation may not be binding on the members.  ii) Political instability due to frequent changes of government etc.  iii) Differences in ideology.  iv) Shortage of fund.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2009>1>a>i", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is legitimacy in government?", "images": [], "marking_scheme": "Legitimacy is a political concept which refers to the acceptance and recognition by the citizens of a country, the rights of their rulers to govern. A government is considered legitimate, if it comes to power through constitutional means. Elected government are legitimate.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2009>1>a>ii", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline any five ways of acquiring legitimacy", "images": [], "marking_scheme": "i) Popular government policies  ii) Good government.  ii) Periodic elections.  iv) Good/ reliable leadership.  v) Wider scope of political participation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2009>2", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Outline six disadvantages of an unwritten constitution", "images": [], "marking_scheme": "i) Violation of the rights of the citizens.  ii) It creates ambiguity which can lead to general misinterpretations.  iii) It is not suitable for multi-ethnic/multi-racial societies.  iv) It cannot be easily studied the way we study a written constitution.  v) It does not have checks and balances which are usually entrenched in written constitution.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2009>3", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Highlight the main function of an executive in a modern state", "images": [], "marking_scheme": "i) Policy formulation.  ii) The executive has the power to appoint and remove top officials of the state from government.  iii) It represent the state in its relations with other countries.  iv) It pardons those that have offended the state.  v) The executive initiates bills, defends them and makes recommendations on the bill.  vi) It prepares and delivers the annual income and expenditure of the state.", "marks": "20", "difficulty": "1"}, {"id": "theory>Government>2009>4>a", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Explain concurrent functions in a federation", "images": [], "marking_scheme": "Concurrent functions relates to the federal and states regional government which have powers to enact laws on matters in the list. But in case of any conflict in the laws made by the federal and state governments, the federal government laws will prevail e.g Agriculture, Sport, Health etc.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2009>4>b", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Outline five features of a confederal system of government", "images": [], "marking_scheme": "i) Consultations are made among them before takinng independent actions.  ii) Confederation is a loose union of sovereign states.  iii) The system does not make room for even development.  iv) Member states have seperate diplomatic representations.  v) The break away of member states from the union can bring an end to the system.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2009>5>a", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "What is Manifesto?", "images": [], "marking_scheme": "A manifesto may be defined as the cardinal plans or programme of a political party which the party intends to fulfil to the electorate if it is elected into  power. It is also defined as the aims and objectives of a political party.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2009>5>b", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Outline five factors that determine the electoral success of a political party", "images": [], "marking_scheme": "i) Manifesto.  ii) Realistic past performance.  iii) Spread of membership.  iv) Party Discipline.  v) Party Patronage.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2009>6", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Identify any three funtions of the Oyomesi in the precolonial Era.", "images": [], "marking_scheme": "i) They took part in the election of the Alaafin.  ii) They are part of the body initiating and making of laws in Oyo Empire.   iii) They act as check on the power of the Oba e.g removal of Alaafin from office.  iv) They make sure that polices decided for the empire were fully implemented.  v) The Oyemesi performed religious functions.  vi) They performed judicial functions in the empire.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2009>7", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Highlight four reasons for the European Colonization of West Africa", "images": [], "marking_scheme": "i) Lack of British personnel: The system had few Europeans to control effectively area under their control.  ii) Insufficient fund: There was no sufficient from the British government to engage British officials for direct administration.  iii) British officials lacked adequate knowledge of the local areas in the country.  iv) The colonials wanted to create market for their goods and to encourage West Africans to produce those raw materials.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2009>8", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Identify four weaknesses of the British Colonial administration in West Africa", "images": [], "marking_scheme": "i) The legislative councils were dominated by British officials only.  ii) The executive council was dominated by British official.   iii) Democratic electioneering and campaign was limited to few areas of colonies.  iv) The divide and rule policy created and uneven development.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2009>9", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Highlight four objective of the National Youth Movement", "images": [], "marking_scheme": "i) To work towards the unity of Nigeria.  ii) To work toward the attainment of self rule.  iii) Political education.  iv) To have a national outlook.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2009>10", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "Give any six function of the president under the 1963 constitution of Nigeria", "images": [], "marking_scheme": "i) As the head of state, he performed ceremonial function.  ii) He approves all the prime ministers appointments or nominees into political position.  iii) He address the parliament at the beginning and end of the legislative year.  iv) He summoned, propagated and dissolved parliament on the advise of the prime minister.  v) He had the power to declare a state of emergency or war in the time of emergency.  vi) On the advice of the parliament, he could remove judges, directors of audit from office.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2009>11", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Explain six causes of the first military intervention in Nigerian politics", "images": [], "marking_scheme": "i) Tribal loyalty: This is a problem facing Nigeria as a nation. Tribal loyalty takes precedence over loyalty to the central government.  ii) Regional differences: Difference among the regions were so acute as to precipitate crises leading to direct assumption of power.  iii) Low level of economic development some individuals were so rich and have succeeded in developing their towns and villages at the expenses of the development of the country.  iv) Politicization of the army: The army or military of the first republic maintained her status quo and thereafter became politicized.  v) Regional/state based political parties : Political parties of the first Republic were all regional political parties.  vi) Dispute over the census result: Another causes of military involvement in politic in Nigeria was because of the 1962/1963 census results.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2009>12", "subject": "Government", "year": "2009", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "State six weaknesses of the United Nations Organization(UN).", "images": [], "marking_scheme": "i) Shortage of funds: The involvement of this organisation in large scale operation affects its financial resources.   ii) Resolution of conflicts: Inability of the UN to resolve conflicts among some member-nations e.g Israel and Palestine  iii) Poverty: The inability of the United Nation to effectively address the issue of poverty among member states.  iv) Differences in idealogy: There are differences in idealogy,culture,politics and methods used in pursuing economic goals.  v) The veto power: each of the 5 permanent members of the security council has a veto power. This could be used at times to satisfy their selfish interest.  vi) Problem of arms race: The UN has failed to find a permanent solution to this many nations are spending so much in manufacturing weapons of war e.g USA, Russia, France etc.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2010>1>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Define Feudalism", "images": [], "marking_scheme": "Feudalism can be defined as the identification of landed property with sovereignty over a parcel of land which became a private hereditary possession and assist to the family.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2010>1>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "State any five demerits of feudalism", "images": [], "marking_scheme": "i) Inability to form strong national government.  ii) The system was purely based on outright exploitation.  iii) It encourage injustices.  iv) Feudalism created confusion between private and public rights.  v) Disobedience to common law.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>2", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "In what six ways can a government of a state violate the principle of the  rule of law .", "images": [], "marking_scheme": "i) Ineffective control: Delegated legislation may lack effectively control from the executive.  ii) Interference: The government  can interfere with the independence of the judiciary.  iii) Inability to check: The legislature may lack the ability to check the excesses of the executive.  iv) Failure of government: The failure of government to adequate publicity to laws in the state.  v) Social and political discrimination: By government e.g religion,ethnicity and gender.  vi) Under delay: There could be undue delay of trials of suspects by government as a result of political reasons.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2010>3>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "What is an absolute majority system?", "images": [], "marking_scheme": "This is a system in which complex electoral  guidelines must be fulfilled before any candidate is declared the winner. According to the 1979 constitution in Nigeria for anyone to be appointed president,he or she must at least 25% of the votes cast in two-third of the state of the federation.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2010>3>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "Identify any five disadvantages of the system", "images": [], "marking_scheme": "i) It gives rooms for money politics.  ii) Allow bribery and corruption especially for those who want a re-run.  iii) Complexity of the system especially in a developing country like Nigeria.  iv) It encourages rigging of election.  v) Result in coalition of political parties.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>4>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Define opinion poll.", "images": [], "marking_scheme": "Opinion poll may be defined as the beliefs,values and attitudes, which are commonly held and expressed by the majority of the people on a given issue.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2010>4>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "State five factors that make the conduct of opinion poll unreliable in West Africa", "images": [], "marking_scheme": "i) Official conducting  the polls lack the necessary expert knowledge.  ii) Absence of reliable technology.  iii) Problems of analyzing statistical data.  iv) Poor communication network.  v) The selection of sampling may be misleading, if it cannot produce the desired results.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>5>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Define public corporation", "images": [], "marking_scheme": "A public corporation is defined as a government establishment or enterprise set up by an act of parliament to provide essential services like electricity, postal services, pipe borne water etc.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2010>5>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Give five reasons for setting up a public corporation in your country", "images": [], "marking_scheme": "i) Provision of essential services.  ii) High capital involvement.  iii) Provision of employment.  iv) Raising people's standard of living.  v) Revenue generation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>6", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Identify any six roles of the traditional rulers in the pre-colonial West Africa.", "images": [], "marking_scheme": "i) Law and order: They were involved in the maintenance of law and order in their domain.  ii) They made laws, rulers and regulations.  iii) They appointed subordinate chiefs to help in the administration.  iv) The traditional rulers were involved in raising and spending of money.  v) They served as political  symbols of unity and power.  vi) They awarded traditional titles to deserving citizens.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2010>7>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Describe the composition of the Executive Council of the 1922 Clifford Constitution", "images": [], "marking_scheme": "The Executive Council of the 1922 Clifford Constitution was the main organ of government. They formulated and implemented government polices. All the members were white men without any Nigerian as a member.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2010>7>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Identify any five ways in which the Clifford Constitution was significant to Nigeria", "images": [], "marking_scheme": "i) Establishment of News papers: The West African pilot, Lagos Daily News for example were established to increases political activities.  ii) The Executive council: It was an all European council. No Nigerians was a member, meaning that Nigerians were not part of the decision making body.  iii) Elective principle: Clifford's constitution established for the first time, elective principle i.e elections were to be conducted into the legislative council.  iv) Proclamation: The North was to be governed by proclamation, emanating from the governance.  v) Head of state: This was Governor Hugh Clifford, representing the Queen of England.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>8", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Highlight six political changes introduced into the Nigerian political system by the 1954 Constitution", "images": [], "marking_scheme": "i) Regionlisation of the civil service and the judiciary:The regions now had its civil service and judiciary.  ii) Federal capital territory: Lagos was removed from the western region and made a federal capital territory.  iii) Supreme court: The constitution established a federal supreme court for the country.  iv) The governor-general and the regional governors still retained the power to accept or reject bills.  v) No provision was made for the post of a prime minister as head of government in Nigeria.  vi) Ministers at both the regional and central levels of governments could now control the departments with their ministries.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2010>9>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Distinguish between a Secretary of State of the Colonies and a Governor-General in the British Colonial administration", "images": [], "marking_scheme": "Secretary of states for the colonies was the high personnel in the colonies. He is a representative of the queen in the colonies and appoints the Governor-General for the colonies. He is a member of the House of Lords in Britain. He does not reside in any of the colonies. He only attends important meetings to introduce any new policy. He is the head of all the colonies.    The Governor-General on the other hand was the head of colonial administration and acted as link between the British government and the colony. He was the head of both Executive and Legislative councils and had powers to appoint and remove the members of these councils from office.He had reserved powers to make and enforce.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2010>9>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Highlight five functions of the Governor-General in the British West Africa shortly after independence.", "images": [], "marking_scheme": "i) He had power to remove recalcitrant and disloyal chiefs.  ii) He had the role of formulation and execution of polices of Executives and legislative council.  iii) He made all crucial appointments in the colony.  iv) He was vested with legislative,executive and judiciary powers to enable him carry out his duties.  v) He had a veto power on the decisions of the legislative council.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2010>10", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Describe six achievements  of the National Party of Nigeria (NPN) between 1979 and 1983.", "images": [], "marking_scheme": "i) It won the 1979 and 1983 second republic presidential election.  ii) The party was more of a national party.The membership spread to almost all parts of the country.  iii) It produced the first Executive President for the country.  iv) It won the governorship election in seven states of the federation.  v) It helped in educating the members and the public on their political rights.  vi) The party helped to recruit leaders to  political offices in government and with parties.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2010>11>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is foreign policy of a country?", "images": [], "marking_scheme": "Foreign policy refers to the decisions and actions taken by a state to pursue her interests within the global system.The ability of a nation to influence the decisions and actions of other nations within the comity of nations is of great importance.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2010>11>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "State the main objectives of Nigeria Foreign policy.", "images": [], "marking_scheme": "i) To promote and protect our national interest.  ii) To respect international laws and treaty obligations.  iii) To assist other neighbouring countries to solve their internal or domestic problems.  iv) Eradication of colonialism.  v) Joining other states in Africa based on the principle of non-interference in the internal affairs of other states.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>12>a", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Describe the composition the General Assembly of the United Nations Organization (UN)", "images": [], "marking_scheme": "The General Assembly is made up of all member states. 5 representatives are drawn from each member state into the assembly.They meet once in a year but there could be a special session,if the security council or a majority of member states request for it. Consensus on issues or matters are achieved by simple majority. A president is elected from one of the member states to head the Assembly for a term of one year  and it is rotated among member states.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2010>12>b", "subject": "Government", "year": "2010", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Highlight four functions of the General Assembly.", "images": [], "marking_scheme": "i) It elects non-permanent members into the security council and judge of international court of justice.  ii) It can amend the UN charter.  iii) It has the power to vote on issues of international concern.  iv) The General Assembly reviews issues that relate to the functions.  v) It discusses and approves the annual budget of the UN", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2011>1", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "State six functions of Government?", "images": [], "marking_scheme": "i) Law-making: Government is responsible for making law in a country.  ii) Amenities like electricity,potable water,health centers etc are provided by the government.  iii) Government is responsible for defending the country against external aggression.  iv) Government is also responsible for protection of lives and property.  v) Job is also provided for the citizens.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>2>a", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain the concept of political participation", "images": [], "marking_scheme": "Political participation is defined as the process whereby individual gets themselves involved in the political activities and in the decision-making of their country.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2011>2>b", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "b", "group": "", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Highlight any four methods of political participation.", "images": [], "marking_scheme": "i) Voting in election: This is one of the ways of political participation and it gives the individual the opportunity  to vote for the candidates of his choice.  ii) Observing political participation:  The individual is only an observer and takes delight in listening to political talks,discussions etc.  iii) Supporting candidates for elective posts: This could take the form of moral or financial support.  iv) Belonging to a political party: This involves the individual's active and direct involvement in the political terrain of his country.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2011>3", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "What are the limitations to the application of Rule of Law?", "images": [], "marking_scheme": "i) Diplomatic community: Diplomats cannot be persecution in the country where they are residing and are accredited representatives of their country.  ii) Immunity of Heads of States: He may not be sued or appear in court.This privilege is not extended to the citizens.  iii) Types of Government: A one party system can grow into dictatorship thereby limiting the application of the rule of law.  iv) Illiteracy,poverty and ignorance: This can limit the application of the rule.  v) Immunity of the parliament: The law makers are immune from every utterance,actions or statements made in parliament.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2011>4", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Highlight the merits and demerits of two-party system", "images": [], "marking_scheme": "Merits:  i) Two-party system makes for choice between political parties.  ii) In this system, one party forms the government the other opposition.  iii) Stability is ensured and the reason is that there is no room for a coalition government which may create a weak and unstable government.  iv) There is opportunity for freedom of choice and opposition.  v)  People can easily identify the strength and weaknesses of the party in government.     Demerits:  i) There is the possibility of two-party system dividing the country to two opposing factions.  ii) The struggle of power within the system may promote national unity.  iii) If one of the two party holds office for a long time, the other may dissolve into the ruling party.  iv) Intimidation,victimization of political opponents  and threats etc could result from two-party system.  v) Most of the resources are wasted in conducting elections and in the maintenance of two political parties.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2011>5", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "Identify any four major functions of Civil/Public Service Commission.", "images": [], "marking_scheme": "i) They formulate policies and these are part of the objectives of the government.  ii) The civil service ensures that the policies made are executed.  iii) It prepares the government's yearly statement of expected income and expenditure.  iv) The civil service ensures continuity of government and this makes for stability.  v) The civil keeps official documents that are relevant to the government of the day.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>6", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "In what six ways did colonial rule contribute to the decline of powers of the traditional rulers in West Africa?", "images": [], "marking_scheme": "i) Colonial rule led to the collapse of the existing link between the traditional rulers and their subject making the former appendages of alien government.  ii) The introduction of salaried job to the working subjects empowered the subjects to be independent of their rulers.  iii Influence of foreign religion scaled down the power of traditional rulers as the spiritual authority of their people.  iv) The establishment of law courts by the colonialists reduced the law-making functions of traditional rulers.  v) Colonialism introduced native/local authorities  which took over the traditional rulers absolute control over taxation and its disbursement.  vi) Shortage of inter-tribal wars put an end to the means by which traditional rulers accumulated wealth.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2011>7", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Why did the French abandon the Policy of Assimilation", "images": [], "marking_scheme": "i) Formation political parties and association was not allowed.  ii) Right to full education was only given to those living in any of the four communes.  iii) France did not regard the culture of the people.  iv) The policy placed financial burden on French citizens who therefore resisted it.  v) The policy of assimilation expected Africans to adopt French culture wholesale.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>8>a", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "Highlight four features of the 1979 Republican constitution", "images": [], "marking_scheme": "i) The constitution adopted an executive presidential system i.e the president is both the Head of state and Head of government.  ii) The president had power to nominated his second in command,the vice president from the same party with the president.  iii) The constitution established a bi-cameral legislature.House of Representatives had 450 members and the senate,95 members.  iv) The constitution made provision for a democratically elected local government councils.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2011>8>b", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "State two ways by which the president could be removed from office according to the Constitution", "images": [], "marking_scheme": "Ways President could be remove removed from office.  i) He could be removed from office in case of insanity.  ii) If he is found violating the provisions of the constitution.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2011>9", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Highlight any six problems confronting local governments in Nigeria", "images": [], "marking_scheme": "i) Acute shortage of trained and experienced personnel affects the efficiency of local government.  ii) Most local government do not have enough fund with which to operate.  iii) Both the military and civilian government have different times interfered with the local activities of the local government.  iv) Some officials demand and even take bribe before performing their official functions.  v) Some of the officials involved in revenue collection embezzle part of this fund for their own selfish ends.  vi) The incentive to work is low, leading to poor attitude to work of local government staff.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>10", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Outline any four ways of preventing military intervention in politics.", "images": [], "marking_scheme": "i) Military intervention should be outlaid by the constitution of the individual country.  ii) There should be accountability on the par of the politicians who are in government planning to be in government.  iii) Ethnic politics should be avoided by the politicians.  iv) The game of politics should be played according to the laid down rules and regulation.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>11", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Highlight any four major objectives of the foreign policy of any one West African Country", "images": [], "marking_scheme": "i) To promote and protect our national interest.  ii) To maintain friendship and co-operation.  iii) Respect for territorial integrity.  iv) Eradication of colonialism.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2011>12", "subject": "Government", "year": "2011", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Outline six benefits member state of the commonwealth derive from the organization", "images": [], "marking_scheme": "i) There is commonwealth scholarship for deserving students.  ii) Member states help discuss common problems, ensuring closer and friendly ties among them.  iii) The richer states help the poor ones through granting of loans or financial aid.  iv) The legal system is similar and fashioned along the British pattern.  v) English language is the official language which makes for easy communication and understanding among members.  vi) Training of defence personnel in other military academy e.g Britain and India.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>1", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight six characteristics of a democratic government", "images": [], "marking_scheme": "a) Disparity in the distribution of national wealth is progressively reduced.  b) Free association and periodic elections.  c) There should be application of the rule of law and no one should be above the law..  d) The rights of the individuals should be promoted and guaranteed.  e) The constitution should be supreme and above every other consideration in any political system.  f) There is universal adult suffrage where adult citizens have the right to vote in the elections.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>2>a", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "What is independence of the judiciary?", "images": [], "marking_scheme": "Independence of Judiciary is one which is free from the interference of the other two arms of government, the executive and legislature. Judges should be free when interpreting the law of the land. They should work without fear or favour.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2012>2>b", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "State three reasons for independence of the judiciary", "images": [], "marking_scheme": "i) Appointment: A neutral body and not the Executive should appoint the officials judiciary.  ii) Dismissal: As long as the executives does not appoint judges, they should also not be involved in their dismissal.  iii) Remuneration: The salary and remuneration of judges should be sufficient and this should be from the consolidated fund.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2012>3", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Give three functions and three limitations of the legislature", "images": [], "marking_scheme": "Functions of the legislature:  i) Law-making: The primary function of the legislature is law-making and it is done through legislative process.  ii) Financial control: It controls the raising and spending of money and approves it as proposed by the executive.  iii) Serve as a link: It serves as a link between the people and government.    Limitations of the legislature:  i) Too expensive to run: Since the two houses are paid,it makes it expensive to run.  ii) Waste of resources: Duplication of functions could result in waste of resources, both human and financial.  iii) Delaying the passage of bills: law making  and other activities of the legislative could be disturbed because of the delay in the passage of bills.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>4", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Identify six functions of pressure groups in a democratic state.", "images": [], "marking_scheme": "Merits of pressure groups:  i) They offer useful suggestions and advise governments at local state and national levels.  ii) They promote economic stability through the chamber of commerce.  iii) Act as a link between the government and the people.  iv) They provide useful information in the process of law making.  v) Pressure groups serve as yardstick for measuring the popularity of government.  vi) They promote certain general welfare services e.g .The Nigerian Bar Association.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>5>a", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "What is civil service?", "images": [], "marking_scheme": "The civil service is a body or department in the executive arm of government. It has a duty has a duty of assisting the executive in the planning and implementation of government polices. The civil service is divided into departments called ministries e.g ministry of education,ministry of finance etc", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2012>5>b", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Explain the structure of the civil service", "images": [], "marking_scheme": "Structure of the civil service:  i) The administrative class: This is the highest class and they are mostly Director Generals, Deputy Director Generals, Principal officers etc.  ii) The professional class: They are mainly recruited as professionals of different category e.g lawyers, doctors etc  iii) The executive class: They are senior executives,executive officers, assistant executive officers etc.  iv) The clerical class: They are school certificate holders and are mostly clerical officers, clerical assistants,typists etc.  v) The messenger class: They are  mostly cleaners,messengers,drivers etc.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2012>6", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Highlight six features of the Igbo traditional societies", "images": [], "marking_scheme": "i) The village priest/diviner wielded great deal of religious and judicial power.  ii) Succession of leadership and to prominence was based on personal achievement.  iii) Deities are of political significance in providing unity  iv) Market square served as the village chambers.  v) The women(Umuada) composed of the first daughter of each family,constituted a socio-political group.  vi) New Yam festival was religiously marked,honoured and celebrated annually.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>7", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Identify any four features of the policy of Indirect Rule in West Africa", "images": [], "marking_scheme": "i) The colonialist rule indirectly  by engaging the traditional rulers and the chiefs to govern the people.  ii) The traditional political system of government in place was utilised.  iii) The customs and traditions of the people played a significant role in the administration.  iv) The cultural values of the people were respected  by the British officials", "marks": "1", "difficulty": "2"}, {"id": "theory>Government>2012>8>a", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Define nationalism?", "images": [], "marking_scheme": "Nationalism nay be defined as a certain form of unity which grows out of historical experience. It is the serve of oneness that emerges from social groups, trying to control their destiny, environment and to defend their interest against competing groups.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2012>8>b", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "State any five external factors that aided the growth of nationalism in West Africa", "images": [], "marking_scheme": "Factors that lead to growth of Nationalism in Nigeria:External  i) Activities of pan-african leaders/organizations.  ii) Britain humiliating defeat by Japan.  iii) The independence of some countries.  iv) The impact of the second world war.  v) Colonial posture of United Nations Organization.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2012>9", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Identify six features of the Macpherson Constitution of 1951", "images": [], "marking_scheme": "i) The three chiefs commissioners for each province were renamed Lieutenant-governor.  ii) The colony of Lagos was part Western region.  iii) A House of Representatives was created and also known as the central legislature.  iv) The governor was the president of the council of ministers others were 6 official members charged with issues relating to civil service,defence,legal matters etc.  v) The Nothern and Western Regions each had a Bicameral legislature- Houses of Assembly and chiefs.  vi) The Three provices were renamed, Western Eastern and Northern Regions.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>10>a", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Describe the formation of the Nigeria National Aliance (NNA) of 1964 .", "images": [], "marking_scheme": "Formation of the Nigerian National Alliance in 1964, before the general election all parties formed an antagonist alliance which NNA was one of them. This alliance was made up of Akintola's NNDR, NPC, etc. The leader was Ahmadu Bello, premier of Northern Region During the campaign and nomination procedures, a lot of irregularities were recorded e.g 68 candidates were declared unopposed out of 167 seats allocated to the North, Federal announced after the elecion that NNA had won 162 out of 167 seats,in the North 36 seats out of 57 seats allocated to the West. But Nnamdi Azikwe refused to used his constitutional powers to appoint the leader of the winning party to form the government. After much consultation,it was agreed that a government of National Unity be formed.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2012>10>b", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Highlight three achievements of the Alliance", "images": [], "marking_scheme": "i) They trained some future politicians.  ii) They helped in bringing unity to Nigerians.  iii) They won the election of 1964 and for the government of National unity.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2012>11", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Identify any six factors affecting Nigeria's foreign policy", "images": [], "marking_scheme": "i) Ideological disposition of the rulers.  ii) The military strength of Nigeria.  iii) Geographical location.  iv) The economic resources.  v) Previous commitments of the government.  vi) The industrial/technological strength.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2012>12", "subject": "Government", "year": "2012", "type": "Theory", "sub_label": "12", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Identify any six problems facing the Economy Community of West Africa States (ECOWAS)", "images": [], "marking_scheme": "i) The political economy of member states is tied to that of their respective former colonial masters.  ii) The free movement as provided by the charter of Ecowas is no more automatic because of its socio-economics implications for member states.  iii) Ideological differences hampers the cohesiveness of the community.  iv) Global recession complicates efforts of the community and its members.  v) The similarity of products of member states made trade among ECOWAS states difficult.  vi) Inability of member states to contribute to ECOWAS fund is another major problem.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2013>1>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Describe the term government as an art of governing", "images": [], "marking_scheme": "Government is seen as an act of governing because it is a body vested with the supreme power of the affairs of a state. A government is vested with the power of maintaining peace and security by putting in place machinery for that purpose.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2013>1>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Highlight any four duties of government", "images": [], "marking_scheme": "Duties of Government:  i) Law making: Government is responsible for making laws in a country.  ii) Provision of social amenities like electricity,potable water, health center etc.  iii) Maintenance of law and order in the states as performed by the police.  iv) Government is responsible for defending the country against external aggression.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>2>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain deconcentration of power", "images": [], "marking_scheme": "Decentralization of power has to do with sharing of power between the central government and other constituent units,within a political system.Power are therefore, distributed to these different units, thereby creating many centres of power", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2013>2>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain any five importance of decentralization", "images": [], "marking_scheme": "Importance of decentralization of power:  i) Brings about quick development.  ii) It brings government nearer to the people .  iii) It increases efficiency of government.  iv) Enhances greater participation of the people in government.  v) Competition among units in terms of development.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2013>3>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "What is constitution?", "images": [], "marking_scheme": "constitution is defined as a body of agreed rulers and principles stating how the powers of governing a country are given and how there powers are to be exercised. It also establishes a basic frame-work or fundamental law of the la", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2013>3>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "Why do some countries use written constitution?", "images": [], "marking_scheme": "Merits of written constitution:  i) It allows for proper documentation and entrenchment of fundamental human rights.  ii) It protect the minority interests against the domination by the majority.  iii) The procedure for amendment is clearly stated so that no one group can change the constitution to suit their selfish interest.  iv) It helps in measuring and assessing the performance of government as the principles governing their operations are written down.  v)  Since is a single document,it can easily be obtained and studied making it possible for the people to known their rights, duties and obligation", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>4>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Explain the concurrent functions in a federation", "images": [], "marking_scheme": "The federal and states regional governments have powers to make laws on matters in this list, i.e concurrent functions, but incase of any conflicts in the laws made by the federal and State governments, the laws made by the federal government will prevail. E.g Education, health, Agriculture, Information, Sport, etc.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>4>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Outline five features of a confederal system of government", "images": [], "marking_scheme": "- It is a union of sovereign or autonomous states.  - major functions or powers of the government are reserved exclusively for the component state  - It has a weak central government   -. the component state retain their sovereignty and identity   -The component states have their own army and police", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>5", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Describe the organizational structure of a political party", "images": [], "marking_scheme": "The organization structure of a political party   These include the following:  (A) National Executive Council (NEC): this is made up of elected officials of the party. e.g.  1. National chairman   2. Vice chairman   3. General secretary   4. Public relation Officer   5. Treasurer     All the above offices are also to be elected in the state levels and word levels  of all the local governments    (B) National Convention: This is an adhoc committee and is the highest policy making body of a party. It meets once every year or at least other times if there is need for it to examine activities of the party, for the year. It approves policies initiated by NEC, elects member of NEC and the presidential candidates of the party and running mate. etc.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2013>6", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "Outline any six functions of the Emir in the Hausa/Fulani traditional political system", "images": [], "marking_scheme": "- The Emirs appoints his officials e.g madawaki, Waziri, Galadima, Hakimi, etc.   -  He provides social services for the people   - He organised his people for communal work   - He organised his people for defence of the emirate   - he enforced the Islamic law (sharia)  - He was the spiritual head of the Emirate", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2013>7", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Explain the importance of the Brazzaville conference of 1944 in the constitutional development of french West Africa", "images": [], "marking_scheme": "- The Brazzavile conference of 1944, bring a very strong and close bond between and her colonies  -  It brings about formation of french association and community and introduction of constitutional proposals  - It helps in granting independence to all the french territories between 1958 and 1960  - It helps to established, no master/servant relationship between the Africans and the french, as such were was no form of discrimination  - It encouraged economic and social developement of the colonies as social amenities like telephone service, electricity, etc. were provided", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2013>8", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Highlight four factors that led to the collapse of the West African Student's Union (WASU) before the end of the Second World War.", "images": [], "marking_scheme": "- lack of finance: Since the running of the secretariat involve money and most of them are students with little financial stand.  - Linguistic problems: There is language barriefs, since (WASU) comprises of both the french and English speaking students   - Distance: After schooling most of them returned to their countries. Hence coming together like when they were in school was a big problem  - Break down in communication: Unlike nowadays, to get across to each other through letter takes months.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2013>9", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "9", "group": "", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Give any six reasons for the Breakdown of the Macpherson Constitution of 1951", "images": [], "marking_scheme": "The Macpherson constitution of 1951 broke down because of the following reason:  - The existence of regional and ethnic politics which made the representatives at the centre to be more loyal to their regions at the expense of the ministers   - The veto power given to the governor to legislate on any matter in the country became the target of criticism by the educated elites. This partly led to the breakdown of the constitution  - The constitution encouraged ethnic nationalism and regional divisions which did not allow the political leader to work together for the operation of the Macpherson constitution.   - There was no provision for the office of a prime minister at the centre to coordinate the activities of the government   - Crisis in NCNC and AG sponsored motion for independence which eventually led to the Kano riot contributed to the breakdown of the 1951 constitution", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2013>10>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Explain the term Indirect Rule", "images": [], "marking_scheme": "Indirect rule is a system of government used by the British and French to control parts of their colonial empires, particularly in Africa and Asia, through pre-existing local power structures. This system was introduced in Nigeria for the following reasons:  - Lack of adequate personnel to manage a direct system of administration   - Lack of fund   - Poor climate   - Established political system", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2013>10>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Why was the policy criticized?", "images": [], "marking_scheme": "The policy of Indirect rule introduced by the British colonial authority was criticized by the educated elites for the following reasons   - The system of indirect rule made use of the uneducated chiefs and traditional rulers at the expense of the educated elites   - The introduction of warrant chiefs in Eastern Nigeria led to problems. This is because the warrant chiefs were ruthless in discharge of their duties and did not command the required respect among the people   - The position of traditional rulers was unduly strengthened and they were given too much powers more than their traditional role. This did not down well with the educated elites   - Introduction of different forms of taxation caused the Aba women riot of 1929 and made the people to oppose the entire indirect rule system  - The entire system was alien to the culture and tradition of the people especially in the Eastern part of Nigeria. The administration was highly centralised administration which contradicted what obtained in this area", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>11", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "11", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What factors have governed Nigeria's relation with her neighbouring states?", "images": [], "marking_scheme": "- The human resources/the size and quality of the population of Nigeria affect her foreign policy   - The economic resources available help to shape her foreign policy   - previous commitments of the government e.g. treaties and pacts with other countries   - Ideological disposition of the rulers   - The military strength of Nigeria   - The industrial/technological strength of Nigeria   - Location: Africa is the centrepiece of Nigeria's foreign policy because we are in Africa   - History background i.e. colonial experience", "marks": "1", "difficulty": "2"}, {"id": "theory>Government>2013>12>a", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "a", "group": "", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Identify any four past Secretaries-General of the United Nations organization (UNO)", "images": [], "marking_scheme": "NAME                     COUNTRY      YEAR 1. U. THANK                   BURMOI         19612. KURT WALDHEIM     AUSTRIAL     1972 - 1981 3. JAVIER PEREZDE CUELLER     PERU             1982 - 1991 4. BOUTUS BOUTUS GHALI    EGYPT          1992 - 19965. KOFI ANNAN              GHANA           1997 - 1996", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2013>12>b", "subject": "Government", "year": "2013", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "State any five functions of the Secretary-General of the United nations Organization (UNO)", "images": [], "marking_scheme": "- He is the chief administrative officer of the organization   - He prepares the agenda for the General Assembly   - He prepares annual report to the General Assembly on the activities of UNO for the year  - The Secretary-General appoints other members of staff under the guidance of the General Assembly   - The annual budget of the organization is prepared by the secretary-General   - The Secretary-General administer peace-keeping operations throughout the world   - He brings any matter that may threaten the maintenance of world peace and security to the attention of the security  council", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2014>1", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "State five reasons for the study of government", "images": [], "marking_scheme": "1. Government helps to stimulate the interest of the citizens to participate in politics, understand the processes and procedures of government   2. Government is very essential to civil servants who work in government ministries, parastatals etc. in order to understand the dynamics of the system   3. Government enables one to appreciate government actions and what the officials do   4. Government helps the citizens to be politically conscious, which makes them to participate more in government activities   5. It makes laws for the country   6. It maintains laws, and justices   7. It provides jobs opportunities for the citizens   8. It raises and spends public fund. etc", "marks": "20", "difficulty": "1"}, {"id": "theory>Government>2014>2>a", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Defined Capitalism", "images": [], "marking_scheme": "Capitalism is a political and economic system in which the means of production, distribution and exchange are owned and controlled by the private individuals and in which the economic activity of the government is at a minimum", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2014>2>b", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "State two advantages and two disadvantages of capitalism", "images": [], "marking_scheme": "Advantages   -. It gives room for private ownership   - It brings competition     Disadvantages  - Making of profit in a major motive   - There is class distinction", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2014>3>a", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Defined Legitimacy", "images": [], "marking_scheme": "Legitimacy means the general acceptance of a political system as being in line with the laws of the land. A legitimate government therefore, is the one that is constitutionally elected and acceptance by the people.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2014>3>b", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight any four factors that determine legitimacy.", "images": [], "marking_scheme": "Legitimacy in a state can be sustained through the following:  - Unrestricted participation of the various groups like political parties, pressure groups and other interest groups in governmental activities   - Friendly relationship with other countries which will be based on the quality of the diplomacy of the government   - The government must have the interest and welfare of the citizen at heart. This must be shown through good welfare schemes and policies.  - Massive support given by the people can enhance the concept of legitimacy in a state", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2014>4", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Outline five factors that give rise to the adoption of federalism", "images": [], "marking_scheme": "- Culture Diversity of Nigeria - Nigeria is made up of over 250 ethnic groups with major and minor tribes. It is hoped that the federal system of government will take care of the fundamental rights of the minority group   - Size of the country - The size of Nigeria is so large that the only better option is to take care of the population and the large territory is the federal system of government   - British Colonial Policy - The British colonial authority introduced federalism in Nigeria by dividing the territory into regions and this was inherited at independence in 1960  - Nigeria has enough human and natural resources that can effectively support a federal system of government   - Adoption of federal system of government was also aimed at bringing government to the people at the grass-root level. This will enhance the involvement of the people in the policy making of the country", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2014>5", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "In what five ways can elections be made free and fair in a country?", "images": [], "marking_scheme": "- Proper delimitation of the country into constituencies by the electorial commission   - Independent electoral commission   - Adequate preparation and revision of voters' register   - Opportunity for effective campaign by political parties before elections   - Adequate training of electoral officials and provision of electorial materials   - Aggrieved candidates should have access to court to challenge the result of the election   - Election results should be announced on time", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2014>6", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Identify five functions and powers of the King Makers in the Yoruba pre-colonial political system", "images": [], "marking_scheme": "The traditional rulers are able to control their subjects in the colonial days through the following ways:  i. Appointment - Subordinate chiefs were appointed to help in the administration of the community. This chiefs assisted the rulers in controlling their subject    ii. Law making - Laws were made according to the customs and traditions of the people and such laws were maintained in the society   iii. Taboos were equally used to instil fear into the people to secure their obedience   iv. Administration of Justice - The traditional rulers in most cases acted as the final court of appeal. Their influences and pronouncement in courts prevailed on the people and made them obedient to their rulers   v) Award of State honour - Traditional titles were awarded as a mark of honour to deserving citizens. This helped to secure loyalty from the subjects.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2014>7", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Highlight five reasons for the slow rate of nationalism in French speaking West Africa", "images": [], "marking_scheme": "- The policy of assimilation by French in her colonies was more accommodating and made the educated Africans find no reason to fight for independence   - Education that is a necessary ingredient of nationalism started very late in French-speaking West African countries. Hence, their eyes were not opened to recognise the evil of colonalism   - There was no freedom of press. This made it difficult for people to criticize government activities   - The existence of indigenat policy that made the people to be subjected to arbitrary arrests and imprisonment threatened the liberty of Africans   - The election of educated Africans into the French parliament as deputies reduced the urge for nationalistic activities", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2014>8>a", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Outline three features of the Macpherson Constitution", "images": [], "marking_scheme": "- Creation of a House of Representatives which comprised the governor, 136 members elected from the regional assemblies and 6 special members appointed by the governor.  - The establishment of a central executive council known as the Council of Ministers - its membership included the governor as president, 6 official members and 12 Nigerian ministers; 4 from each of the regions.  - The ministers were without portfolios and were appointed by the governor on the recommendations of the 3 regional assemblies  - Each of the regions was to establish an executive council consisting of Lt-Governor as president, 5 official members and 9 ministers each.  - Election was both by direct and indirect methods.  - Only male tax payers voted in the North, whereas both males and females voted in the East and West.  - The responsibility of House was to legislate for the whole country and its laws could override any regional legislation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2014>8>b", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "State two reasons for the breakdown of the Lyttleton Constitution", "images": [], "marking_scheme": "- It did not provide for the office of the prime minister at the federal level.there was no other substitute leader to lead the council in its deliberations,thus the council remained inactive.  -There was no second chamber which would act as a check on the tyranny,despotism and hasty decisions often associated with the unicameral legislature.  - The appointment of ministers were regionally based.this rendered the central executive ineffective because the loyalty of the ministers resided in the regions.  - The existence of regional and ethical politics which made the representative at the centre to be more loyal to their regions at the expense of the country.   - The constitution made no provision for a stable government at the centre because port folios were given to the ministers.  - The veto power given to the governor to legislate on any matter in the country became the target of criticism by the educated elites. This partly led to the breakdown of the constitution.  - The constitution encouraged ethical nationalism and regional divisions which did not allow the political leaders to work together for the operation of the Macpherson constitution.   - Crisis in NCNC and AG sponsored motion for independence which eventually led to the Kano riot contributed partly to the breakdown of the 1951 constitution.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2014>9", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline five reasons people prefer democratic governments to military regimes", "images": [], "marking_scheme": "- Democracy is the name of government of people. Eligible candidates are elected through a free and fair election process and after that they become eligible to hold the public office according to term specified in constitution or law.     - Democracy is the most acceptable principle of governance in most of the countries. No one is allowed in this system to came into power without passing through a proper channel that is general election system.     - All the citizens are equal according to law.     - There is no concept of centralization of power and authorities in democracy.     - Representative government is the other word that is used for the democratic government. It is purely the anti-shape of authoritarianism where the selected politicians of the public set the all public and private behavior in the country. It is the government system of the modern day world that at first replaced the traditional monarch and caliph system.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2014>10", "subject": "Government", "year": "2014", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Identify five challenges facing the Commonwealth of Nations", "images": [], "marking_scheme": "- Immigrants are no longer free to enter without visa  - Military personnel are not automatically trained in Britain   - Membership of Britain in the European Economic community (The common market) is divided loyalty   - Inability to enforce orders   - Financial commitment   - Weak bonds among members", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2015>1>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Explain constitutionalism", "images": [], "marking_scheme": "Constitution is the fundamental laws, principles, customs, convention rules and regulations according to which the government of a country or an organization operates. Constitutionalism on the other hand is the extent to which those in power adhere to the provision of the constitution. This means that the activities of government and its officials should be in line with the provision of the constitution.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>1>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "State four factors that can promote constitutionalism", "images": [], "marking_scheme": "- Impartial Judicial system   - There must be checks and balances  - There must be rule of law   - The constitution must be supreme   - Fundamental human right must be respected", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>2>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "What is seperation of power?", "images": [], "marking_scheme": "Seperation of Power can be defined as the seperation or division of political powers and functions among the three arms of government i.e. The executive, legislature and judiciary. i.e. Each arms of Government should work independently, without interference from other arms. For example, the executive should be solely involved in policy making and implementation or execution. Also that no arm of government should be allowed to perform more than one function to avoid tyranny victimisation and oppression of the citizens. Because power corrupts, and absolute power corrupts absolutely", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2015>2>b>i", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "How does it operates under the Presidential system of government?", "images": [], "marking_scheme": "In presidential system of government, the government does not make law, nor does he participate in the process of law making. In short there is a clear or pronounced seperation of power in presidential system of government   The parliament cannot be resolved by the president unless its tenure is complete. Although it is the president that appoints the Judges, they preside over judgement of the president and government officials. The Judges have the power to review the activities of the legislature and that is not according to the constitution, unconstitutional and of no effect.   The president can be removed through impeachment, if found guilty of a serious offence by the parliament. The president sends bills to this parliament to be passed into law, bu the president have veto power over the laws passed by the parliament, i.e he has the right to sign or give assent or withdraw its assent.   Finally, the judicial serves as check on the excesses of the executive and legislature. In all there is principles of check and balance in the presidential system of government.", "marks": "6", "difficulty": "2"}, {"id": "theory>Government>2015>2>b>ii", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "How does it operates under the Cabinet system of government?", "images": [], "marking_scheme": "There is fusion of government in cabinet system of government of power cannot be fully operate", "marks": "4", "difficulty": "2"}, {"id": "theory>Government>2015>3>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "Define parliamentarianism.", "images": [], "marking_scheme": "It is a system whereby the head of state is different from the head of government and the legislative and executive power are fused.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2015>3>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Identify four differences between parliamentary and presidential system of government", "images": [], "marking_scheme": "- The people elect the executive president through popular ballot but the leaders of the party that won majority is appointed prime minister in the cabinet system.  - The ministers are individually responsible to the presidential system while fusion of power is practiced in the cabinet system.   - The minister are individually responsible to the president and for their actions while the principle of collective responsibility is used in the cabinet system.  -The president and his ministers are not members of the legislature in the presidential system but the prime minister and his ministers are members of the parliament.   - The president can be removed through the process of impeachment by the legislature while the prime minister and his cabinet can be removed through a vote of no confidence by the parliament.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>4>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Define Public Opinion", "images": [], "marking_scheme": "Public opinion is widely shared view in a country. In practice, public opinion refers to views which are strongly held by the more politically active and conscious citizens.", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>2015>4>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Highlight three ways by which public opinion can be formed", "images": [], "marking_scheme": "- It can be formed through the media   - It can be formed by political parties   - It can be formed by pressure groups, others are rumours and gossips", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2015>4>c", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "In what three ways can public opinion be encouraged in your country?", "images": [], "marking_scheme": "- Mass media   - Parliamentary Debates  - General Elections often provide the most important means of encouraging public opinion, too.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>5>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Identify five officials used in the conduct of election on the polling day", "images": [], "marking_scheme": "- Party agents   - Security agents e.g police   - INEC official  - Collation officers   - Polling agents   - Returning officers", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>5>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "State one functions of each of the officials identified in 5(a)", "images": [], "marking_scheme": "- Party agents: They are the representative of each party to watch over the conduct of the election of the election  - Security agents: They are in-charge of security of poling units   - INEC officials: They are the custodians of the election materials  - Polling agent: They are the one to return all election results, and unseen material to the INEC office for collations", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>6", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Highlight any five functions of the Secretary of State for the colonies in the colonial period", "images": [], "marking_scheme": "- He was the highest personnel in the colonies.he oversees all the colonies  - He represents the queen of england in any assignment in her colonies  - He appoints the governor general  - He only comes for important meetings to introduce new policies in the colonies  - He also plays a part in decision making.he is a member of the house of lords.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2015>7>a", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "State any two newspapers founded by nationalist in Nigeria after the Second World War", "images": [], "marking_scheme": "-  Lagos Daily News by Herbert Macaulay   - West Africa Pilot by Nmamdi Azikiwe", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2015>7>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Highlight any four roles played by Local Newspaper in the struggle against colonial rule", "images": [], "marking_scheme": "- It is a means of communication  - Development of indigenous press   - It is a means of educating the people in west Africa   - It is against Discrimination in the civil service   - It helps the rise of Trade Unions", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2015>8", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Outline five achievements of the Action Group as a political party in Nigeria", "images": [], "marking_scheme": "- The party formed official opposition in the house of representative to check the excesses of the government party   - The party contested and won elections in the Western region   - It introduced free primary education in 1955  - It represented Western region in all the constitutional conference held before independence   -The party sponsored the 1953 motion for the independence of Nigeria in 1956", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2015>9>a>i", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Explain the military.", "images": [], "marking_scheme": "It means the armed forces e.g. soldiers, Army, Air force, Navy, etc.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2015>9>a>ii", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What is a military coup d'etat?", "images": [], "marking_scheme": "It is a sudden, violent, and illegal seizure of power from a government by the military.", "marks": "4", "difficulty": "2"}, {"id": "theory>Government>2015>9>b", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Outline three basic features of military rule", "images": [], "marking_scheme": "- Suspension of the constitution  - They rule through decrees  - They are dictatorial and use force", "marks": "13", "difficulty": "2"}, {"id": "theory>Government>2015>10", "subject": "Government", "year": "2015", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What are the factors that determine the external relations of West Africa countries?", "images": [], "marking_scheme": "- Friendship and cooperation with other nations of the world that respect her territorial integrity   - Adoption of clear and practical policies regarding Africa with a view to promoting cooperation and progress among all independent Africa States.   - Helping non-independent African State to achieve total independence i.e Africa became centre-piece of Nigeria's foreign policy   - Respect for territorial integrity of other states in Africa based on the principle of non-interference in the internal affair of other states   - Total decolonisation of Africa. This is the reason for the support given by Nigeria to various liberation movement in Africa.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>1>a", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is Fascism?", "images": [], "marking_scheme": "Fascism is a political ideology which intents to ensure national strength by having allegiance to a nation, a nantional grandeur and a master race or group. A fascist government is therefore totalitarian, as it employs any means necessary to achieve that goal irrespective of the opinion of the citizens of the country.   Fascism is headed by a dictator, authoritarian and extremist in nature. It does not entertain individuality as the activities of the group are considered to be important. This strong sense of community is usually achieved through common convinction or violence. Fascism is headed by a male leader considered the national saviour.  Fascism government ignore human rights, violate the rule of law, curtail freedom of the use of the press and employ a very agressive military force. Example of fascist government are : Italy under Benito Mussolini, Germany under the rule of Adolf Hitler, Spain during the reign of Francisco Franco and Argentina uder Juan Peron.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2016>1>b", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight any four features of Fascism.", "images": [], "marking_scheme": "Features of Fascism include:  i)   Superiority of male gender  ii)  Violation of human rights  iii)  Military involvement in government   iv)  Use of patriotic symbols to emphasize nationalism  v)   Undue limitation to freedom of press  vi)  Elimination or suppression of labour power   vii)  Absence of free and fair election  viii)  Frequent use of propaganda  ix)   Elimination of perceived enemies or threat   x)   Manipulation of the most common religion to government advantage to manipulate the people.  xi)  Corruption, management of funds  xii)  Dominant business/government relationship in the economy", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2016>2", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Outline five processes by which a bill becomes law in a presidential system of government", "images": [], "marking_scheme": "There are seven ways of turning bill into law, they are:  i) FIRST READING: This is the first stage of the bill. The bill is presented and it is required that its title be read by the clerk in House. At this point no opposition is registered and the bill is printed into leaflets for members to study.    ii) SECOND READING: The bill is now presented, after the member or a minister introducing the bill moves that the bill be read the second time. At this stage, discussions are made concerning the principles of the bill. The bill is debated and at the end a vote is taken on whether the bill should be read and sent to a committee. If the majority are in favour, the bill will move to the next stage.    iii)  COMMITTEE STAGE: At this stage, if the principles of the bill are approved by the house at the second reading. It is referred to one or other of the communities for detailed discussion, amendment and report.    iv)  THE REPORT STAGE: The committee report stating the suggestions of the committee to improve the bill, is presented and any member may move for amendment.    v)  THIRD READING:  Only verbal amendments may be made here. At this stage, the bill is passed or rejected. A thorough examination is done on the bill in order to improve on the actual drafting of the drift.    vi)  THE UPPER HOUSE:  If the bill is passed, it is sent to the upper house where it passes through similar stages. (It first started with the lower House) Jointly setting up a committee to iron things out.    vii)   ASSENT:  The bill is then presented for presidential assent, after which it becomes a law.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2016>3", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "State five factors that can limit the independence of the judiciary.", "images": [], "marking_scheme": "i)  Political Ideology: The Ideology which undermines the operations of a government will determine if the judiciary will be able to exercise its duty as stated by the law. In a totalitarian, authoritarian, military or fascist government, where the rule of law and fundamental human rights are neglected, judiciary is most time hindered to make fair judgements, among other things.  ii)  Appointment: In a country like Nigeria where the Chief Judge is appointed by the president may end up controlling the judges in the exercise of their functions. The judge, in return may in turn do the will of the executive so as not to lose favour.  iii)  Decrees: Decrees are laws made by a Federal military government while edicts are made by state military government. This laws must be followed and can't be ignored when the judicial prosecutes and sentences a person who commits crimes stated under these decrees and edicts.  iv)  Bribery and Corruption: This is a situation common in most aspects of the Nigerian society. Cases involving members of the executive or legislators are swept under the carpet aas soon as the judges receive brown envelopes. This has influenced the activities of the judiciary because a judge who tries to refuse all these criminal acts may in turn lose his job or good reputation.  v)  Disrespect of Court Decisions: There are instances when members of government feel they are above the law. When they are summoned to court, or given an injunction order, they refuse, claiming they won't be moved by anyone.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>4", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "4", "group": "", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Highlight any five roles of minority parties in a multi - party system.", "images": [], "marking_scheme": "A minority party is a political party with a smaller role than the mainstream parties in a country's politics and elections. There will be differences between minority and mainstream parties in terms of membership total, donations and the number of candidates they are able to produce in elections.  Minority parities generally receive very small numbers of votes at an election - frequently losing their deposit as they don't receive more than 5% of the vote.  Despite all these findings, minority parties play important roles in a multi-party democracy. The roles are discussed below    i) Minority parties organize and mobilize around  a single issue or position, putting pressure on candidates from major political parties to address these issues.  ii) Though minority parties rarely garner a plurality of the vote, they can influence the election by taking votes away from major parties candidates.  iii) They also serve as a readily available 'saviours' for electorates who feel major parties are representing their interests enough.  iv) They act as critics to major parties' performers and also act as reformers.  v) Minority party which represent the ideologies of people at the grass roots may form a coalitions which will gain popularity and become the choice of the masses.  vi) They introduce into the political spectrum, new viewpoint and approaches that major parties may have never introduced on their own.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>5", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Identify any five roles performed by Mass Media in nation building.", "images": [], "marking_scheme": "i)  Reflection of Public Opinion:  The mass media is an instrument for dissemination of information to a large number of people at the same time. Through discussions on this media, public opinion is created, moulded and reflected publicly to all; governors and governed.   ii) Development Communication: The media also also consciously packages messages with contents to persuade, encourage or convince the receiver or target audience to adopt an attitude and participate in actualizing a development plan or goal. These messages aim at making the target audience adopt a positive attitudinal change towards a development purpose.  iii) Protection of Social Justice: The media analyze issues and facts contained in the news, in line with the need and interest of social justice. They serve as subordinate to a far higher goal which is the goal of ensuring that public and private conduct is directed towards thee greatest possible measure of the justice in society.  iv)  Preaching against Social Vices: The media also contributes to a nation building by discouraging negative issues like ethnicity, dictatorship in leadership like the military rule and embezzlement of public funds.  v)  Information: The media also has the responsibility of informing people about development projects and programs designed and proposed by policy makers. These programmes will be new to the people, so, they need to be enlightened, educated and mobilized by the media.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>6", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "6", "group": "", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Highlight any five features of the Igbo traditional societies.", "images": [], "marking_scheme": "i)   Decentralized administration  ii)  Existence of village assembly (Oha - na - eze/ Umunna)   iii)  Significant position of grades - grades  iv)  The village priest/diviner wielded great deal of religious and juicial powers.  v)   The family heads played important roles in the administration of the village.   vi)   Absence of formal political instituttions   vii)   Decisions were reached by consensus  viii)   Succession to leadership was not hereditary but based ona achievement   ix)   Title holders (ozo titles) played significant role in the traditional political system  x)   There was the principle of checks and balances  xi)  Fusion of religious, judicial and political functions in governance.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>7>a", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Mention three former French colonies in West Africa", "images": [], "marking_scheme": "Former French colonies in West Africa are:   i)  Mauritania  ii)  Senegal  iii)  French Sudan ( now Mali )  iv)  Ivory Coast  v)  Upper Volta (now Burkina Faso)   vi)  Dahomey (now Benin)   vii)  Niger   viii)  French Guinea", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2016>7>b", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Identify four qualifications for assimilation of indigenous Africans into French citizenship", "images": [], "marking_scheme": "The French Colonial administration in West Africa adopted the policy of ' assimilation' till 1946. With this, France intended to implant French culture and civilisation on the people with the intention of suffocation the culture and fundamentalist of Africans.  French wished to expand its culture to the colonies outside France, that is, to civilize Africans by turning them into french men, the French citizens when they met certain qualifications:  i) Being born in one of four communes in Senegal gives automatic French citizenship.  ii)  Having a merited position in French service  iii) Having good character and means of  existence  iv) Being decorated with legion of honour.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2016>8", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Outline five positive effects of colonialization on West Africa", "images": [], "marking_scheme": "Though the main aim of colonialism was the sole benefit of the colonial masters economically politically and socially, Africa also got some benefits. Below are some of the benefits.   1. Africa economy expanded greatly due to the increase in the demand of African goods on the international market.  2. Africa learned about new and organised government.  3. Europeans defended Africans against their enemy. Local and tribal conflicts decreased  4. Colonialism created the need for cures of diseases that were otherwise unknown in Europe. The exposure of europeans to those diseases prompted efforts to cure them which benefited the world.  5. More religious mission opportunities were created for christianity.  6. Many West Africans learned Europeans languages  7. Education, arts and literature started flourishing  as it never had before.  8. The standard of living and quality of life for Africans improved drastically. Although the Europeans got the 'lions' share of it. Africans obtained new and better goods.  9. Production increased greatly due to new technology and new methods.  10. More jobs were created, so people were able to learn skills and new business practices.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2016>9>a", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Outline three aims and objectives of  the Nigerian People Party (NPP)", "images": [], "marking_scheme": "The Nigerian Peoples Party (NPP) is a coalition of several smaller groups: The National Union Council for Understanding (NUCU) led by Alhaji Waziri Ibrahim, Club 19, The Committee for National Unity and Progressive Front. Though the party was formed to create a national outlook, the exit of Waziri Ibrahim led to an erosion of politics without borders. Waziri's exit was precipitated because he wanted to be the chairman and also the Presidential Candidate of the party.  The aims and objectives of the party are :  a) To promote the unity, sovereignty and the territorial integrity of Nigeria.  b)  To promote the rights of individuals in the society and the enhancement of the rule of law and equal justice.  c)  For a better standard of living by providing shelters and food.  d)  For a self-radiant economy, to embark on self - radiant economy with equitable distribution of the gains of economic development within the political system.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2016>9>b", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "b", "group": "", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "b) Outline two sources of finance of NPP.", "images": [], "marking_scheme": "Nigerian People's Party got its finance sources. They are :  i. Sponsorship of Alhaji Waziri Ibrahim  ii. Pan - African Nationalist", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2016>10>a", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is National Interest?", "images": [], "marking_scheme": "National interest is a country's goals and ambitions whether economic, military or cultural. It is also an analytic tool employed to describe, explain or evaluate the sources or the adequacy of a nation's foreign policy. As an instrument of political action, national interest acts as a means of justifying , denouncing or proposing policies.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2016>10>b", "subject": "Government", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Outline four objectives of your country's foreign policy.", "images": [], "marking_scheme": "A country's foreign policy consists of self - interest strategies chosen  by the state to safeguard and to achieve goals within its international relations milieu.   The objectives of Nigeria's foreign policy are:   i)  Improving the African economy: Upon gaining independence in 1960, Nigeria quickly committed itself to improving the lives of the people of the country and harnessing the resources that remain vital to the economy of the country and their neighbours.  ii)  Military aid: Over the years Nigeria has sent troops on peace-keeping missions organised by World African bodies, to maintain peace and fight against segregation and discrimination in African countries.  iii)  Regional Economic cooperation and development: With this objective in mind, Nigeria helped create ECOWAS, which seeks to harmonise trade and investment practices for its 16 West African member countries and ultimately to achieve a full custom union.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2017>1>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is legitimate government?", "images": [], "marking_scheme": "A legitimate government is one which is accepted by the citizens", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>2017>1>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Outline any four features of legitimacy", "images": [], "marking_scheme": "- Legality: It should be approved by the law   - Acceptability: It should have the approval of the citizens   - Recognition: It should have both domestic and foreign recognition  - Responsiveness: It should always respond to the citizen opinions  - It should observe the principle of rule of law   - It should give room to public opinion   - It should have the support of the citizen", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2017>2>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "What are right?", "images": [], "marking_scheme": "Rights are legal privileges conferred on every citizen of 1 country", "marks": "5", "difficulty": "1"}, {"id": "theory>Government>2017>2>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Highlight four limitations on the right of a citizen", "images": [], "marking_scheme": "- Oath of secrecy of public servnts restricts them from releasing official information   - Declaration of a state of emergency   - Ignornce and poverty   - Imprisonment by a court   -System of government which restrict citizens' right such as military system, totalitarianism, etc.  - Non-partisanship of civil/public servants   - Insurgency and insecurity   - Age, sex, wealth (in some countrie) restrictions during elections", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2017>3>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Differentiate between a de jure and de facto one-party system", "images": [], "marking_scheme": "De jure one-party system is one in which there is only one legalized political party in a country while in de facto one-party system, among many parties, only one is dominant", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2017>3>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Outline four advantages of a multi-paty system", "images": [], "marking_scheme": "- It gives the citizens to exercise their right to freedom of choice.   - It encourages accountability and good governance of political parties of opposition   - It eradicate the risk of party dictatorship   - It covers a wide political sphere  - The other parties serve as underdogs by checking the ruling party's arbitrary use of power   - The interest of the majority are protected in this system", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2017>4>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "What is a simple majority system?", "images": [], "marking_scheme": "This is an electorate system in which the party with the highest number of votes wins the election", "marks": "5", "difficulty": "2"}, {"id": "theory>Government>2017>4>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "Outline four demerit of the system", "images": [], "marking_scheme": "- It reduces the chances of smaller parties of winning   - It is not suitable for a multi-party state as it may create  thought in the voters that they do not need to vote since their party is not a major party  - The winner wins by less than half of the total votes cast, thus the party not properly represent the interest of a large percentage of the population   - It is easily manipulated/rigged", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2017>5", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Identify five ways by which the central government can improve upon local government system in West Africa", "images": [], "marking_scheme": "- The local government should be made to properly account for funds   - The principle of meritocracy should be the basis of administrators   - All local government loans should be properly checked by the central government   - The Local government should be properly funded   - Necessary amenities and facilities such as good roads vehicles, computer, high grade markets etc. should be made available.", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2017>6", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Outline five functions performed by the Ogboni Secret Society in the pre-colonial Yoruba political system", "images": [], "marking_scheme": "- It checked any Alaafin's arbitrary use of power   - It made laws for the land which is said to be delivered from Ifa, the god  - It served as  mediator between the gods and the people  - It was the court of Appeal which resolved criminal cases   - It dethroned any Alaafin who was due for it   - It preserves the cultural values of the people", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2017>7>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "What is crown colony?", "images": [], "marking_scheme": "Crown colony is an area acquired by the British crown and governed and governed by it", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2017>7>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Highlight four functions of the secretary of State for the colony under the British colonial system", "images": [], "marking_scheme": "- Overseeing of the governments of the colonies exparte the monarch   - Approval of laws made by the local legislative councils   - He advised the Queen on governors appointment, transfer and discipline   - maintenance of law and order in the territories   - He receive petitions from the colonies   - Approval of major projects to be implemented in the colonies   - He approved budgets prepared by the governor   - Ke kept the governor's veto power in check   - He drafted and submitted reports on the colonies to the British parliament annually   - He influenced British policies on the colonies", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2017>8", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Highlight five contributions of Herbert Macaulay to the political development of Nigeria", "images": [], "marking_scheme": "- He founded a newspaper: Lagos Diary Newspaper which educated the people politically   - He created the Nigeria National Democratic Party in 1920 which stirred the people up politically   - He is the father of Nigerian nationalism, i.e he estimated nationalism in Nigeria  - He is the father of Nigeria nationalism, i.e he stimulated nationalism in Nigeria  - He contributed to labour union's fight for their rights through stories and rallies   - He fostered a protest against the imposed 1946 Richard's constitution   - He represented Nigeria in several constitutional conferences   - He is the reason behind the introduction of the Elective principle in Nigeria", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2017>9>a", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is foreign policy?", "images": [], "marking_scheme": "Foreign policy is a standard scheme or principle set by a country to define his relationship with other states with the aim of achieving her national interest", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2017>9>b", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "State four factors that influence Nigeria's foreign policy", "images": [], "marking_scheme": "- Membership and commitment to international organizations   - Nigeria's massive population and quality of human resorces   - Her reputation as a frontline state in Africa   - Her economical resources, for example, her mineral resources (erode oil) and agricultural products   - Afro-centrism: Nigeria's foreign policy is said to be centred on Africa   - Historial background  - Her government system for example, military or democratic   - Her national interest   - Her industrial buoyancy has an effect on her selection of trading partners   - Her urgent political economic or social need may also determine her foreign partners", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2017>10", "subject": "Government", "year": "2017", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Outline any five contributions of Nigeria towards the growth of Economic Community of West African States (ECOWAS)", "images": [], "marking_scheme": "- Nigeria is committed to the laws, treaties and conventions of ECOWAS  - Nigeria pays her due to the secretarist and the ECOWAS Fund regularly   - Nigeria assists members states who are lagging behind economically, for example, by providing petroleum for member states who lack it   - Nigeria has involved in peace keeping missions in member-state during their period of insurgency e.g. Liberia, Cote d' Ivoire and Sierra Leone   - Nigeria has encouraged inter-state relationship by allowing free movement to member-states' citizen, goods and service  - Nigeria has involved in carrying out major projects in members-states   - Nigeria has developed soldiers to members-state in the fetters of war", "marks": "20", "difficulty": "3"}, {"id": "theory>Government>2018>1>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Define Society", "images": [], "marking_scheme": "Society include every kind and degree of relationship entered into by men, whether organised or unorganised, direct or indirect, conscious or unconscious, co-operation or antagonistic. It includes the whole issue of human relations and is without a boundary or assignable limits.  it is also define as a group of people who share similar values,laws and traditions living in organised communities for mutual benefit.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2018>1>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Identify four features of a society", "images": [], "marking_scheme": "- Society could include any of the multiplicity of groups, limits or organisation found among men.  - It encompasses all of humanity, that is varied and multiform.  - It is the degree of relationship entered into by men.  - Society include the whole issue of human relations.  -the rules and regulations of a society are binding on all residents.  -it has a unique culture.  -roles in society are dynamic.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2018>2>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is communalism?", "images": [], "marking_scheme": "Communalism refers to a system of collective ownership of property and co-operation among members of a community in the execution of development projects.  communalism is a socio-political system based on common ownership of land in which the sense of togetherness in the community is the factor of unity.", "marks": "2", "difficulty": "1"}, {"id": "theory>Government>2018>2>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "State four differences between feudalism and communalism.", "images": [], "marking_scheme": "- Communalism involve collective ownership of property while feudalism is based mainly on hierarchical order of ownership of land.    - In Communalism, there is corporation among members in the execution of development projects while feudalism, ownerships of land is vested in the king or monarch or emperor.    - In communalism, the system is most common in communal societies while in feudalism, the land owners are duty bound to protect the serfs.    - In communalism, members of communal societies have blood relationship while in feudalism, the system is characterised by chose personal bond between the lords and surfs.", "marks": "13", "difficulty": "2"}, {"id": "theory>Government>2018>3>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Highlight three methods of acquiring citizenship.", "images": [], "marking_scheme": "- Citizenship by birth  - Citizenship by Naturalization  - Citizenship by registration  -Citizenship by descent  -Adoption through legal process  -Honorary/conferment by the state  -Conquest through wars/subjugation", "marks": "9", "difficulty": "1"}, {"id": "theory>Government>2018>3>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Outline two conditions an alien must satisfy before becoming a citizen of another country.", "images": [], "marking_scheme": "- The alien must have lived in the country for a long period of time which may range from 15 - 20 years  - The alien must marry a citizen for about 5 years.  -The alien must have marry a citizen for not less than a period of 5years.  -The alien must have renounced his or her for nationality.  -He or She must be of matured age i.e 18years.", "marks": "6", "difficulty": "2"}, {"id": "theory>Government>2018>4>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Define opinion poll", "images": [], "marking_scheme": "Opinion poll can be defined as the people view or opinion towards the policy of government. The reactions of people toward the policy made by government.     Opinion poll is a scientific method of measuring views,opinions and choice of the people based on the prediction of social, political and economic issues facing a state", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2018>4>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "State any four factors that make the conduct of opinion poll unreliable in West Africa.", "images": [], "marking_scheme": "- Unitary system of government or military  - Political Instability  - Bad Government  - A dictatorship or tyranical system e.g Nacizm or Fracism  -Lack of expertise knowledge by officials conducting the polls.  -Poor communication network  -Poor funding of poll  -Lack of objectivity among the pollsters", "marks": "12", "difficulty": "3"}, {"id": "theory>Government>2018>5>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Define a constituency", "images": [], "marking_scheme": "Constituency can be defined as the delimitation or breaking down of a particular political jurisdiction into numbers of segment for easy administration.    Constituency is an electoral district where the electorate exercises their right to elect their representatives into government or parliament.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2018>5>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Highlight any four merits of the single member constituency.", "images": [], "marking_scheme": "- It enhances smooth running of government.  - A single member constituency also encourage unit.  - It is easy to run, that is, less experience.  - It brings about quick development in such constituency.  -Community support-it encourages candidates who are community based.  -Active interest-it stimulates the interest of voters  -Reduce cost-it is not costly as opposed to multi-member constituency election  -Better knowledge of candidates", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2018>6", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "Highlight five features of the Hausa/Fulani pre-colonial political system in Nigeria.", "images": [], "marking_scheme": "- Hausa/Fulani political emirate was monarchical, headed by a king   - The Hausa/fulani political emirate was exercised by the emir and his council of advisers   - The Hausa/fulani political emirate was centralized   - The Hausa/fulani: political emirate, legislative functions was performed by the Emir and his council  - The Hausa/fulani traditional political system, judicial matters rested with the Emir and his council (alkali courts).  -Stratification-The Hausa/Fulani society was segment;uper,middle and lowerclasses  -Succession to the throne was hereditary  -Rulership was for life  -The political system was based on theocracy e.g islamic religion.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2018>7>a", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "What is proto nationalism?", "images": [], "marking_scheme": "Proto nationalism can be explain or defined as the various nationalist movement that is formed primarily by the educated elite in African continent in order to liberate the continent from colonialism.    it denotes that activities of nationalist movement were geared towards reform and participation of natives in the colonial adminstration rather than for immediate self-government", "marks": "3", "difficulty": "2"}, {"id": "theory>Government>2018>7>b", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Identify four features of proto nationalism.", "images": [], "marking_scheme": "- Formation of political parties  - Formation of Nationalist movement e.g NCBWA  - Protests against maltreatment  - The return of educated elite from britain   -It was characterized by the formation of youth movements e.g Gold coast  -Their activities were more popular along the coastal areas.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2018>8", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Highlight five functions of the President in the 1989 Constitution of Nigeria.", "images": [], "marking_scheme": "- The President is a dressed as the head of state, the head of government and commander in Chief of Army Forces.    - The President has veto power to declare war against any state that is contesting sovereighty of the state.    - The constitution also empower the President to established some parastatals e.g Nigeria population, Commission.    - The constitution also empower the president to appoint nominate ministers.     - The President has the constitutional right to check mate the activities of legislative    -He performed ceremonial functions    -He formulated policies for good governance    -He signed treaties with other countries on behalf of the country", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2018>9", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What mechanisms should be put in place to forestall military intervention in politics?", "images": [], "marking_scheme": "- Military Intervention could be prevented with the elimination or reduction in the level of corruption    - It can also be prevented through efficiency and probity, honesty and transparency in the conduct of administration    - Necessary atmosphere should be created for the conduct of free and fair elections in order to prevent military intervention in politics    - The people should always resist military interventions through the organisation of peaceful mass disobedience    - Military intervention should be outlined by the constitution    - The most potent weapon against military intervention in politics is good governance.    -Non recognition of military government by international community or organisations e.g UNO,AU,ECOWAS etc.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2018>10", "subject": "Government", "year": "2018", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "State five obstacles to the implementation of the Economic Community of West African States (ECOWAS) aims and objectives.", "images": [], "marking_scheme": "- Problems posed by Immigrants  - Financial problem  - Fear of domination and unequal development  - Problem of language  - Currency differences  -Frequent border disputes  -Lack of consensus on international issues  -Problems of refugees and internally display people  -Ideological differences  -Inability to implement most of its policies", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2019>1", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Explain five reasons for the study of government.", "images": [], "marking_scheme": "- It helps us to know our fundamental human right.    - It helps us to actively participate in politics.    - It enables adult citizens to have enough political awareness.    - It also enables us to know our duties/obligation as citizens.    - It helps us to acquire leadership skills or qualities.", "marks": "20", "difficulty": "1"}, {"id": "theory>Government>2019>2>a", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Who is a citizen?", "images": [], "marking_scheme": "Citizen is a legally recognized subject or national of a state or commonwealth, either native or naturalized. It is an inhabitant of a particular town or city.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2019>2>b", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Outline four responsibilities of a citizen to the state.", "images": [], "marking_scheme": "- Support and defend the constitution.  - Stay informed of the issues affecting your community.  - Participate in the democratic process.  - Respect and obey federal, state and local laws.  - Respect the rights, beliefs and opinions of others.  - Participate in your local community.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>3", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Highlight five roles played by the mass media in strengthening modern democracy.", "images": [], "marking_scheme": "- Media are often acclaimed as the \"fourth power\" in a democracy.    - Mass media play a crucial role in shaping a healthy democracy.    - Mass media has undoubtedly evolved and become more active over the years. It is the media only who reminds politicians about their unfulfilled promises at the time of elections.    - Mass media have made a significant achievement in educating rural illiterates masses in making them aware of all the events in their language.    - Mass media also exposes loopholes in the democratic system, which ultimately helps government in filling the vacuums of loopholes and making a system more accountable, responsive and citizen-friendly.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2019>4>a", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "What is Local Government?", "images": [], "marking_scheme": "Local government is the system of electing representative to be responsible for the administration of public services and facilities in a particular area. It is the same as a local authority.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2019>4>b", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Outline four reasons for the creation of Local Government.", "images": [], "marking_scheme": "- To bring government near to the people at the grassroot level.  - To provide opportunities for local participation in politics by the rural dwellers.  - To train the local people in the art of governance and leadership.  - Establishing link between the people at the local, state and the central government levels.  - providing employment at the local level for the people.  - seeing to the preservation of local customs, history and traditions of people.  - giving the people at the local level a very real degree of control over their local affairs.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>5>a", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "State three types of elections.", "images": [], "marking_scheme": "- General election  - Primary election  - Special election  - Constitutional amendment election  - Direct election  - Indirect election", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>5>b", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Explain four purposes elections serve in a democratic state.", "images": [], "marking_scheme": "- For registration of voters and preservation of voter registration records.  - To encourage public participation in political parties   - To provide a means by which political parties and affiliated candidates, which have demonstrated a meaningful level of community support, may qualify for losting in the general election ballot.  - For the orderly and fair selection of party nominees by primary election or political party convention and for the filling of vacancies among such nominees.  - To provide for the free exercise of the write-in vote for both politically affiliated and unaffiliated candidates.  - For the conduct of primary and general elections.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>6>a", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Outline five Negative effects of Colonial rule on the people of West Africa.", "images": [], "marking_scheme": "- Those leaders who could have made Africa strong because of their influence, were killed by colonisers or arrested this left societies divided and unorganised.    - Colonial rule took away the freedom of African nations.    - Colonist used the divide and rule theory, this brought about divisions in Africa society and setup    - It increased slavery.    - Africans were forced to drop their dressing codes, cut their hairs and traumatised in their own land.    - Our religious ideologies were rendered useless and backward thus forced to drop them.", "marks": "10", "difficulty": "3"}, {"id": "theory>Government>2019>6>b", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Five Negative effects of military rule in West Africa", "images": [], "marking_scheme": "- Ruined Economy  - Suffering education and culture  - Corruption  - Limited freedoms and rights  - Unruly country's system of government   - Praising of war.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>9>a", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "What is the New Partnership for Africa's Development (NEPAD)?", "images": [], "marking_scheme": "New partnership for Africa's development (NEPAD) is the Pan-African strategic framework for the socio-economic development of the continent. It is an economic development program of the continent. It is an economic development program of the African Union.  NEPAD was adopted at the 37th session of the Assembly of Heads of state and government in July 2001 in Lusaka, zambia.", "marks": "10", "difficulty": "1"}, {"id": "theory>Government>2019>9>b", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Identify four objectives of the New Partnership for Africa's Development (NEPAD).", "images": [], "marking_scheme": "- Eradicate poverty in Africa  - Promote sustainable growth and development  - Foster Integration of Africa in the world economy  - Accelerate the empowerment of women.", "marks": "10", "difficulty": "2"}, {"id": "theory>Government>2019>10", "subject": "Government", "year": "2019", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "List five negative effects of military rule in West Africa.", "images": [], "marking_scheme": "- Ruined Economy  - Suffering education and culture  - Corruption  - Limited freedom and rights  - Unruly country's systems of government  - Praising of war.", "marks": "20", "difficulty": "2"}, {"id": "theory>Government>2020>1>a", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "What is political socialization?", "images": [], "marking_scheme": "Political socialization refers to a process by which the citizen are educated on the values,attitudes and beliefs of the political system.Through political socialization,the citizens internalise the political culture of the nation and are made to be aware of political system,the role they are expected to play in the system,raise their loyalty,pride,patriotism and nationalistic feelimgs to the nation.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2020>1>b", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Identify four features of a nation", "images": [], "marking_scheme": "- Population: One of the major characteristics of a nation is population. For a nation to exist, there must be a given number of people which has minimum or maximum that will occupy it  - Territory: A nation must possess a definite territory which has no limit to its size.The territory must have clear cut boundaries that will separate it from other nation.  - Government: A nation must have a machinery called government,that will steer its affairs.Goverment performs its functions on behalf of the nation.  - Recognition: A nation must be recognised internally and externally.The people of a nation must realise and recognise the corporate existence of their nation, while other nation in the international environment must equally give recognition to an existing nation.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2020>2", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Highlight five features of Federalism", "images": [], "marking_scheme": "- Division of governnmental powers: Division of governemental powers between the central and component governments of the regions or states.  - Constitution: One of the characteristics of federalism is the adoption of a written constitution and rigid  - Court system: Existence of supreme court for judicial interpretation and review.  - Organs of government: Duplication of organs of government in all governments  - Legislature: Existence of bicameral legislature and supremacy of the central government  -", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2020>3>a", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "What is a Public Corporation?", "images": [], "marking_scheme": "Public corporation is a business organization established, owned, managed and financed with tax payers money by government of a country with the main motive of not making profit but to render essential services to members of the public. A public corporation is also known as public enterprises or statutory corporation.It is owned by the government and, but managed by board of directors appointed by the government.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2020>3>b", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Identify four ways in which Public Corporation are controlled", "images": [], "marking_scheme": "- Parliamentary control: Since public corporation are established by acts of parliament,the parliament is given some powers by the acts to exercise some forms of control over the activities of the corporations.  - Judicial control: As a legal entity which can sue and be sued, a public corporation can be dragged to court if its fails to act within the limits set by law that established it and its action declared ultra vires.  - Ministerial control: Ministers that are answerable to the parliament are given extensive power over public corporations.These includes powers to appoint and dismiss members of Board of Directors,determination of remunerations, conditions of services,  approving all loans and major expenditures etc.  - Public control: Members of the public who consume goods and services of the public corporations exercise some form of control through criticisms they level against these corporations.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2020>4", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Outline five ways in which Public Opinion is measured", "images": [], "marking_scheme": "- Opinion poll: This is a method of asking questions from a selected sample of people and their views are used to represent that of the entire population.  - Election:  It serves as a means of measuring public opinion on the popularity or otherwise of a government. In a free and fair election, a government which public opinion favours, wins such election and vice versa.  - Referendum: This is  a method of referring a political question or government policy to the electorate for approval or disapproval  - Through Mass Media: Public opinion can also measured or determined through views people expressed freely in the mass media  - Public response: Public opinion can also be measured or determined through the way members of the public respond to government policies through mass protests and demonstrations for or against such policies or programmes.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2020>5", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Explain five means of safeguarding rights of citizens", "images": [], "marking_scheme": "- An independent and impartial judiciary which a citizen can run to for protection whenever his rights are infringed upon  - Lack of ethic prejudice will ensure a citizen's right to freedom from discrimination on the ground of tribe  - Good economic system will ensure a citizen's rights to education, work and commensurate compensation  - A clear declaration of the fundamental human rights in the constitution is a necessary condition for the protection and guarantee of the rights of a citizen  - If freedom of the press is guaranteed, the press will fearlessly protect and safeguard the rights of a citizen.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2020>6", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS -UNO", "question": "Identify five challenges faced by the United Nations Organization(UNO)", "images": [], "marking_scheme": "- Veto power: The use of veto power by the so-called \"Big Five\"- that is the five permanent member-states of the security Council has rendered the security Council in particular impotent and UNO in general ineffective and a threat to world peace and security because of the selfish interest,political and ideological purposes for which the veto is used  - Problem of Enforement of Decisions: The UNO lacks sufficient power and machinery to enforce its resolutions and decisions and therefore, relies on moral persuassion  - Idelogical rivalry: The ideological rivalry between the Communist East and Capital West and the non- aligned nations has acted as a cog in the wheel of fulfilment of the aims and objectives of the UNO  - Racial discrimination: The UNO seems to have failed in its bid to eradicate racial discrimination in the world especially n South Africa.  - Language problem: The UNO still battles with the problem of language as speeches in the General Assembly are interpreted into at least 5 major languages", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2020>7", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Highlight five differences between the crown colony and the protectorate", "images": [], "marking_scheme": "- A protectorate is its own state merely protected by a larger country while a colony is a part of a larger country governed by the same country.  - A state which is a protectorate has the aid of a larger nation when  conducting foreign relations while for a colony, all foreign relations are created and dealt with by the mother country.  - Protectorates can be seen as an alliance.The more allies, the stronger the territory and country while colonies can be seen as a threat to  other nations,as it is the spreading of one country.  - A protectorate governs itself internally while a colony governed internally and externally by a foriegn power.  - A protectorate is a country ruled by another country while a colony is a country invaded by a larger power which set up its own government in the colony headed by a Governor General.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2020>8>a", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "List three political parties and their leaders who contested the 1979 presidential elections in Nigeria", "images": [], "marking_scheme": "- The National Party Of Nigeria(NPN): The leaders included: Alhaji Aliyu Makama Bida, Ali Monguno, Shehu Shagari, Maitama Sule, Adamu Ciroma, Inua Wada, Adisa Akinloye, MKO Abiola, Richard Akinjide, K.O Mbadiwe, Olusola Saraki, C.C Onoh, Clement Isong, Joseph Tarka    - Unity Party Of NIgeria(UPN): Chief Obafemi Awolowo    - Nigeria People's Party(NPP): Dr Nnamdi Azikwe", "marks": "6", "difficulty": "3"}, {"id": "theory>Government>2020>8>b", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Highlight three features of political parties in Nigeria since independence", "images": [], "marking_scheme": "- Power: Political parties use persuasive rather than coercive means in coming to power and their aim are contesting elections,gaining political power and governing a country.  - Ideologies and manifestoes: Political parties have ideologies they tend to implement when they come to power and they are guided by different political party manifestoes  - Constitutions: Political parties draft their different constitutions that direct the conduct of their political activities.", "marks": "9", "difficulty": "2"}, {"id": "theory>Government>2020>9", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Highlight five weaknesses of the 1999 constitution of the Federal republic of Nigeria", "images": [], "marking_scheme": "- There are problems with the process of making the 1999 constitution as well as the content of the constitution.The constitution was made during a millitary regime and approved by the Armed Forces Ruling Council  - It is not legitimate because the premable which begins with \"WE THE PEOPLE\" of the Federal Republic of Nigeria....do hereby make,enact and give to ourselves the following constitution\" has been severely criticised in Nigeria as being false claim  - The content of the constitution does not take into account the political history of the country and in addition, there are a lot of inconsistencies and provisions that do not meet the wishes and aspirations of the people.  - The 1999 constitution not only continues the margibalisation of women but also discrimination against women.There is no specific equality clause and there is no affirmative action clause.  - The constitution does not provide a liberal regime for political parties to operate and also the constitution vests all the resources in the country on the federal government.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2020>10>a", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "List three features of the Igbo Tradtional political system", "images": [], "marking_scheme": "- Traditional Igbo political organization was based on a quasi- democratic republican system of government  - The administrative system was decentralized and characterized by the principle of acephalous  - It is a chiefless society which was segmentary and eligatarian in nature.", "marks": "3", "difficulty": "2"}, {"id": "theory>Government>2020>10>b", "subject": "Government", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Identify four democratic tenets of the Igbo Traditional political system", "images": [], "marking_scheme": "- The village assembly: The village assembly was a meeting of all adult males in the community. The meetings were held at the Obi or palace of the Okpara or Obi, or at the village square, where every adult male had the right to air his views on any issue under discussion, and decisions were reached through a consensus of the people in attendance.  - The judiciary : Judicial functions were performed by the council of elders and the entire village assembly.There was no seperation of powers between the organs of government,and all the institutions participated in the enactment and interpretation of laws to the society.  - Age grade societies: One of the traditional political instutions in igboland was the age grade societies.The age grades consisted of young men divided into various groups according to their ages.  - Title holders: In some areas of Igboland,the traditional political organisation also consisted of title holders.The titles were acquired by very wealthy,honest and trustworthy members of the society who are highly respected.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2021>1", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight five features that make democracy the most popular system of government", "images": [], "marking_scheme": "- Political liberty: It is an indispensable factor, the equal rights of all normal adults to vote and to stand as candidates for election, periodic elections and equal eligibility for political offices etc.     - value of individual personality: In democracy, the belief in the value of individual personality is restored. It implies the need to respect the other man to listen to his arguments and to take account his point of view.     - Free association and group: people should be able to choose their own candidates or support political parties without being intimidated. Citizens can form parties and canvass for support for their programmes     - Provision of opportunities: Democracy provides opportunities for an individual to develop his or her personality. It provides acess to knowledge and free education, securing against unemployment, fair working conditions, leisure etc     - Supremacy of the constitution/Rule of law: The constitution should be supreme and above every other consideration in any political system. There should be the application of the rule of law and no one should be above the law.     - Independence of the judiciary/fundamental human right: The judiciary should be free and independent of other branches of government e.g executive and the legislature. The rights of individual should be promoted and guaranteed.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2021>2", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Explain five factors that limit the powers of government", "images": [], "marking_scheme": "- Constitution:Constitution achieved limited government through a separation of powers. Constituion states the principle of constitutional supremacy that guarantees limited government and the rule of law.     - seperation of powers: Division of the legislative, executive and judicial functions of government among separate and independent bodies. That document futher precluded the concentration of political power by providing staggered terms of office in the key governmental bodies.     - rule of law: The rule law constraint on rulers means that the government is subject o existing laws as much as its citizens are. It limites the power of the government and it is one of the key feature of democracy     - consent of the governed: It refers to the idea that a government's legitimacy and moral right to use state power is justified and lawful only when consented to by the people or society over which that political power is exercised.     - rights of the minority: The rights applied to members of racial, ethnic, class religious or gender and also the collective rights accorded to any minority group.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2021>3", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Outlline five reasons for which the judiciary is kept independent of the control of executive and legislature", "images": [], "marking_scheme": "- Independence of the judiciary ensures and protects the rights and civil liberties of the citizens     - Independence of the judiciary will give the organ more impetus to ascertain the true winners when election petition are brought to it to determine     - The judiciary will be in a vantage position to punish law breakers and those who refuse to obey the laws of the land if it is independent     - An independent judiciary will guard and protect the constitution better than the when it is controlled by the executive or the legislature     - Independence of the judiciary allows it to give proper and unbias interpretations of the laws and the constitution and stand firmly to declare any act that is conflict with the constitution unconstituional whether committed by the legislature or executive.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2021>4", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Identify five factors that make public opinion an important aspect of the democratic process", "images": [], "marking_scheme": "-Press freedom: The use of mass media should be maintained     - Bureau of information: This should be established to receive, compile and disseminate information     - Freedom of speech and asscociation: By encouraging and allowing freedom of speech and asscociation     - Activities of pressure groups: By encouraging the activities of pressure groups and the other voluntary organisations     - Opinion Poll: Encouraging the use of opinions on issues of general importance     - Existence of political parties: Will help to mould the opinion of the people     - Responsible and responsive: For example, social institutions such as families and religious centres should be able to demonstrate these.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2021>5", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Highlight five ways of effectively controlling the local government to live up to its mandate", "images": [], "marking_scheme": "- Approval of loan: Any loan to be taken by the local government from any financial institution, must get the approval of the state government     - Auditing: Auditors should either the state or the central government to audit the finances of the local government     - Specific functions: The state House of Assembly can ask a local government to perform certain specific functions     - Amendment of laws: The National Assembly through the central government can at any time decide to amend the laws establishing local government     - Withholding of grants: The central government may withhold local government grants if implicated in financial mismanagement     - Monitoring the activities of local government: The state government can do this be ensuring that they adhere to guideline and rules set for them     - Judicial control: The courts can declare any bye-law made null and void or unconstitutional, if such laws, are not in line with the provision of the country's constitution     - Public control: People are free to criticize some of the activities of local government and can come up with useful suggestions that would help in sanitizing some of these activities.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2021>6>a", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "State three institutions in Yoruba Pre-colonial political system of administration.", "images": [], "marking_scheme": "These are the institutions  - The Oba   - Oyomesi   - The Ogboni", "marks": "3", "difficulty": "3"}, {"id": "theory>Government>2021>6>b", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Explain four checks and balances that existed in Yoruba pre-colonial politcal system", "images": [], "marking_scheme": "- Control of the king:   At the top of the yoruba political structure was the king, called the Alaafin. He was vested with most of the powers of the state and this included both the political and spiritual powers. There was three assistants who were in charge of the king's administration. They were, Ona EFa, The Empires Cheif justice, the Otun Efa, the head of the Sango shrine and the Osi Efa, the controller of the palace finances. The head of the Council of Chiefs, Bashorun, had the power to dethrone the king of the people lost confidence in him     - Control of the Aremo:   The Aremo was the first son of the king. In the event of the demise of the Alaafin, the Aremo was the one step into his shoes. At a point in the history of the Yoruba, it was realized that the Aremo were assassinating their fathers so that they could sit on tghe throne. It was therefore, decreed that whenever the king died , the Aremo must commit suicide. This was the check the killing of the kings before their natural term.     - Control of the Bashorun:   The Bashorun was controlled by the Ogboni which was a gathering of the representatives of the various lineages. The Bashorun was appointed upon the approval of the Ogboni. The king or Alaafin could use the Ogboni to control excesses of the Oyemesi(council of prominet chiefs) headed by the Bashorun.     - Control of the arny and their commander:   The army commander was answerable to the Alaafin and the Bashorun. The army officer were appointed by the Alaafin but their promotions were carried out by the Oyemesi. If the army commander lost a war, he was expected to commit suicide or go into exile.", "marks": "12", "difficulty": "3"}, {"id": "theory>Government>2021>7", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Identify five weakness of the Independence Constitution of 1960", "images": [], "marking_scheme": "- It retained the Bristish Queen as the constitutional ceremonial Head of the State.     - The supreme Court was not the court of last resort; the judicial committee of the Privy Council in Britain continued to act as the highest court of appeal for Nigeria     - The constitution was weak because members of the House of Senate were appointed by the regional government not elected. They therefore become stooges and surrogates of the regional government     - The constitution failed to specify the number of ministers to be appointed and, whethet or not their appointment should reflect the federal character of Nigeria     - The constitution succeeded only in granting independence to Nigeria but failed to address important political issues such as the minority problem and the the political integration of the country     - A glance at the distribution of powers between the central government and the regional government showed that the Federal Government was more powerful than the regional government", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2021>8", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Explain five problems Nigeria encounter in her interaction with nations of the world", "images": [], "marking_scheme": "- Many African countries do not appreciate Nigeria;s generosity and sacrifice on behalf of the African continent     - Some African countries fear that Nigeria may use her position in terms of size and resources to dominate the conitnent     - The policy of indirect rule and assimilation respectively introduced by Britain and France in AFrica, brought about sharp political differences between the two blocs.     - Nigerians cannot appreciate Nigeria's generosity to other Africa countries especially inn the face of local deprivations     - It is also expensive and Nigeria hasn't got enough means to effectively play the big brother role", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2021>9", "subject": "Government", "year": "2021", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Highlights five positive impacts of British and French colonial administration in West Africa.", "images": [], "marking_scheme": "- Military and technical aid: Some former colonial territories especially the French territories, receives military and technical aid from their former colonial masters.     - Common language: Colonialism promoted the development of common languages among the colonial territories. English was developed and spoken in British territories while French developed in French territories     - Development of political parties: One of the positive impact of colonialism in British and French West Africa was the development of political parties parties. Many of these political parties emerged to champion the struggle for political independence.     - Common wealth: This organisation was formed to bring together all former colonies under Britain and Britain itself. They cooperate among themselves in different areas of human endeavour e.g sport, scholarship programmes etc.     -Emergency of the press: Another positive impact of colonialism was the emergence of the press. especially the print media(Newspaper). the press developed and become the mouthpiece of the people in the struggle for political independence", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION A>1", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "In what five reasons for which citizens lose trust in government.", "images": [], "marking_scheme": "- Poor economic performance: When government fails to utilize resources and the citizens have to endure a high cost of living and increase in poverty rate, they begin to lose trust in the government.    -Corruption: When government officials prioritize their selfish interest over national interest, citizens lose trust in the government.    -There is a need for checks and balance amongst the various organs of government. To the extent where these checks are not acted upon and there is too much excesses, citizens lose trust in government.    - Citizens are meant to enjoy certain public services as they pay taxes and levies. If citizens fail to get social care in return for performing their basic duties and obligations, they lose trust in government.    -Lack of free and fair elections: When candidates are forced on citizens and citizzens are unable to exercise their voting rights - as well, when the processes are shadowed by imbalances, citizens lose trust in government.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION A>2", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "In what five ways can the management body ensure fair play in an electoral contest in Nigeria?", "images": [], "marking_scheme": "-Non-partisanship of electoral officials   Overtime, electoral officers who are meant to be independent have sided with particular candidates. Partisan politics of this kind queries the legitimacy of the electoral process. Hence, an abrupt end to this will ensure fairplay in any electoral contest in Nigeria.    -Eradication of violence and intimidation of voters  During voters' registration, people are often hindered from having an hitch-free process due to favoritism of a particular political group. Also, during elections, the processes are usually marred by violence and harassment of voters. A peaceful election will ensure fair play during elections in Nigeria.    -Proper logistics  A timely arrival and transportation of electoral materials and officials on election day and after election such that election materials are well delivered and remitted will also ensure fair play during elections.    -Non-government interference  In ensuring that there is fairplay in any election, the electoral commission has to be independent and free from interference from government officials in order to give all candidates level ground to contest.    -Proper funding  Proper funding of elections in Nigeria will ensure fair play in the electoral process. This involves funding for more electronic voting equipments such as effective card readers, e-transmitters and many others to ease the electoral procedure.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION A>3", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Highlight five negative impacts on a state should the judiciary fail to live up to its constitutional mandate.", "images": [], "marking_scheme": "- The first and foremost function of the judiciary is to give justice to the people, whenever they may approach it. It awards punishment to those who after trial are found guilty of violating the laws of the state or the rights of the people. If the judiciary fails, the rights of the common man would be impede on and oppression will be the order of the day.    -One of the major functions of the judiciary is to interpret and apply laws to specific cases. In the course of deciding the disputes that come before it, the judges interpret and apply laws. Every law needs a proper interpretation for getting applied to every specific case. If the judiciary fails, laws will be muddled up and there will be partiality in the interpretations of the law.    -The judiciary acts as the guardian of the Constitution. The Constitution is the supreme law of the land and it is the responsibility of the judiciary to interpret and protect it. The rule of law hinges on the supremacy of the constitution and should the judiciary fail, the rule of law becomes inapplicable.    - In a federal system, the judiciary has to perform an additionally important role as the guardian of the constitution and the arbiter of disputes between the centre and states. It acts as an independent and impartial umpire between the central government and state governments as well as among the states. Should the judiciary fail in its duty, there will be an override of power by the central government on states or by a stronger state over another.    - In case any law is found ultra vires (unconstitutional), it is rejected by the judiciary and it becomes invalid for future. This power of the court is called the power of judicial review. It is through this means that the judiciary checks the executive and legislature. If they fail in doing this, there is a tendency of abuse of power by the other organs of government.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2022>SECTION A>4", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Identify five differences between the state as an entity and government as an institution", "images": [], "marking_scheme": "- Membership of a State is compulsory but not of Government: All people are citizens of the State. They together constitute the population of the State. Each one normally gets the membership (citizenship) of a state automatically right at the time of one's birth and continues to live life as such. However, membership of the government is not automatic. No one can be forced to become its part. Anyone can voluntarily seek an election, get elected as a representative of the people and become a part of the government. Only some persons form the government..    -State is Abstract, Government is Concrete: State is a concept, an idea or a name used to denote a community of persons living on a definite territory and organised for the exercise of sovereignty. State cannot be seen. Government is made by the people of the State. It is formed by the representatives of the people. It has a definite and defined organisation and form. It can be seen as a team of people exercising the power of the State.    -Sovereignty belongs to State and not to Government: Sovereignty is the hallmark of the State. It belongs to the State. The government exercises power on behalf of the State. It acts on the basis of the sovereignty of the State. Sovereignty is comprehensive, absolute, unlimited and all inclusive supreme power of the State. The government exercises only well defined and limited powers.    -Every State has uniformly four essential elements, however the forms and features of Government differ from State to State: Each State has a uniform personality with its four essential elements Population, Territory, Government and Sovereignty. However, governments can be of different forms— Parliamentary or Presidential, Unitary or Federal or a mixture of these. A government can be monarchical or aristocratic or democratic or a dictatorship. The people can by choice change the form of their government. But the State exists independently and has a uniform character.    -State is Permanent, Government is Temporary: Governments come and go regularly. After every general election the government changes. It can also undergo a total change through an election or even through a revolution. State is permanent. It continuously lives so long as it continues to enjoy sovereignty.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION A>5", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Explain five reasons for the decline in public trust of the media in your country", "images": [], "marking_scheme": "- Spread of misinformation and disinformation  The widespread emergence of information that is false or misleading, that is intended to persuade or confuse rather than inform, is a contributor to the decline of trust in media. The problem is not entirely new. Propaganda, usually distortions manufactured by a government or a powerful political interest group to influence the attitudes and opinions of its own citizens or the citizens of another country, has a long history. The media has lied so often to the public about major stories and issues affecting the entire nation and every citizen.    -Political interference   Nowadays, the media that is supposed to be independent has delved into partisan politics which puts their judgement and information in question. This political interference in the media sphere causes a decline in public trust especially when the government is not worthy of trust.    -Another reason is the fact that virtually all media are now owned by 6 corporations and are operated solely for profit. Informing the public is no longer part of the purpose of the media.     -One of the reasons that there appears to be lower levels of confidence in media, or news media in particular, is because of the emergence of a crowded and confusing market. Many publishers are competing for the attention of audiences and this has made them lose public trust.    -Finally, trust in the media is plummeting because people are becoming aware that most media outlets are owned by giant corporations and investment groups who are backing one side over the other because it benefits their business.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION B>6", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Identify five ways in which traditional rulers controlled their subjects in pre-colonial Nigeria", "images": [], "marking_scheme": "-Rules and regulations  Any society without rules and regulations could degenerate into chaos. In pre-colonial traditional societies, there were rules and regulations that the inhabitants were required to abide by. The rules and regulations were therefore established to govern the conduct of individuals within the jurisdiction of the chiefs, so that it does not degenerate into confusion.    -Settlement of disputes  The pre-colonial traditional rulers settled disputes. Disputes are normal in every society and pre-colonial societies in West Africa, were no exception. Any dispute that arose was settled by the chiefs. Culprits were punished, and the innocent were set free. This was one of the ways chiefs controlled their subjects.    -Use of ancestral spirits  The traditional belief that when the living misbehaved, the dead who lived in the after world could punish them, was another ingenious way of controlling the people. This belief in the underworld was common in pre-colonial times and nobody wanted to be on the wrong side of the gods, hence they obeyed the laws, thus helping the chiefs maintain control.    -Customs or taboos and conventions  There were things that traditional society frowned upon and society never compromised on them. These were aspects of their customs, taboos, and conventions. Any infraction of the customs, taboos or conventions attracted a certain form of fine or sanctions. This way, the chiefs were able to control their subjects.    -Oath taking  In pre-colonial times, one of the ways of ascertaining the truth was the taking of an oath, to tell the truth. There were serious repercussions for anybody who took the oath and still went ahead to tell a lie. The oath was usually taken before the gods of the land represented by the Chief Priests. Sub-chiefs were also made to swear oaths to remain loyal to the Paramount Chief. All of these helped to keep them in line.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2022>SECTION B>7", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Outline five significant provisions of the 1989 Third Republican Constitution which deepened the democratic development of Nigeria", "images": [], "marking_scheme": "-The provision of the Constitution that any fraction arising out of an electoral count should be rounded up to the next whole number, showed the sensitivity of the framers of the constitution to the political problems created by the interpretation of two-thirds of 19 states in the 1979 presidential elections and their readiness to avert similar problems in future.    -The Constitution also put the legislators on their toes by providing for a system of recall. By giving the electorate the power to recall their unproductive elected representatives who no longer enjoyed their confidence, the constitution was only establishing the principle of voter sovereignty.    -The cost of government was drastically reduced by this constitution. For example, the number of Senators representing each state was reduced from five to three under this constitution. Second, legislators were paid only a sitting allowance, a payment made for those days they attended sittings of the house. Also,  the President could only appoint a maximum of three Special Advisers unlike the limitless number he could employ under the 1979 Constitution.     - The adoption of the secondary school leaving certificate as the minimum qualification for eligibility for participation in politics prevents illiterates from seeking offices.    - The constitution entrenched the fundamental human rights.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2022>SECTION B>8", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Highlight five benefits which the adoption of federalism has brought to the political development of Nigeria", "images": [], "marking_scheme": "- Federalism was basically introduced to bring about peace and unity in the different regions of the country. In Nigeria, federalism has emerged as a means of accommodating the growing desire of people to preserve or revive the intimacy of small societies and the growing necessity for larger combinations to mobilize the utilization of common resources.    -Another important factor that necessitated federalism in Nigeria and hence benefitted the country was the political culture of the country. Evidently, Nigeria's political culture was federalism friendly and that gave rise to easy adoption of federalism. As already explained, Nigeria is an amalgamation of three different regions with beliefs and customs. Federalism was the only solution to ensure peace and unity amongst the leaders and the citizens and that was why federalism was adopted into the Nigerian political system.    -In other not to control only some parts of the big country, Nigeria, the colonial masters thought it wise to divide the country into different component units that will be represented in the government. This helped to solve the problem of marginalization in the leadership. The fear of marginalization by the minority in a unitary system of government has, to a great extent, influenced the majority state support for federating states. In a Unitary system, the minority states cannot govern the entire region which is controlled by majority. Thus, federalism seemed to be the only option left for Nigeria because it allows for popular participation in government. Here, both the majority and minority are represented in the government.    - The availability of resources in a particular region and the need for that area to control the resources has also been seen as a reason for a befitting federal system in Nigeria. This has nexus with the particular sharing formula adopted. In a unitary constitution which opposes federal principles, everything belongs to the central government; the federating unit does not exist, let alone agitating for resource control. However, that is not so in a federal government system.    -Federalism as said earlier decentralizes power. This feature of federalism is widely believed to be a veritable framework for even and need-sensitive development.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION B>9>a", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "What is meant by E-Government?", "images": [], "marking_scheme": "Electronic government (or e-Government) is the application of Information and Communication Technologies (ICTs) to government functions and procedures with the purpose of increasing efficiency, transparency and citizen participation.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2022>SECTION B>9>b", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Explain five benefits which Nigeria stands to gain in adopting E-Government", "images": [], "marking_scheme": "-Saving Costs   A lot the Government expenditure goes towards the cost of buying stationery for official purposes. Letters and written records consume a lot of stationery. However, replacing them with smartphones and the internet can saves crores of money in expenses every year.    -Transparency   The use of e-governance helps make all functions of the business transparent. All Governmental information can be uploaded onto the internet. The citizens access specifically access whichever information they want, whenever they want it, at the click of a mouse, or the touch of a finger.    -Easy and Quick Implementation  With e-government, paperwork has been made so simple and intuitive. This facilitates sharing of information and ideas between all government agencies and department to build one mega data base.  Getting the government decisions and policies across to the citizens is easy as well, since e-government gives every citizen access to information.    -High Level of Trust on Government  For any government to survive or maintain or keep control of power, such government must win the trust of the majority of the citizens. E-government can always afford that for any government that embraces it. It improves services through better understanding of citizens' requirements, thus aiming for seamless online services. That it achieves through improving transparency, accuracy and facilitating information transforming between government and citizens.    -Inclusive Governance  E-governance helps in building trust between governments and citizens, an essential factor in good governance by using internet-based strategies to involve citizens in the policy process, illustrating government transparency and accountability.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2022>SECTION B>10", "subject": "Government", "year": "2022", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Highlight five compelling reasons for which Nigeria interacts with international organizations", "images": [], "marking_scheme": "-Security: In case of a breach to her sovereignty, belonging to international organizations gives Nigeria the advantage of having allies that will help fight her cause. Isolation(non-belonging) increases external threat.    -Trade opportunities: Like many other countries, Nigeria cannot be totally self-dependent. There is a need to interact with other countries on economic basis. This includes the area of imports and exports. This helps build the economy which in turn grows the country.    - International organizations are formed for efficiency, hence, when Nigeria joins international organizations; there is a particular standard required of her. This means that being a member of international organizations is a positive influence on the country.    -International organizations can function for the aggregation and articulation of the national interests of its members into the international system. Thus, they bring Nigeria into the same framework to articulate their interests into the world society.    - International relations can function as the makers of norms and law for the operation of international relations. In other words, they make law for the states to follow. They produced several documents or treaties in improving human rights, for example 1948 UN Universal Declaration of Human Rights which is entrenched in the Nigerian constitution.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2023>1", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Identify Five functions of government as an Agent of the State", "images": [], "marking_scheme": "The government, as an agent of the state, performs several functions. These include:   - Law-making: The government formulates and implements laws to guide the conduct of citizens.   - Maintenance of Law and Order: The government ensures peace and security through law enforcement agencies.   -  Provision of Public Goods and Services: The government provides essential services such as education, healthcare, and infrastructure.   - Protection of Rights and Liberties: The government protects the fundamental rights and freedoms of its citizens.   - Economic Management: The government manages the economy through fiscal and monetary policies to ensure economic stability and growth.", "marks": "15", "difficulty": "1"}, {"id": "theory>Government>2023>2", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Explain Five factors that hamper the effective operation of the justice delivery system", "images": [], "marking_scheme": "Several factors can hamper the effective operation of the justice delivery system. These include:   - Corruption: This undermines the integrity of the justice system.   -  Inadequate Funding: Lack of sufficient funds can lead to delays and inefficiencies.   - Poor Infrastructure: Inadequate facilities can hinder the administration of justice.   - Inadequate Manpower: A shortage of trained personnel can affect the delivery of justice.    -  Political Interference: This can compromise the independence of the judiciary.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2023>3", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Highlight Five factors that have contributed to the weakened government institutions in many West African States", "images": [], "marking_scheme": "Several factors have contributed to the weakening of government institutions in many West African States. These include:   - Corruption: This undermines the effectiveness and credibility of government institutions. - Political Instability: Frequent changes in government can disrupt the functioning of institutions.   - Poor Governance: Lack of transparency and accountability can weaken institutions.   - Inadequate Funding: Lack of resources can hinder the performance of institutions.   - Weak Rule of Law: This can undermine the authority and effectiveness of institutions.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2023>4", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In what five ways does political socialization assist in the democratic process of a state?", "images": [], "marking_scheme": "Political socialization assists in the democratic process of a state in several ways. These include:   - Formation of Political Opinions: Through political socialization, individuals develop their political beliefs and opinions.   - Civic Participation: It encourages citizens to participate in the political process.   - Development of Political Culture: It helps in the development of a democratic political culture.   - Promotion of Political Stability: It promotes political stability by inculcating in citizens the values of tolerance and compromise.   - Facilitation of Political Change: It facilitates peaceful political change by preparing citizens to accept new political ideas and leaders.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2023>5", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Outline five reasons for which it is important for a state to have efficient local government system", "images": [], "marking_scheme": "It is important for a state to have an efficient local government system for several reasons. These include:   - Grassroots Development: Local governments are closer to the people and can therefore address their specific needs.   - Promotion of Democracy: Local governments provide a training ground for democracy as they involve people in decision-making.   - Efficient Service Delivery: Local governments can deliver services more efficiently due to their proximity to the people.   - Conflict Resolution: Local governments can help resolve local disputes and maintain peace.   - Economic Development: Local governments can stimulate economic development by implementing local economic policies.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2023>6", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Explain five reasons for which the study of nationalism and nationalist activities is important to the democratic development of a state", "images": [], "marking_scheme": "The study of nationalism and nationalist activities is important to the democratic development of a state for several reasons. Firstly, it fosters a sense of unity and common identity among the citizens of a state. This unity is crucial for the smooth functioning of a democratic system as it promotes cooperation and mutual understanding among the diverse groups within the state. Secondly, nationalism encourages active participation in the democratic process. When citizens feel a strong sense of belonging to their nation, they are more likely to take part in elections, voice their opinions, and engage in other democratic activities. Thirdly, nationalism can serve as a bulwark against external threats and influences. A strong sense of national identity can help to protect the democratic institutions of a state from foreign interference. Fourthly, nationalism can promote social cohesion and stability, which are essential for the effective functioning of a democratic system. Lastly, the study of nationalism and nationalist activities can provide valuable insights into the historical, cultural, and social factors that shape the democratic development of a state.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2023>7>a", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "What is political leadership", "images": [], "marking_scheme": "Political leadership refers to the role of individuals or groups in influencing, guiding, and directing the political activities and affairs of a state or a political entity. It involves making decisions that affect the lives of the citizens, formulating policies, implementing laws, and maintaining order and stability in the society. Political leaders can be elected officials, such as presidents and prime ministers, or they can be influential figures in political parties, social movements, or other political organizations. The effectiveness of a political leader is often measured by their ability to mobilize support, achieve their political objectives, and contribute to the overall well-being of the society.", "marks": "3", "difficulty": "1"}, {"id": "theory>Government>2023>7>b", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Identify four qualities of a good political leader", "images": [], "marking_scheme": "A good political leader should possess several qualities. Firstly, they should have integrity. This means they should be honest, transparent, and accountable in their actions. Secondly, they should have good communication skills. They should be able to articulate their ideas clearly and persuasively, and they should also be good listeners. Thirdly, they should have a vision. They should have a clear idea of what they want to achieve and how to go about it. Fourthly, they should have the ability to inspire and motivate others. They should be able to rally their followers and inspire them to work towards a common goal.", "marks": "12", "difficulty": "2"}, {"id": "theory>Government>2023>8", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "In what five ways is diplomacy important to the development of Nigeria?", "images": [], "marking_scheme": "Diplomacy plays a crucial role in the development of Nigeria in several ways. Firstly, it helps to maintain peace and security. Through diplomatic negotiations and agreements, Nigeria can resolve conflicts with other countries and prevent the outbreak of war. Secondly, diplomacy enables Nigeria to establish and maintain economic ties with other countries. This can lead to increased trade, investment, and economic growth. Thirdly, diplomacy allows Nigeria to gain international support for its development goals. By engaging in diplomatic activities, Nigeria can persuade other countries and international organizations to provide financial aid, technical assistance, and other forms of support. Fourthly, diplomacy can enhance Nigeria's international reputation and influence. By acting as a responsible and constructive member of the international community, Nigeria can gain respect and influence on the global stage. Lastly, diplomacy can help to protect the rights and interests of Nigerians abroad. Through diplomatic channels, the Nigerian government can assist its citizens who are living, working, or traveling in other countries.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2023>9", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Outline five positive political impacts colonial administrations had on West African States leading to statehood", "images": [], "marking_scheme": "Colonial administrations had several positive political impacts on West African States leading to statehood. Firstly, they introduced modern systems of governance, including the principles of rule of law and administrative efficiency. Secondly, they established infrastructure such as roads, railways, and ports, which facilitated trade and communication. Thirdly, they introduced formal education, which produced a class of educated Africans who later became leaders in the struggle for independence. Fourthly, they brought about economic development, albeit uneven, through the introduction of cash crops and mining. Lastly, they inadvertently fostered a sense of nationalism among Africans. The experience of colonial rule, with all its injustices and inequalities, made Africans more aware of their common identity and their desire for freedom and self-determination.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2023>10", "subject": "Government", "year": "2023", "type": "Theory", "sub_label": "10", "group": "CLOSENESS", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Identify five mistakes committed in democratic governance that give cause for the military to intervene in politics", "images": [], "marking_scheme": "Democratic governance is a form of government where the supreme power is vested in the people and exercised by them directly or indirectly through a system of representation usually involving periodically held free elections. However, there are instances where democratic governance fails due to certain mistakes, which may give cause for the military to intervene in politics. Here are five such mistakes:    - Corruption: This is one of the most common mistakes in democratic governance. When the elected officials engage in corrupt practices, it undermines the trust of the people in the government and can lead to military intervention to restore order and integrity.    - Abuse of Power: When those in power use their position to serve their personal interests rather than the interests of the people, it can lead to dissatisfaction among the populace and create a vacuum that the military may feel compelled to fill.    - Failure to uphold the rule of law: Democratic governance is based on the rule of law. When this is not upheld, it can lead to chaos and disorder, providing a reason for the military to step in.    - Political Instability: Frequent changes in government, political infighting, or lack of clear leadership can lead to instability, which can be detrimental to the nation's progress. In such cases, the military may intervene to establish stability.    - Infringement on Human Rights: When a democratic government fails to protect the rights of its citizens or engages in activities that infringe on these rights, it can lead to public outcry and potential military intervention.    In conclusion, while democratic governance is the preferred form of government, certain mistakes can undermine its effectiveness and give cause for the military to intervene. However, it's important to note that military intervention in politics is generally viewed as a setback to democratic governance and is not a desirable outcome.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2024>SECTION A>1", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "1", "group": "CLOSENESS", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Discuss five ways in which the mass media can play a vital role in making democratic governance work in Nigeria.", "images": [], "marking_scheme": "The mass media plays a crucial role in democratic governance, and its impact can be particularly significant in a diverse and complex democracy like Nigeria's. Here are five ways in which the mass media can contribute to making democratic governance work effectively:     Enhancing Transparency and Accountability  The mass media serves as a watchdog, scrutinizing government actions and policies. Through investigative journalism and regular reporting, the media can expose corruption, misuse of public funds, and maladministration. By bringing these issues to the public's attention, the media compels government officials to be more transparent and accountable. Regular coverage of government activities, audits, and expenditures helps ensure that officials act in the best interest of the public, promoting good governance.     Informing and Educating the Public  A well-informed electorate is essential for a functioning democracy. The media plays a key role in educating citizens about their rights, responsibilities, and the workings of government. By providing comprehensive coverage of political processes, electoral procedures, and policy issues, the media helps voters make informed decisions. Educational programs and news reports that explain complex political and economic issues empower citizens to participate more effectively in democratic processes.    Facilitating Public Debate and Discourse  The media provides a platform for public debate and discourse, allowing diverse opinions and perspectives to be heard. Talk shows, opinion pieces, and public forums hosted by the media encourage dialogue among citizens, policymakers, and experts. This exchange of ideas helps in formulating balanced and representative policies. It also ensures that various segments of society, including marginalized groups, have a voice in national conversations, fostering inclusiveness and better decision-making.     Promoting Civic Engagement  The media plays a significant role in encouraging civic engagement by covering local and national elections, informing citizens about voting procedures, and highlighting the importance of participation. Campaigns and initiatives promoted through media channels can motivate people to register to vote, participate in community activities, and engage in civic duties. Media coverage of public events and political rallies further stimulates public interest and involvement in democratic processes.     Providing a Platform for Government Communication  Effective communication between the government and the public is vital for democratic governance. The media serves as a bridge, enabling the government to disseminate information about policies, programs, and initiatives directly to the public. This ensures that citizens are aware of government efforts and can provide feedback. Regular updates and official statements through various media channels help maintain a dialogue between the government and its citizens, fostering trust and cooperation.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION A>2", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "2", "group": "", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Identify and explain five reasons for which civil society organizations are considered a major stakeholder in the governance structure of Nigeria.", "images": [], "marking_scheme": "Civil society organizations (CSOs) play a crucial role in the governance structure of Nigeria for several reasons:    Advocacy for Good Governance and Accountability  CSOs are instrumental in advocating for good governance and holding public officials accountable. They work to ensure that government activities are transparent and that leaders are answerable for their actions. By monitoring government spending, public policies, and electoral processes, CSOs help to curb corruption and promote transparency. Their advocacy efforts often lead to increased public awareness and pressure on government institutions to adhere to ethical standards and improve their performance.    Promotion of Human Rights and Social Justice  CSOs are at the forefront of advocating for human rights and social justice in Nigeria. They work to protect marginalized groups, including women, children, and ethnic minorities, from discrimination and exploitation. By providing legal aid, conducting human rights education, and campaigning against abuses, CSOs contribute to the protection and promotion of fundamental rights and freedoms. Their efforts help to ensure that human rights are respected and upheld, contributing to a more just and equitable society.    Community Development and Service Delivery  Many CSOs are actively involved in community development and service delivery, particularly in areas where government resources are limited. They provide essential services such as healthcare, education, and vocational training, often reaching underserved and remote communities. By filling gaps in service provision, CSOs enhance the quality of life for many Nigerians and support sustainable development. Their grassroots approach ensures that interventions are tailored to the specific needs of communities, leading to more effective and relevant outcomes.    Encouragement of Civic Participation and Engagement  CSOs play a key role in encouraging civic participation and engagement. They mobilize citizens to get involved in governance processes, such as voting, community meetings, and public consultations. By educating the public about their rights and responsibilities, CSOs foster a more informed and active citizenry. Their efforts help to strengthen democratic processes and ensure that the voices of ordinary Nigerians are heard and considered in decision-making.    Conflict Resolution and Peacebuilding  In a country with diverse ethnic and religious groups, CSOs are vital in promoting peace and resolving conflicts. They engage in dialogue, mediation, and reconciliation efforts to address tensions and build social cohesion. By fostering understanding and cooperation among different groups, CSOs contribute to a more stable and harmonious society. Their work in conflict prevention and peacebuilding helps to mitigate the impact of disputes and support long-term stability.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION A>3", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "3", "group": "", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "What five factors explain the reasons for the attack on the democratic system of government in some member states of the Economic Community of West African States (ECOWAS) in recent times?", "images": [], "marking_scheme": "Several factors explain the recent attacks on democratic systems in some member states of the Economic Community of West African States (ECOWAS). These factors contribute to political instability and undermine democratic governance in the region:  Corruption and Mismanagement  Corruption remains a significant issue in many West African countries. Mismanagement of public funds, embezzlement, and lack of transparency erode public trust in democratic institutions. When citizens perceive that their leaders are engaged in corrupt practices, they may become disillusioned with the democratic process, leading to political instability and even calls for the overthrow of the government. Corruption undermines the effectiveness of governance and fuels dissatisfaction, which can manifest in attacks on democratic structures.    Political Instability and Weak Institutions  Political instability, often characterized by weak or fragmented institutions, undermines democratic governance. In several ECOWAS member states, political institutions lack the capacity to enforce laws, maintain order, and effectively address citizens' needs. This institutional weakness creates an environment ripe for conflict, as competing political factions may resort to violence or coup attempts to seize power. Weak institutions also make it difficult to conduct free and fair elections, leading to contested results and further instability.     Socioeconomic Inequality and Unemployment  High levels of socioeconomic inequality and widespread unemployment contribute to political unrest and dissatisfaction. In many ECOWAS member states, economic disparities and lack of job opportunities fuel frustration among the youth and marginalized communities. This economic disenfranchisement can lead to protests, demonstrations, and support for radical alternatives to the existing democratic system. Economic grievances often intersect with political instability, making the democratic process vulnerable to attacks.     Ethnic and Religious Tensions  Ethnic and religious tensions can exacerbate political instability and lead to attacks on democratic systems. In some ECOWAS member states, deep-seated ethnic and religious divisions contribute to conflicts and undermine national unity. Political leaders may exploit these divisions for their gain, creating further rifts and instability. The exploitation of ethnic and religious identities often results in violence and undermines democratic processes, as various groups may challenge the legitimacy of the government or engage in disruptive activities.    Lack of Political Will and Leadership  A lack of political will and effective leadership can also undermine democratic governance. Leaders who prioritize personal or party interests over national development contribute to the erosion of democratic norms. Inadequate responses to public grievances, failure to uphold the rule of law, and disregard for democratic principles weaken the legitimacy of the government. When leaders fail to demonstrate commitment to democratic values and address the needs of their citizens, it can lead to unrest and attacks on the democratic system.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION A>4>a", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Highlight three ways in which the judicial arm of government sustains democracy.", "images": [], "marking_scheme": "The judicial arm of government plays a crucial role in sustaining democracy through the following ways:    Upholding the Rule of Law: The judiciary ensures that laws are applied consistently and fairly, maintaining legal order and protecting individual rights. By adjudicating disputes and interpreting laws, the courts help to prevent abuse of power by other branches of government and ensure that all citizens, including leaders, are held accountable under the law. This adherence to the rule of law is fundamental for a functioning democracy.    Protecting Constitutional Rights: Courts safeguard the constitution and fundamental rights enshrined within it. They have the authority to review laws and government actions to ensure they do not violate constitutional provisions. Through judicial review, the judiciary can nullify unconstitutional laws and protect citizens' rights and freedoms, thereby reinforcing democratic principles and preventing potential overreach by the executive or legislative branches.    Resolving Electoral Disputes: The judiciary plays a key role in resolving disputes arising from elections, such as allegations of fraud or irregularities. By providing a neutral and impartial forum for these disputes, the courts help to maintain public confidence in the electoral process and ensure that democratic elections are fair and credible. This function is vital for the legitimacy and stability of democratic governance.", "marks": "6", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION A>4>b", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Examine three ways by which the executive arm of government can be put to check in a democracy.", "images": [], "marking_scheme": "In a democracy, ensuring that the executive arm of government is effectively checked is crucial for maintaining balance and accountability. Here are three key mechanisms:    Legislative Oversight: The legislature, through various committees and hearings, can scrutinize the actions and decisions of the executive. By reviewing budgets, policies, and administrative actions, legislators can hold the executive accountable for its performance and ensure compliance with laws. This oversight function helps prevent abuse of power and encourages transparency.    Judicial Review: Courts have the authority to review and rule on the constitutionality of executive actions. Judicial review ensures that executive decisions adhere to constitutional principles and legal standards. If the executive exceeds its authority or violates rights, the judiciary can invalidate those actions, providing a critical check on executive power.    Public Accountability and Media Scrutiny: A free press and active civil society play a vital role in monitoring and criticizing the executive. Investigative journalism and public discourse expose corruption, inefficiency, or misconduct, pressuring the executive to act responsibly. Public opinion and advocacy can drive reforms and demand accountability, ensuring that the executive remains answerable to the people.", "marks": "9", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION A>5", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "5", "group": "", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Outline five ways in which citizens can checkmate political office holders in Nigeria.", "images": [], "marking_scheme": "Citizens play a crucial role in holding political office holders accountable and ensuring effective governance. In Nigeria, there are several ways citizens can checkmate political leaders and influence positive change:    Participating in Elections  One of the most direct ways citizens can hold political office holders accountable is by actively participating in elections. By voting in local, state, and national elections, citizens can choose leaders who align with their values and interests. Voting is not just about selecting candidates but also about expressing approval or disapproval of current office holders. Engaging in the electoral process helps ensure that leaders are held accountable to the electorate and that only those with genuine public support remain in office.    Engaging in Advocacy and Civic Activism  Citizens can engage in advocacy and civic activism to influence policy decisions and governmental actions. This includes participating in public demonstrations, joining civil society organizations, and campaigning for specific issues. Advocacy efforts can draw attention to important issues such as corruption, human rights violations, and inadequate public services. Civic activism helps to amplify citizens' voices, push for reforms, and pressure political leaders to address public grievances.    Utilizing Social Media and Traditional Media  Social media platforms and traditional media are powerful tools for checking political office holders. Citizens can use social media to share information, raise awareness, and mobilize support for causes. Platforms like Twitter, Facebook, and Instagram facilitate real-time communication and public discourse, enabling citizens to challenge political leaders and demand accountability. Traditional media, including newspapers, radio, and television, also play a crucial role in investigating and reporting on governmental activities, exposing corruption, and holding leaders accountable.    Participating in Public Consultations and Forums  Many governments and local authorities hold public consultations and forums to gather feedback from citizens on policy decisions and government actions. By actively participating in these events, citizens can voice their opinions, ask questions, and contribute to decision-making processes. This engagement helps ensure that leaders are aware of public concerns and preferences, and it provides an opportunity for citizens to directly influence policies and governance.     Filing Complaints and Legal Action  Citizens can hold political office holders accountable by filing complaints and pursuing legal action when necessary. If there are allegations of misconduct, corruption, or violation of rights, citizens can lodge formal complaints with relevant agencies, such as anti-corruption bodies or ombudsman offices. Additionally, legal action can be taken through the judiciary to challenge unlawful actions or decisions made by political leaders. This legal recourse ensures that office holders are subject to the rule of law and can be held accountable for their actions.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION B>6", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "6", "group": "", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA~~PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Judging from the negative impact of the major political crises in Nigeria, explain five reasons for which peace education is vital to the state.", "images": [], "marking_scheme": "Peace education is crucial in Nigeria due to the negative impacts of major political crises. Here are five reasons why peace education is vital for the state:    Promoting Social Cohesion  Nigeria is characterized by diverse ethnic, religious, and cultural groups. Political crises often exacerbate divisions and fuel tensions among these groups. Peace education fosters understanding, respect, and cooperation among different communities. By teaching individuals about the importance of diversity and the value of peaceful coexistence, peace education helps to build a more cohesive and unified society. This reduces the likelihood of conflict and promotes harmony among various groups.    Reducing Violence and Extremism  Political crises in Nigeria have sometimes led to violent conflicts and extremism. Peace education plays a critical role in addressing the root causes of violence by promoting non-violent conflict resolution strategies. It equips individuals with the skills to manage disputes constructively and avoid resorting to violence. By emphasizing dialogue, negotiation, and mediation, peace education helps to mitigate the conditions that can lead to extremism and violent behavior.    Enhancing Civic Responsibility  In times of political instability, citizens may become disillusioned or disengaged from the democratic process. Peace education encourages active civic engagement and responsibility. It teaches individuals about their rights and duties as citizens, the importance of participating in democratic processes, and how to hold leaders accountable. By fostering a sense of civic duty and encouraging constructive participation, peace education helps to strengthen democratic institutions and promote stable governance.     Encouraging Conflict Prevention  Preventing conflicts before they escalate is essential for maintaining stability. Peace education provides individuals with tools and knowledge to identify and address potential sources of conflict early on. It emphasizes proactive measures, such as community dialogue, early intervention, and collaborative problem-solving. By equipping citizens with these skills, peace education contributes to the prevention of conflicts and supports the creation of a more resilient and peaceful society.    Supporting Post-Conflict Reconciliation  After political crises, societies often face the challenge of rebuilding trust and relationships. Peace education supports post-conflict reconciliation by promoting healing and understanding among affected communities. It provides frameworks for addressing grievances, rebuilding social capital, and fostering a culture of forgiveness and mutual respect. Through education, individuals and communities can work towards reconciling differences, restoring social harmony, and preventing future conflicts.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2024>SECTION B>7", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "7", "group": "", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Identify five debilitating effects of French Colonial rule on her West African Colonies.", "images": [], "marking_scheme": "French colonial rule in West Africa had several debilitating effects on the region's societies, economies, and political structures. Here are five key consequences:    Economic Exploitation and Dependency  French colonial rule was marked by the exploitation of West African resources for the benefit of France. The colonial economy was structured to serve French economic interests, leading to the extraction of valuable resources such as minerals, agricultural products, and raw materials. This exploitation resulted in economic dependency, where the colonies became reliant on French-controlled markets and industries. Traditional economies were disrupted, and local production systems were often neglected or dismantled to favor the colonial economic model. This created long-lasting economic challenges and hindered the development of a self-sustaining economy in the post-colonial era.    Disruption of Traditional Social Structures  The imposition of French colonial rule disrupted traditional social structures and governance systems. Indigenous systems of leadership, community organization, and legal practices were undermined or replaced by colonial institutions. Chiefs and traditional leaders were often co-opted into the colonial administration, weakening their authority and diminishing their roles in their communities. This disruption led to a loss of cultural continuity and social cohesion, as traditional practices and governance mechanisms were sidelined in favor of colonial systems that often lacked local relevance.    Educational and Cultural Marginalization  French colonial education policies emphasized the French language and culture, often at the expense of indigenous languages and cultural practices. The colonial education system was designed to create a small elite that could serve the colonial administration rather than fostering broad-based educational development. As a result, many West Africans were denied access to education or were educated in a manner that devalued their own cultures and histories. This marginalization of indigenous knowledge and cultures had a lasting impact on the region's identity and intellectual development.    Political Disenfranchisement and Authoritarianism  French colonial rule implemented an authoritarian system of governance, where political power was concentrated in the hands of colonial officials. The local population had little to no say in their own governance, and political participation was limited. This disenfranchisement stunted the development of democratic institutions and political consciousness among the populace. Post-independence, many West African countries struggled with the legacy of authoritarian governance, facing challenges in building inclusive and representative political systems.     Infrastructural Development Focused on Extraction  Colonial infrastructure development in West Africa was primarily aimed at facilitating resource extraction and transportation to ports for export. Railways, roads, and ports were constructed to serve colonial economic interests rather than to meet the needs of local populations. This resulted in uneven development, where infrastructure was concentrated in areas with economic value while many regions remained underdeveloped. The lack of comprehensive infrastructural development impeded economic growth and access to essential services in many areas, perpetuating regional inequalities.", "marks": "15", "difficulty": "3"}, {"id": "theory>Government>2024>SECTION B>8", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "8", "group": "", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "In what five ways can the pre-colonial traditional political organization and governance in Nigeria compare with modern day political arrangement?", "images": [], "marking_scheme": "Comparing pre-colonial traditional political organization and governance in Nigeria with modern-day political arrangements reveals both contrasts and continuities. Here are five key ways in which they compare:    Structure of Leadership  In pre-colonial Nigeria, traditional political systems were often organized around chieftaincies, monarchies, and councils of elders. Leadership was typically hereditary, with kings or chiefs holding significant authority over their communities. Governance was deeply rooted in customs and traditions, with leaders expected to maintain harmony and justice within their societies.  In contrast, modern-day Nigerian political structures are democratic, with elected officials assuming leadership roles. The President, Governors, and Legislators are chosen through elections rather than inheritance. This shift emphasizes representative governance and adherence to constitutional principles, contrasting with the traditional emphasis on lineage and custom.    Decision-Making Processes  Pre-colonial decision-making in Nigeria was generally communal and consensus-driven. Councils of elders or traditional assemblies played a central role in deliberating and making decisions that affected the community. This process emphasized collective wisdom and inclusivity, with input from various segments of society.  Modern political arrangements in Nigeria, however, often involve a more hierarchical decision-making process. Government decisions are typically made by elected officials and bureaucrats, and while there are mechanisms for public participation, the process can be less inclusive and more centralized. Political parties and elected representatives often dominate decision-making, which can sometimes lead to a disconnect between government actions and grassroots concerns.    Conflict Resolution  In traditional Nigerian societies, conflict resolution was managed through customary laws and traditional courts. Chiefs and elders would mediate disputes based on established customs and communal values. This approach was rooted in a deep understanding of local contexts and norms.  Modern Nigeria employs a formal judicial system with statutory laws and courts that handle conflict resolution. While this system aims for fairness and impartiality, it sometimes struggles with delays and corruption. The shift from customary to statutory law represents a move towards a more standardized legal system but can also lead to challenges in addressing local and culturally specific issues.    Role of Religion and Tradition  Pre-colonial governance in Nigeria was closely intertwined with religious and traditional beliefs. Leaders were often seen as divine or semi-divine figures, and governance was deeply rooted in spiritual and cultural practices.  In modern Nigeria, the separation of religion and state is a fundamental principle, although in practice, religion continues to influence politics. The modern political system is secular and operates based on constitutional and legal frameworks rather than religious or traditional mandates. However, the persistence of traditional practices and beliefs still plays a role in shaping political and social dynamics.    Citizens' Participation  Traditional governance systems allowed for a form of participatory politics where community members had a say through assemblies and council meetings. Leadership was accountable to the community, and public opinion was a significant factor in decision-making.    In modern Nigeria, citizen participation is structured through democratic processes such as voting and public consultations. While these mechanisms are designed to be inclusive, challenges such as political apathy, voter suppression, and corruption can hinder effective participation. The modern system aims for broader representation but often struggles with achieving the same level of direct engagement seen in traditional systems.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION B>9", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "9", "group": "", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "As a student of Government, discuss five ways by which the Economic Community of West African States (ECOWAS) can operate to achieve its stated objectives.", "images": [], "marking_scheme": "The Economic Community of West African States (ECOWAS) aims to promote economic integration, regional stability, and development across West Africa. To achieve its stated objectives, ECOWAS can operate through the following five ways:    Strengthening Regional Economic Integration  ECOWAS can enhance economic integration by implementing policies that promote trade and investment within the region. This includes reducing trade barriers, such as tariffs and import quotas, and creating a unified market through agreements like the ECOWAS Trade Liberalization Scheme (ETLS). By harmonizing regulations, standards, and customs procedures, ECOWAS can facilitate smoother trade flows and encourage cross-border investments. Establishing infrastructure such as roads, railways, and ports is also crucial for improving connectivity and economic collaboration among member states.     Promoting Political Stability and Security  To ensure regional stability, ECOWAS must address political and security challenges, including conflicts and instability. The organization can use its conflict prevention and resolution mechanisms, such as mediation and peacekeeping missions, to manage and resolve disputes between member states. ECOWAS's role in monitoring elections, supporting democratic processes, and promoting good governance is vital for maintaining political stability. The establishment of the ECOWAS Standby Force and collaboration with international partners help in responding to crises and ensuring peace and security in the region.     Fostering Regional Cooperation on Development Projects  ECOWAS can achieve its development objectives by coordinating and implementing regional projects that address common challenges. This includes initiatives in areas such as health, education, and infrastructure. Collaborative projects, such as the West African Power Pool (WAPP) and the West African Regional Action Plan for Disaster Risk Reduction, can enhance regional resilience and improve living standards. By pooling resources and expertise, ECOWAS member states can undertake large-scale projects that might be challenging for individual countries to achieve alone.    Enhancing Institutional Capacity and Governance  Effective governance and institutional capacity are essential for the success of ECOWAS. The organization can work on strengthening its institutions and improving their functionality by ensuring that they operate efficiently and transparently. This involves enhancing the capacity of the ECOWAS Commission, the Community Parliament, and other bodies to execute their mandates effectively. Training programs, capacity-building initiatives, and the adoption of best practices in administration and management can contribute to more effective decision-making and implementation of regional policies.     Engaging in Strategic Partnerships and International Cooperation  ECOWAS can achieve its objectives by building strategic partnerships with international organizations, development partners, and private sector entities. Collaboration with organizations such as the United Nations, African Union, and European Union can provide additional resources, expertise, and support for regional initiatives. Engaging with international financial institutions and donor agencies can facilitate funding for development projects and programs. By leveraging these partnerships, ECOWAS can enhance its capacity to address regional challenges and advance its goals.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2024>SECTION B>10", "subject": "Government", "year": "2024", "type": "Theory", "sub_label": "10", "group": "", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Examine five reasons for which Nigeria attaches so much importance to foreign policy determination and implementation.", "images": [], "marking_scheme": "Nigeria attaches significant importance to foreign policy determination and implementation for several strategic reasons. Understanding these motivations provides insight into the country's approach to international relations and its global positioning:    National Security and Regional Stability  Nigeria's foreign policy is deeply influenced by its need to ensure national security and promote regional stability. Given its size, strategic location, and the presence of various security threats—such as insurgencies and cross-border crimes—Nigeria seeks to foster strong international alliances and regional cooperation. By engaging with neighboring countries and global powers, Nigeria aims to enhance its security, manage conflicts, and address transnational threats. Effective foreign policy helps Nigeria to collaborate on counter-terrorism efforts, peacekeeping missions, and regional security arrangements, thereby contributing to both national and regional stability.    Economic Interests and Development  Foreign policy plays a crucial role in Nigeria's economic strategy. As one of Africa's largest economies, Nigeria seeks to expand its trade relationships, attract foreign investment, and access global markets. By establishing strong diplomatic ties and participating in international trade agreements, Nigeria aims to boost its economic growth and development. Engaging in foreign policy initiatives allows Nigeria to negotiate trade deals, secure funding for development projects, and participate in international economic forums, which are essential for achieving sustainable economic progress and diversifying its economy.    Influence and Leadership in Africa  Nigeria's foreign policy is driven by its aspiration to play a leading role in Africa. As the most populous country on the continent with significant economic and military capabilities, Nigeria seeks to assert its influence and leadership in African affairs. By actively participating in regional organizations such as the Economic Community of West African States (ECOWAS) and the African Union (AU), Nigeria aims to shape continental policies, promote African unity, and address regional challenges. This leadership role enhances Nigeria's status on the global stage and aligns with its vision of contributing to Africa's overall progress and integration.    Diplomatic Relations and International Cooperation  Maintaining strong diplomatic relations and international cooperation is a key reason for Nigeria's focus on foreign policy. Nigeria recognizes the importance of building and sustaining relationships with other countries to advance its national interests. By engaging in diplomacy, Nigeria can secure support for its policies, participate in global decision-making processes, and address international issues such as climate change, health crises, and human rights. Effective foreign policy enables Nigeria to navigate complex international dynamics, leverage global partnerships, and enhance its influence in international organizations.    Cultural and Diaspora Engagement  Nigeria's foreign policy also emphasizes the promotion of its cultural heritage and the interests of its diaspora. The Nigerian government seeks to enhance its cultural diplomacy by showcasing its rich cultural diversity and fostering cultural exchanges. Additionally, supporting the Nigerian diaspora is a significant aspect of foreign policy, as the diaspora contributes to the country's development through remittances, investments, and advocacy. Engaging with the global Nigerian community helps strengthen the nation's international ties and harness the benefits of its expatriates.", "marks": "15", "difficulty": "2"}, {"id": "theory>Government>2025>SECTION A>1", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "1", "group": "", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "In what ways do political parties contribute to the foundation of democracy? Outline your answers in five key points fully developed.", "images": [], "marking_scheme": "- Articulating and Channeling Public Opinion:  Political parties serve as critical intermediaries between the citizenry and the government. They gather, organize, and articulate the views, needs, and concerns of the public on a wide range of national and local issues. By doing so, they give structure to public opinion and ensure that the diverse voices within a society are heard. These collective sentiments are then transmitted to the government through party platforms, campaigns, and legislative advocacy. This process helps align governmental actions and public policies with the aspirations and preferences of the majority, thereby reinforcing the principles of participatory democracy.    - Structuring and Simplifying Governance:  Political parties contribute significantly to the stability and functionality of the political system by bringing together individuals who share similar ideologies, values, and policy objectives. This ideological alignment enables parties to act as organized blocs within the legislature, simplifying deliberation and decision-making processes. Rather than engaging with countless individual viewpoints, governments and parliaments can negotiate and implement policies more efficiently through party structures. As a result, governance becomes more streamlined and coherent, reducing gridlock and fostering effective leadership.    Developing Clear Policy Agendas:  Each political party formulates a comprehensive policy platform that sets forth its proposed strategies and priorities in areas such as economic management, healthcare, education, national security, environmental protection, and social justice. These platforms serve as blueprints for governance and provide the electorate with a tangible sense of what each party stands for. By laying out these visions before elections, parties enhance political transparency and enable voters to make informed choices based on their values and expectations for national development.    - Fostering Democratic Competition:  A fundamental role of political parties in a democracy is to contest elections and offer alternative leadership and policy directions. The existence of multiple parties vying for political power ensures healthy competition, which is vital for the evolution and resilience of democratic systems. This competitive environment prevents the concentration of power in the hands of a single entity and motivates parties to innovate, refine their programs, and remain responsive to public needs in order to gain electoral support. Through regular electoral contests, political parties rejuvenate democracy and promote accountability.    - Promoting Accountability Through Opposition:  Political parties that are not in power play a crucial role in maintaining checks and balances within the democratic process. As opposition forces, they scrutinize the actions and decisions of the ruling party, raise public awareness about governmental misconduct, and provide alternative perspectives on policy issues. By questioning, criticizing, and challenging the government's actions, opposition parties act as watchdogs, helping to curb abuse of power, uphold the rule of law, and safeguard democratic values. Their presence ensures that the governing party remains answerable to both the legislature and the electorate.    – Political Socialization and Civic Education:  Political parties play a vital role in educating citizens about their rights, responsibilities, and the workings of the political system. Through rallies, debates, manifestos, grassroots mobilization, and media outreach, parties inform the public about national issues, policy alternatives, and electoral procedures. This process enhances political awareness and fosters active civic engagement. By shaping political attitudes and encouraging participation, parties contribute to the growth of an informed electorate capable of making thoughtful decisions that strengthen democratic governance.    – Recruitment and Development of Political Leadership:  Political parties serve as platforms for identifying, nurturing, and promoting future leaders. They scout for individuals with leadership potential at the grassroots level and provide them with opportunities to grow through internal party roles, mentorship, and public service. Over time, these individuals gain experience, skills, and visibility, preparing them to assume greater responsibilities within government. This leadership pipeline ensures continuity in governance and helps maintain institutional knowledge and stability within the political system.    – Enhancing National Integration:  By operating across ethnic, regional, and religious lines, political parties can foster national unity and cohesion. When parties are inclusive and draw support from diverse segments of the population, they help bridge societal divides and reduce polarization. Such cross-cutting alliances promote a sense of collective identity and shared destiny, which is crucial in multi-ethnic societies. Through inclusive platforms and policies that reflect national interests, parties contribute to peacebuilding and sustainable development.    – Facilitating Peaceful Transfer of Power:  Political parties provide the institutional framework for orderly and legitimate changes in government through elections. By participating in electoral processes and respecting the outcomes, they help prevent political instability and conflict. A vibrant party system ensures that transitions from one administration to another are peaceful and constitutionally regulated. This reinforces the rule of law, strengthens democratic institutions, and builds public trust in governance.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION A>2", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "2", "group": "", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Argue out with five well explained points that the media is a vital associate of democratic process.", "images": [], "marking_scheme": "The media is a powerful institution in any democratic society. It plays a central role in ensuring that democracy functions effectively by keeping citizens informed, leaders accountable, and public discourse active. Through newspapers, radio, television, and online platforms, the media connects the government with the people and enables free expression. Below are well-developed reasons the media is a vital associate of the democratic process.    - Informing and Educating the Public  A strong democracy depends on informed citizens who can make wise decisions, especially during elections and national discussions. The media provides regular updates on political, economic, and social matters, helping people understand government actions, laws, and public policies. By making information accessible, the media promotes civic awareness and enables people to engage meaningfully in democratic activities.    - Holding Government Accountable  The media acts as a watchdog by monitoring the actions of those in power. It investigates and reports cases of corruption, injustice, and abuse of office. When wrongdoings are exposed through reliable journalism, public pressure forces leaders to act responsibly. This role helps to reduce impunity and reminds public officials that they are servants of the people.    - Promoting Dialogue and Public Participation  Democracy encourages freedom of speech and open discussion. The media provides platforms-such as talk shows, opinion articles, and interviews-where citizens can express their views, challenge ideas, and contribute to public debate. This allows different voices, including those from minority groups, to be heard. As a result, the democratic process becomes more inclusive and representative of the entire society.    - Ensuring Transparency in Governance  By reporting on government activities such as budgets, legislative debates, and court rulings, the media helps make public affairs more transparent. This openness discourages secrecy and builds trust between the people and the government. When citizens are aware of how decisions are made and how public funds are spent, they are more likely to support democratic institutions.    - Supporting Free and Fair Elections  The media plays a critical role during election periods. It informs voters about political parties, their manifestos, and their candidates. It also educates the public about voting procedures and the importance of their vote. Furthermore, the media helps prevent electoral fraud by reporting irregularities and monitoring the conduct of electoral bodies. All these efforts promote electoral integrity and strengthen democratic values.    - Encouraging Government Responsiveness  The media serves as a bridge between the government and the people by conveying citizens' concerns, grievances, and needs to public officials. Through news reports, editorials, and public feedback, it alerts authorities to social issues that require urgent attention. A responsive government listens to such media-reported concerns and takes prompt action, thereby reinforcing trust and democratic engagement.    - Promoting Political Pluralism and Tolerance  In a diverse society, the media showcases a wide range of political opinions and ideologies. By giving airtime and coverage to all parties and candidates, regardless of size or popularity, the media ensures fair representation. This inclusiveness fosters tolerance, discourages political marginalization, and allows voters to consider different viewpoints before making decisions.    - Strengthening Rule of Law  By reporting on judicial proceedings, human rights cases, and legal reforms, the media reinforces the supremacy of law in democratic societies. Investigative journalism can uncover legal violations, ensuring that justice is pursued. This continuous spotlight on legal systems helps prevent abuse and affirms the idea that no one is above the law.    - Facilitating Civic Education  Beyond news, the media provides educational content on democratic rights, responsibilities, and values. Documentaries, public service announcements, and civic programmes raise awareness about topics such as constitutional rights, voter education, and national unity. Such initiatives empower citizens to participate actively and responsibly in democratic life.    Conclusion  The media is more than just a channel for delivering news-it is a key pillar of democracy. By informing citizens, exposing corruption, encouraging dialogue, and supporting fair elections, the media strengthens democratic governance and protects the rights of the people. Without a free and active media, democracy would lose its voice and its strength.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION A>3", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "3", "group": "", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "In what five key ways can the government of Nigeria innovate to ensure that State Owned Enterprises remain relevant to the development of the state.", "images": [], "marking_scheme": "- Enhance corporate governance structures:  The government should build transparent and accountable governance systems for State Owned Enterprises by clearly defining roles, establishing independent and competent boards, and enforcing strict oversight to ensure ethical and efficient management.    - Advance digital innovation:  Adopting modern technologies such as automation, data analytics, artificial intelligence, and electronic governance tools can boost the efficiency, responsiveness, and service quality of State Owned Enterprises, making their operations more effective and data-driven.    - Foster financial independence:  To reduce reliance on public funding, State Owned Enterprises should focus on generating internal revenue, improving cost control, and adopting commercial business models that support long-term financial stability and operational sustainability.    - Strengthen public-private collaboration:  Engaging private sector partners can provide State Owned Enterprises with access to capital, technical expertise, and innovative practices. Such partnerships can enhance competitiveness while maintaining public ownership in key strategic sectors.    - Establish robust performance management systems:  Introducing performance-based frameworks that set clear targets, conduct regular evaluations, and link rewards to results will help boost efficiency, improve accountability, and drive better outcomes across State Owned Enterprises.    - Promote Merit-Based Appointments:  Leadership positions in SOEs should be filled through transparent and competitive processes based on qualifications, experience, and integrity. This helps eliminate political interference and ensures that competent professionals are entrusted with decision-making responsibilities.    - Implement Regular Audits and Compliance Checks:  Independent financial and operational audits should be conducted periodically to detect inefficiencies, mismanagement, or fraud. Enforcing compliance with national and international best practices strengthens credibility and improves investor and public confidence.    - Improve Customer Service and Public Engagement:  SOEs should adopt a customer-centric approach by investing in service delivery, seeking regular public feedback, and resolving complaints promptly. When citizens feel valued and heard, trust in public institutions is enhanced.    - Develop Strategic Plans and Long-Term Vision:  Each SOE should operate with a clear mission, strategic goals, and measurable outcomes aligned with national development priorities. This long-term planning helps maintain focus, guide investment decisions, and monitor progress over time.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION A>4", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "4", "group": "", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Examine five strategies that can greatly assist to prevent judicial autocracy with the view of ensuring a fair and balanced judicial system in the governance structure of the Federal Republic of Nigeria.", "images": [], "marking_scheme": "- Ensure merit-based and transparent judicial appointments:  To prevent political interference and maintain the integrity of the bench, the processes for appointing and promoting judges must be open, fair, and based strictly on merit. This strengthens judicial independence while promoting accountability and professionalism.    - Establish strong accountability and oversight mechanisms:  Judicial officers should be subject to regular performance reviews and transparent disciplinary procedures. Independent bodies such as the National Judicial Council must be empowered to investigate misconduct and enforce standards, helping to prevent arbitrary or unethical behavior on the bench.    - Promote strict compliance with laws and precedents:  Judges must consistently apply established statutes and judicial precedents in their rulings. This minimizes the influence of personal bias and curbs excessive use of discretion, ensuring that judgments remain objective and grounded in the rule of law.    - Support judicial independence with responsibility:  While it is vital to shield the judiciary from external pressures, independence should go hand in hand with responsibility. A truly independent judiciary must be free to interpret the law without fear or favor but must also operate within ethical and constitutional boundaries.    - Expand civic education and public legal awareness:  Educating citizens about the structure, powers, and limitations of the judiciary enables them to engage with the justice system more confidently and challenge instances of judicial overreach. A well-informed public plays a key role in preserving judicial accountability and transparency.    - Improve access to justice through institutional reforms:  Reforming court procedures to reduce delays, ensure timely rulings, and simplify litigation can improve public trust in the judiciary. Introducing alternative dispute resolution mechanisms, such as mediation and arbitration, also helps decongest courts and make justice more accessible.    - Ensure adequate funding and resource allocation:  The judiciary must be financially autonomous and well-resourced to perform its duties effectively. Guaranteed, timely, and independent funding helps prevent undue influence from other arms of government and allows for better infrastructure, training, and case management systems.    - Invest in continuous legal training and ethical development:  Regular training for judges and court staff on legal updates, ethics, human rights, and emerging jurisprudence strengthens competence and integrity. Continuous professional development also keeps the judiciary responsive to evolving legal and social contexts.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION A>5", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "5", "group": "", "topic": "POLITICAL CULTURE", "question": "Discuss five ways in which political culture enhances state development.", "images": [], "marking_scheme": "- Promotes Active Civic Engagement  A vibrant political culture encourages citizens to participate in democratic processes such as voting, advocacy, public debate, and community involvement. When people are actively involved in shaping policies and holding leaders accountable, it leads to more responsive governance and development policies that reflect the real needs of the population.    - Strengthens Democratic Institutions  Political cultures that value the rule of law, respect for democratic principles, and institutional accountability contribute to the growth of stable and reliable institutions. Such institutions are essential for sustainable development, as they create a predictable and fair environment where laws are upheld, rights are protected, and development programs can thrive.    - Encourages Political Stability  Where political culture embraces peaceful dialogue, tolerance, and respect for electoral outcomes, political crises and violence are minimized. This stability reduces disruptions to economic and social progress, allowing governments and investors to focus on long-term development planning and implementation.    - Builds Trust in Governance  When political culture promotes fairness, inclusiveness, and transparency, citizens are more likely to trust public institutions. This trust improves cooperation between the government and the people, making it easier to implement policies, enforce laws, and carry out national development initiatives effectively.    - Fosters Inclusive and Equitable Development  A political culture that values participation from all segments of society-especially women, youth, and marginalized groups-ensures that development is more balanced and representative. Inclusive governance results in policies that consider diverse needs, leading to more just and comprehensive national growth.    – Enhances Policy Continuity and Long-Term Planning  A mature political culture discourages abrupt policy changes and promotes respect for national development plans across administrations. When political actors prioritize national interest over partisan gains, governments are better able to follow through on long-term infrastructure, education, and health initiatives, ensuring continuity in development.    – Promotes Accountability and Reduces Corruption  In a political culture where integrity, transparency, and ethical conduct are widely valued, public officials are more likely to be held accountable for their actions. This culture of accountability discourages corruption, strengthens institutional efficiency, and ensures that public resources are used for development purposes rather than diverted for personal gain.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION B>6", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "6", "group": "", "topic": "DEMOCRACY", "question": "In five distinct pointsfully developed, explain how the influence of the traditional authorities and their institutions can be tapped to enhance democratic governance in Nigeria.", "images": [], "marking_scheme": "- Deepening Civic Awareness at the Grassroots  Traditional rulers enjoy deep-rooted respect and influence within their communities. By using their platforms to educate citizens on voting rights, civic duties, and democratic values, they help to raise political awareness and encourage greater participation in governance, especially in rural areas.    - Promoting Peace and Conflict Resolution  Traditional institutions have long served as custodians of local dispute resolution. Their integration into the democratic process can help resolve political tensions, mediate conflicts during elections, and prevent communal violence—thereby fostering a more stable and peaceful political environment.    - Acting as a Bridge Between Government and the People  Because traditional rulers are closely connected to local communities, they can effectively communicate grassroots concerns to government officials. Their role as intermediaries helps ensure that public policies and development programs reflect the real needs and priorities of the people.    - Supporting Credible and Peaceful Elections  Traditional leaders can play a vital role in electoral mobilization by encouraging voter participation and discouraging violence, manipulation, and apathy. Their moral authority helps reinforce trust in the electoral process and contributes to peaceful and credible elections.    - Encouraging Accountability and Ethical Leadership  Through their cultural influence and moral standing, traditional rulers can monitor the conduct of local leaders and hold them accountable to their communities. Their presence discourages corruption and promotes integrity in public service, especially at the grassroots level.    – Preserving Indigenous Systems of Justice and Inclusion  Traditional institutions maintain long-standing systems of justice that emphasize dialogue, reconciliation, and restorative practices. Their integration into the broader democratic framework ensures that local customs and values are respected while promoting inclusive governance that resonates with community norms.    – Promoting Cultural Identity and National Unity  By upholding cultural heritage, languages, and traditions, traditional rulers foster a sense of identity and belonging among their people. This cultural cohesion contributes to national unity, which is a vital foundation for a stable democratic system.    – Enhancing Policy Implementation at the Local Level  Because of their influence and direct access to local populations, traditional rulers can help mobilize community support for government policies, vaccination campaigns, census exercises, and development projects. Their endorsement often lends legitimacy and boosts compliance at the grassroots.    – Facilitating Youth and Women Empowerment  Traditional institutions can champion the inclusion of women and youth in leadership and civic life. By supporting cultural reforms and mentoring programs, they contribute to broader participation, social justice, and the development of future democratic leaders.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION B>7", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "7", "group": "", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Outline five major lessons that citizens can draw from the activites of nationalism and nationalist leaders in state development.", "images": [], "marking_scheme": "- The Power of Unity and Collective Action  Nationalist movements showed that unity across ethnic, religious, and regional lines can lead to meaningful political change. Citizens learn that when people come together with a shared vision, they can overcome oppression, resist injustice, and achieve national goals.    - Civic Responsibility and Active Participation  Nationalist leaders like Nnamdi Azikiwe, Obafemi Awolowo, and Ahmadu Bello demonstrated the importance of civic engagement. Their efforts teach citizens that active participation in politics-through voting, advocacy, or public service-is essential for national growth and accountable leadership.    - Leadership Rooted in Vision and Sacrifice  Most nationalist leaders put national interest above personal gain, often enduring hardship for the sake of freedom and development. Citizens are reminded that genuine leadership requires selflessness, commitment, and a clear vision for the country's future.    - The Role of Education and Enlightenment  Nationalists used newspapers, lectures, and writings to educate and mobilize the masses. This highlights the importance of education in national development. An informed citizenry is better equipped to demand good governance and contribute meaningfully to societal progress.    - Resistance Against Oppression and Injustice  The nationalist struggle was a direct response to colonial exploitation and inequality. Citizens learn the value of standing up against any form of injustice-be it political, economic, or social-and the need to protect democratic freedoms and human rights.    - Promotion of National Identity and Patriotism  Nationalist movements fostered pride in local cultures, languages, and traditions. Citizens learn to value their heritage and promote national unity while embracing diversity and mutual respect among different ethnic groups.    - Importance of Dialogue and Peaceful Negotiation  Many nationalist leaders sought constitutional reforms through peaceful dialogue and negotiation before resorting to protests. This teaches that non-violent communication and diplomacy are effective tools for resolving national issues.    - Strategic Use of Media and Communication  Nationalists used newspapers, pamphlets, and speeches to spread awareness and rally support. This shows citizens the importance of using media responsibly to educate, mobilize, and promote national interests.    - Economic Empowerment and Self-Reliance  Some nationalist campaigns encouraged boycotts of foreign goods and promoted indigenous enterprises. Citizens learn the value of supporting local industries and striving for economic independence as a means of national development.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION B>8", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "8", "group": "", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Discuss five major ways in which international organisations positively influence Nigeria as a sovereign state in her developmental agenda.", "images": [], "marking_scheme": "International organisations play a significant role in supporting the development of sovereign states like Nigeria. Through financial assistance, technical support, policy guidance, and global cooperation, these organisations contribute to Nigeria's progress in areas such as health, education, infrastructure, governance, and economic growth. Below are the major ways in which they positively influence Nigeria's developmental agenda.    - Financial Support and Development Grants  Organisations such as the World Bank, International Monetary Fund (IMF), and African Development Bank (AfDB) provide Nigeria with loans, grants, and financial aid to fund infrastructure, education, health, and poverty reduction projects. These funds help the government bridge budgetary gaps and invest in long-term development programmes.    - Technical Assistance and Capacity Building  International bodies like the United Nations Development Programme (UNDP) and World Health Organization (WHO) offer expert support, training, and technical advice to enhance Nigeria's capacity in sectors like healthcare, governance, environmental management, and civil service reform. This helps improve service delivery and strengthens institutions.    - Promotion of Good Governance and Anti-Corruption Measures  Through partnerships and programmes, organisations such as the United Nations, Transparency International, and the Economic Community of West African States (ECOWAS) promote accountability, democratic governance, human rights, and the rule of law. Their support helps Nigeria tackle corruption and build more transparent public institutions.    - Humanitarian and Emergency Response  In times of crisis-such as conflict, famine, or disease outbreaks-international organisations provide critical humanitarian aid. The United Nations, International Red Cross, and other bodies have supported internally displaced persons (IDPs), delivered food aid, and supplied medical support during emergencies like the COVID-19 pandemic and the Boko Haram insurgency.    - Trade and Economic Integration  Through platforms like the World Trade Organization (WTO), African Union (AU), and ECOWAS, Nigeria gains access to regional and global markets. These bodies promote fair trade, regional cooperation, and investment, enabling Nigeria to grow its economy, diversify exports, and attract foreign direct investment.    - Environmental Protection and Climate Action  International organisations like the United Nations Environment Programme (UNEP) and the Global Environment Facility (GEF) support Nigeria's efforts to combat climate change, reduce pollution, and preserve biodiversity. Their interventions include funding for clean energy, reforestation, and environmental education.    - Support for Electoral Processes and Democracy  Bodies such as the European Union (EU), United Nations, and African Union (AU) often assist Nigeria during elections by providing observers, funding, and technical guidance. This promotes free, fair, and credible elections, thereby strengthening Nigeria's democratic institutions.    - Health Programmes and Disease Control  Organisations like WHO, UNICEF, and the Global Fund provide vaccines, medical equipment, and strategic support to combat diseases such as malaria, HIV/AIDS, and polio. Their contributions improve public health outcomes and strengthen Nigeria's healthcare systems.    - Educational Development and Scholarships  Through partnerships with UNESCO, the British Council, and international NGOs, Nigeria receives support for improving access to quality education. These include building schools, training teachers, and providing scholarships that expand learning opportunities for Nigerian students.    Conclusion  As a sovereign state, Nigeria retains its independence, but partnerships with international organisations help the country pursue its development goals more effectively. From funding and expertise to peacebuilding and trade, these organisations are valuable allies in Nigeria's journey toward sustainable development.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION B>9", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "9", "group": "", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Explain five key strategies the West African States can adopt to keep the military at bay from interfering in the political administration of statesin the sub-region.", "images": [], "marking_scheme": "Military intervention in politics has been a major setback for democratic development in many countries, including Nigeria. To safeguard constitutional governance and ensure long-term political stability, deliberate efforts must be made to keep the military firmly within its professional boundaries. The following are the key strategies that help prevent military interference in democratic affairs:    - Strengthening Democratic Institutions  Independent and credible institutions such as the judiciary, legislature, and electoral commissions help enforce the rule of law and uphold democratic norms. Their effective operation creates a stable political system where power is exercised through legal and constitutional means, reducing opportunities for military interference.    - Ensuring Civilian Oversight of the Military  Civilian authorities must retain full control over the armed forces through defense ministries and legislative checks. Oversight of military budgets, operations, and appointments ensures accountability and prevents the military from operating autonomously or nurturing political ambitions.    - Professionalizing the Armed Forces  A disciplined and well-trained military that focuses solely on defense and security is less likely to intervene in politics. Military education should emphasize loyalty to the constitution, respect for democratic values, and non-involvement in governance.    - Promoting Free and Credible Elections  Regular, fair, and transparent elections reinforce the legitimacy of civilian governments. When citizens believe in the electoral process, it reduces public sympathy for military coups and keeps political transitions within constitutional bounds.    - Addressing Corruption and Poor Governance  When democratic governments perform poorly or are perceived as corrupt, the military may exploit the situation to justify intervention. Improving public service delivery, enforcing accountability, and tackling corruption help build public trust in civilian rule and deny the military any excuse for political takeover.    - Upholding Human Rights and Civil Liberties  A democratic society that respects freedom of speech, assembly, and the press reduces the likelihood of military intervention. When citizens can express grievances peacefully and engage in civic life, it strengthens democratic norms and weakens the appeal of authoritarian solutions.    - Enhancing Civic Education and Political Awareness  Educating citizens about their rights, the importance of democracy, and the dangers of military rule builds a politically informed population. A well-informed electorate is more likely to resist undemocratic takeovers and demand accountability from their leaders.    - Building Strong Political Parties and Institutions  Stable, issue-based political parties and strong democratic institutions promote peaceful power transitions and political stability. This limits political crises that could invite military interference and ensures that governance continues under civilian control.    - Encouraging International Support and Pressure  Global and regional bodies like the African Union, ECOWAS, and the United Nations can help discourage military takeovers by imposing sanctions, withdrawing recognition, and supporting democratic transitions. International pressure reinforces democratic values and deters unconstitutional power grabs.", "marks": "1", "difficulty": "3"}, {"id": "theory>Government>2025>SECTION B>10", "subject": "Government", "year": "2025", "type": "Theory", "sub_label": "10", "group": "", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "In five key points fully developed, highlight the extent to which foreign policy plays a crucial role in shaping national development outcome.", "images": [], "marking_scheme": "- Attraction of Foreign Investment and Aid:  A well-structured foreign policy can help a country attract direct foreign investment and development assistance. Through diplomatic ties and participation in international organizations, nations can secure grants, loans, and technical support. For example, Nigeria's bilateral relations with countries like China, the United States, and members of the European Union have led to infrastructure funding, energy sector development, and technological transfers that stimulate economic growth.    - Promotion of Trade and Market Access:  Foreign policy promotes international trade by fostering economic partnerships, reducing trade barriers, and negotiating favorable agreements. When a country engages actively in regional and global trade frameworks-such as the African Continental Free Trade Area (AfCFTA)-it gains access to wider markets for its goods and services. This drives industrial growth, creates jobs, and boosts national income.    - Enhancing National Security and Stability:  Through military alliances, intelligence sharing, and diplomatic cooperation, foreign policy helps strengthen national security. Collaborations with international agencies and friendly nations can assist in combating terrorism, cybercrime, and arms trafficking. For example, Nigeria's cooperation with neighbouring countries through ECOWAS has been critical in addressing cross-border insurgencies, which in turn supports a stable environment for development.    - Facilitating Technological and Educational Exchange:  Foreign policy can promote bilateral educational programs and technological partnerships. Scholarships, research funding, and student exchange programs are often the result of strong international relations. These opportunities help build human capital and expose citizens to global best practices, contributing to innovation and sustainable development back home.    - Shaping Global Perception and Tourism:  A nation's foreign policy affects how it is perceived globally. Positive diplomatic engagements and international participation can improve a country's image, making it attractive for tourism, cultural exchange, and international cooperation. A strong international reputation enhances soft power, promotes peace, and creates opportunities for social and economic benefits.    - Supporting Diaspora Engagement  Effective foreign policy helps maintain strong ties with citizens living abroad. By establishing diaspora commissions, consulates, and investment-friendly policies, a country can encourage its diaspora to contribute to national development through remittances, skills transfer, and business investment.    - Influencing Global Decisions and Multilateral Agreements  Through active participation in international organizations like the United Nations, World Trade Organization, and African Union, a country can influence global policies and ensure its interests are represented in multilateral decisions. This strategic involvement strengthens national relevance in international affairs.    - Promoting Peacekeeping and Regional Stability  A responsible foreign policy can include contributions to peacekeeping missions and conflict resolution efforts. By helping to stabilize neighboring regions, a country not only promotes peace but also prevents the spillover of crises such as refugee influxes or arms trafficking into its own borders.    - Strengthening Cultural Diplomacy  Foreign policy can promote a country's cultural heritage abroad through cultural festivals, arts exchanges, and language promotion. Cultural diplomacy enhances mutual understanding, builds international friendships, and improves the nation's image, creating pathways for collaboration across various sectors.", "marks": "1", "difficulty": "3"}];